output.rtl/fir_filter.sv:
module fir_filter (
    input wire clk,                  // Clock signal
    input wire reset,                // Asynchronous reset
    input wire [15:0] data_in,       // Input data
    output reg [15:0] data_out,      // Filtered output data
    input wire [1:0] window_type     // Window type selector: 0-Rectangular, 1-Hanning, 2-Hamming, 3-Blackman
);

    // Coefficient registers for each tap
    reg [15:0] coeff0, coeff1, coeff2, coeff3, coeff4, coeff5, coeff6, coeff7;
    // Shift registers for delay line
    reg [15:0] shift_reg0, shift_reg1, shift_reg2, shift_reg3, shift_reg4, shift_reg5, shift_reg6, shift_reg7;
    // Intermediate sum register (32-bit to capture multiplication results)
    reg [31:0] sum;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            // Reset logic: clear output and all shift registers
            data_out <= 16'd0;
            shift_reg0 <= 16'd0;
            shift_reg1 <= 16'd0;
            shift_reg2 <= 16'd0;
            shift_reg3 <= 16'd0;
            shift_reg4 <= 16'd0;
            shift_reg5 <= 16'd0;
            shift_reg6 <= 16'd0;
            shift_reg7 <= 16'd0;
        end else begin
            // Cascade shift registers: shift data_in through the registers
            shift_reg7 <= shift_reg6;
            shift_reg6 <= shift_reg5;
            shift_reg5 <= shift_reg4;
            shift_reg4 <= shift_reg3;
            shift_reg3 <= shift_reg2;
            shift_reg2 <= shift_reg1;
            shift_reg1 <= shift_reg0;
            shift_reg0 <= data_in;

            // Dynamically select filter coefficients based on window_type
            case(window_type)
                2'b00: begin
                    coeff0 <= 16'd10;
                    coeff1 <= 16'd11;
                    coeff2 <= 16'd12;
                    coeff3 <= 16'd13;
                    coeff4 <= 16'd14;
                    coeff5 <= 16'd15;
                    coeff6 <= 16'd16;
                    coeff7 <= 16'd17;
                end
                2'b01: begin
                    coeff0 <= 16'd2;
                    coeff1 <= 16'd4;
                    coeff2 <= 16'd8;
                    coeff3 <= 16'd12;
                    coeff4 <= 16'd12;
                    coeff5 <= 16'd8;
                    coeff6 <= 16'd4;
                    coeff7 <= 16'd2;
                end
                2'b10: begin
                    coeff0 <= 16'd3;
                    coeff1 <= 16'd6;
                    coeff2 <= 16'd9;
                    coeff3 <= 16'd11;
                    coeff4 <= 16'd11;
                    coeff5 <= 16'd9;
                    coeff6 <= 16'd6;
                    coeff7 <= 16'd3;
                end
                2'b11: begin
                    coeff0 <= 16'd1;
                    coeff1 <= 16'd2;
                    coeff2 <= 16'd5;
                    coeff3 <= 16'd9;
                    coeff4 <= 16'd9;
                    coeff5 <= 16'd5;
                    coeff6 <= 16'd2;
                    coeff7 <= 16'd1;
                end
                default: begin
                    coeff0 <= 16'd0;
                    coeff1 <= 16'd0;
                    coeff2 <= 16'd0;
                    coeff3 <= 16'd0;
                    coeff4 <= 16'd0;
                    coeff5 <= 16'd0;
                    coeff6 <= 16'd0;
                    coeff7 <= 16'd0;
                end
            endcase

            // Calculate the FIR output: sum the products of each shift register and its coefficient,
            // then normalize the result by shifting right by 4 bits.
            sum = (shift_reg0 * coeff0) +
                  (shift_reg1 * coeff1) +
                  (shift_reg2 * coeff2) +
                  (shift_reg3 * coeff3) +
                  (shift_reg4 * coeff4) +
                  (shift_reg5 * coeff5) +
                  (shift_reg6 * coeff6) +
                  (shift_reg7 * coeff7);

            data_out <= sum >> 4;
        end
    end

endmodule

output.rtl/glitch_free_mux.sv:
module glitch_free_mux (
    input  logic clk1,
    input  logic clk2,
    input  logic sel,
    input  logic rst_n,
    output logic clkout
);

  // Internal clock enable signals for glitch‐free switching.
  // When sel = 0, clk1 is enabled; when sel = 1, clk2 is enabled.
  // The enables are updated on the rising edges of their respective clocks.
  logic clk1_en;
  logic clk2_en;

  // On the rising edge of clk1, update clk1_en.
  // When sel transitions from 0 to 1 (synchronously with clk1), clk1 is disabled.
  always_ff @(posedge clk1 or negedge rst_n) begin
    if (!rst_n)
      clk1_en <= 1'b0;
    else
      clk1_en <= ~sel;
  end

  // On the rising edge of clk2, update clk2_en.
  // When sel transitions from 1 to 0 (synchronously with clk2), clk2 is disabled.
  always_ff @(posedge clk2 or negedge rst_n) begin
    if (!rst_n)
      clk2_en <= 1'b0;
    else
      clk2_en <= sel;
  end

  // Generate clkout as the OR of the gated clocks.
  // Since clk1 and clk2 are assumed to be synchronous with a fixed phase difference,
  // they are non-overlapping and the OR operation is glitch free.
  assign clkout = (clk1_en ? clk1 : 1'b0) | (clk2_en ? clk2 : 1'b0);

endmodule

input.rtl/glitch_free_mux.sv:
module glitch_free_mux
(
    input clk1,		//input clk1
    input clk2,		// input clk2
    input rst_n,	// async reset
    input sel,		// selection line
    output  clkout	// clock output
);

reg clkout_reg ;
reg clk1_enable, clk2_enable;
reg clk1_out, clk2_out ;


// CLK1 ENABLE LOGIC
always@(posedge clk1 or negedge rst_n  ) begin
        if (~rst_n) begin
            clk1_enable <= 0 ; 
        end else begin
            clk1_enable <= ~ clk2_enable & ~sel  ;
        end 
end

// CLK2 ENABLE LOGIC
always@(posedge clk2 or negedge rst_n  ) begin
       if (~rst_n) begin
           clk2_enable <= 0 ; 
       end else begin
           clk2_enable <= ~ clk1_enable & sel  ;
       end 
end

// OUTPUT LOGIC
assign clkout = (clk1 & clk1_enable) | (clk2 & clk2_enable) ;

endmodule

