    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            x_prev1 <= 0; x_prev2 <= 0; x_prev3 <= 0;
            x_prev4 <= 0; x_prev5 <= 0; x_prev6 <= 0;
            y_prev1 <= 0; y_prev2 <= 0; y_prev3 <= 0;
            y_prev4 <= 0; y_prev5 <= 0; y_prev6 <= 0;
        end
        else begin
            // Calculate the filter output (32-bit arithmetic) then shift right by 16 bits.
            temp_y = (b0 * x + b1 * x_prev1 + b2 * x_prev2 + b3 * x_prev3 +
                      b4 * x_prev4 + b5 * x_prev5 + b6 * x_prev6 -
                      a1 * y_prev1 - a2 * y_prev2 - a3 * y_prev3 -
                      a4 * y_prev4 - a5 * y_prev5 - a6 * y_prev6) >>> 16;

            // Use an if-else to assign y, avoiding multiple assignments in the same block.
            if (x > 16'h8000)
                y <= 16'h7FFF;
            else
                y <= temp_y[15:0];

            // Update historical registers
            x_prev6 <= x_prev5; x_prev5 <= x_prev4; x_prev4 <= x_prev3;
            x_prev3 <= x_prev2; x_prev2 <= x_prev1; x_prev1 <= x;
            y_prev6 <= y_prev5; y_prev5 <= y_prev4; y_prev4 <= y_prev3;
            y_prev3 <= y_prev2; y_prev2 <= y_prev1; y_prev1 <= y;
        end
    end

endmodule

output.rtl/cache_mshr.sv:
module cache_mshr #(
    parameter INSTANCE_ID                   = "mo_mshr",
    parameter MSHR_SIZE                     = 32,
    parameter CS_LINE_ADDR_WIDTH            = 10,
    parameter WORD_SEL_WIDTH                = 4,
    parameter WORD_SIZE                     = 4,
    // Derived parameters
    parameter MSHR_ADDR_WIDTH               = $clog2(MSHR_SIZE),     // default = 5
    parameter TAG_WIDTH                     = 32 - (CS_LINE_ADDR_WIDTH + $clog2(WORD_SIZE) + WORD_SEL_WIDTH), // default = 16
    parameter CS_WORD_WIDTH                 = WORD_SIZE * 8,          // default = 32 
    parameter DATA_WIDTH                    = WORD_SEL_WIDTH + WORD_SIZE + CS_WORD_WIDTH + TAG_WIDTH  // default = 4 + 4 + 32 + 16 = 56
)(
    input  wire                           clk,
    input  wire                           reset,

    // allocate
    input  wire                           allocate_valid,
    output wire                           allocate_ready,
    input  wire [CS_LINE_ADDR_WIDTH-1:0]  allocate_addr,
    input  wire                           allocate_rw,
    input  wire [DATA_WIDTH-1:0]          allocate_data,
    output wire [MSHR_ADDR_WIDTH-1:0]     allocate_id,
    output wire                           allocate_pending,
    output wire [MSHR_ADDR_WIDTH-1:0]     allocate_previd,

    // finalize
    input  wire                           finalize_valid,
    input  wire [MSHR_ADDR_WIDTH-1:0]     finalize_id
);

   //-------------------------------------------------------------------------
   // MSHR entry structure: Only meta-data is stored here.
   //-------------------------------------------------------------------------
   typedef struct packed {
       bit valid;
       logic [CS_LINE_ADDR_WIDTH-1:0] cache_line_addr;
       bit write;
       bit next;
       logic [MSHR_ADDR_WIDTH-1:0] next_idx;
   } mshr_entry_t;

   //-------------------------------------------------------------------------
   // MSHR entry array and valid table.
   //-------------------------------------------------------------------------
   mshr_entry_t mshr_entry [0:MSHR_SIZE-1];
   reg [MSHR_SIZE-1:0] entry_valid_table_q;

   //-------------------------------------------------------------------------
   // Wires for allocation logic.
   //-------------------------------------------------------------------------
   wire [MSHR_ADDR_WIDTH-1:0] allocate_id_d;
   wire full_d;
   wire [MSHR_SIZE-1:0] match_with_no_next;
   wire [MSHR_ADDR_WIDTH-1:0] prev_idx;

   //-------------------------------------------------------------------------
   // Instantiate leading zero counter for allocation index.
   // It finds the first available slot by counting leading zeros in ~entry_valid_table_q.
   //-------------------------------------------------------------------------
   leading_zero_cnt #(
       .DATA_WIDTH(MSHR_SIZE),
       .REVERSE(0)
   ) allocate_idx (
       .data(~entry_valid_table_q),
       .leading_zeros(allocate_id_d),
       .all_zeros(full_d)
   );

   //-------------------------------------------------------------------------
   // Compute match_with_no_next: For each entry, if valid, its cache line address 
   // matches the incoming allocate_addr, and it has no next pointer, then assert the bit.
   //-------------------------------------------------------------------------
   genvar i;
   generate
       for (i = 0; i < MSHR_SIZE; i = i + 1) begin : gen_match
           assign match_with_no_next[i] = (mshr_entry[i].valid &&
                                            (mshr_entry[i].cache_line_addr == allocate_addr) &&
                                            (!mshr_entry[i].next));
       end
   endgenerate

   //-------------------------------------------------------------------------
   // Instantiate leading zero counter for previous index.
   // It returns the index of the first MSHR entry (with no next pointer) that matches 
   // the incoming cache line address.
   //-------------------------------------------------------------------------
   leading_zero_cnt #(
       .DATA_WIDTH(MSHR_SIZE),
       .REVERSE(1)
   ) allocate_prev_idx (
       .data(match_with_no_next),
       .leading_zeros(prev_idx),
       .all_zeros() // not connected
   );

   //-------------------------------------------------------------------------
   // Output assignments.
   //-------------------------------------------------------------------------
   assign allocate_ready = ~full_d;         // Ready when there is at least one free slot.
   assign allocate_id    = allocate_id_d;     // Allocated entry index.
   assign allocate_pending = (prev_idx != {MSHR_ADDR_WIDTH{1'b0}}); // Assert if a pending request exists.
   assign allocate_previd  = prev_idx;        // ID of the previous entry for the same cache line.

   //-------------------------------------------------------------------------
   // Sequential logic: Allocation and Finalize.
   // Allocation: On a valid allocation request (and when not full), allocate the first free slot.
   // If the cache line is already pending (i.e. a previous entry exists), link the new entry.
   // Finalize: On finalize, invalidate the entry and update any chain pointers.
   //-------------------------------------------------------------------------
   integer j;
   always_ff @(posedge clk or posedge reset) begin
       if (reset) begin
           // Clear all MSHR entries.
           for (j = 0; j < MSHR_SIZE; j = j + 1) begin
               mshr_entry[j].valid      <= 1'b0;
               mshr_entry[j].cache_line_addr <= {CS_LINE_ADDR_WIDTH{1'b0}};
               mshr_entry[j].write      <= 1'b0;
               mshr_entry[j].next       <= 1'b0;
               mshr_entry[j].next_idx   <= {MSHR_ADDR_WIDTH{1'b0}};
           end
           entry_valid_table_q <= {MSHR_SIZE{1'b0}};
       end
       else begin
           //-------------------------------------------------------------------------
           // Allocation Logic.
           //-------------------------------------------------------------------------
           if (allocate_valid && allocate_ready) begin
               // Allocate new entry at index allocate_id_d.
               mshr_entry[allocate_id_d].valid         <= 1'b1;
               mshr_entry[allocate_id_d].cache_line_addr <= allocate_addr;
               mshr_entry[allocate_id_d].write         <= allocate_rw;
               mshr_entry[allocate_id_d].next          <= 1'b0;
               mshr_entry[allocate_id_d].next_idx      <= {MSHR_ADDR_WIDTH{1'b0}};
               entry_valid_table_q[allocate_id_d]       <= 1'b1;

               // If there is an existing pending request for the same cache line,
               // link the new entry as the next entry.
               if (prev_idx != {MSHR_ADDR_WIDTH{1'b0}}) begin
                   mshr_entry[prev_idx].next      <= 1'b1;
                   mshr_entry[prev_idx].next_idx  <= allocate_id_d;
               end
           end

           //-------------------------------------------------------------------------
           // Finalize Logic.
           // On finalize, invalidate the entry and, if it is part of a chain, update the 
           // previous entry's next pointer to skip the finalized entry.
           //-------------------------------------------------------------------------
           if (finalize_valid) begin
               // Invalidate the finalized entry.
               mshr_entry[finalize_id].valid      <= 1'b0;
               mshr_entry[finalize_id].next       <= 1'b0;
               mshr_entry[finalize_id].next_idx   <= {MSHR_ADDR_WIDTH{1'b0}};
               entry_valid_table_q[finalize_id]      <= 1'b0;

               // If the finalized entry was linked in a chain, update the previous entry.
               if (mshr_entry[finalize_id].next) begin
                   for (j = 0; j < MSHR_SIZE; j = j + 1) begin
                       if (mshr_entry[j].next && (mshr_entry[j].next_idx == finalize_id)) begin
                           mshr_entry[j].next_idx <= mshr_entry[finalize_id].next_idx;
                           mshr_entry[j].next     <= (mshr_entry[finalize_id].next_idx != {MSHR_ADDR_WIDTH{1'b0}});
                       end
                   end
               end
           end
       end
   end

endmodule

//--------------------------------------------------------------------------
// The following is the leading_zero_cnt module used for computing the 
// index of the first available slot and the previous pending request.
//--------------------------------------------------------------------------
module leading_zero_cnt #(
    parameter DATA_WIDTH = 32,
    parameter REVERSE = 0 
)(
    input  [DATA_WIDTH-1:0] data,
    output [$clog2(DATA_WIDTH)-1:0] leading_zeros,
    output all_zeros
);
    localparam NIBBLES_NUM = DATA_WIDTH/4; 
    reg [NIBBLES_NUM-1:0] all_zeros_flag;
    reg [1:0] zeros_cnt_per_nibble [NIBBLES_NUM-1:0];

    genvar i;
    integer k;
    // Break data into nibbles.
    reg [3:0] data_per_nibble [NIBBLES_NUM-1:0];
    generate
        for (i = 0; i < NIBBLES_NUM; i = i + 1) begin
            always @* begin
                data_per_nibble[i] = data[(i*4)+3:(i*4)];
            end
        end
    endgenerate

    generate
        for (i = 0; i < NIBBLES_NUM; i = i + 1) begin : g_nibble
            if (REVERSE) begin : g_trailing
                always @* begin
                    zeros_cnt_per_nibble[i][1] = ~(data_per_nibble[i][1] | data_per_nibble[i][0]); 
                    zeros_cnt_per_nibble[i][0] = (~data_per_nibble[i][0]) &
                                                   ((~data_per_nibble[i][2]) | data_per_nibble[i][1]);
                    all_zeros_flag[i] = (data_per_nibble[i] == 4'b0000);
                end
            end else begin : g_leading
                always @* begin
                    zeros_cnt_per_nibble[NIBBLES_NUM-1-i][1] = ~(data_per_nibble[i][3] | data_per_nibble[i][2]); 
                    zeros_cnt_per_nibble[NIBBLES_NUM-1-i][0] = (~data_per_nibble[i][3]) &
                                                                ((~data_per_nibble[i][1]) | data_per_nibble[i][2]);
                    all_zeros_flag[NIBBLES_NUM-1-i] = (data_per_nibble[i] == 4'b0000);
                end
            end
        end
    endgenerate

    reg [$clog2(NIBBLES_NUM)-1:0] index; 
    reg [1:0] choosen_nibbles_zeros_count;
    reg [$clog2(NIBBLES_NUM*4)-1:0] zeros_count_result;
    wire [NIBBLES_NUM-1:0] all_zeros_flag_decoded;

    assign all_zeros_flag_decoded[0] = all_zeros_flag[0];
    genvar j;
    generate
        for (j = 1; j < NIBBLES_NUM; j = j + 1) begin
            assign all_zeros_flag_decoded[j] = all_zeros_flag_decoded[j-1] & all_zeros_flag[j];
        end
    endgenerate

    always @* begin
        index = 0;
        for (k = 0; k < NIBBLES_NUM; k = k + 1) begin
            index = index + all_zeros_flag_decoded[k];
        end
    end

    always @* begin
        choosen_nibbles_zeros_count = zeros_cnt_per_nibble[index];
        zeros_count_result = choosen_nibbles_zeros_count + (index << 2);
    end

    assign leading_zeros = zeros_count_result;
    assign all_zeros = (data == 0);

endmodule

module cache_mshr #(
    parameter INSTANCE_ID            = "mo_mshr"             ,
    parameter MSHR_SIZE                     = 32                    ,
    parameter CS_LINE_ADDR_WIDTH            = 10                    ,
    parameter WORD_SEL_WIDTH                = 4                     ,
    parameter WORD_SIZE                     = 4                     ,
    // Derived parameters
    parameter MSHR_ADDR_WIDTH               = $clog2(MSHR_SIZE)     , // default = 5
    parameter TAG_WIDTH                     = 32 - (CS_LINE_ADDR_WIDTH+ $clog2(WORD_SIZE) + WORD_SEL_WIDTH), // default = 16
    parameter CS_WORD_WIDTH                 = WORD_SIZE * 8 ,// default = 32 
    parameter DATA_WIDTH                    = WORD_SEL_WIDTH + WORD_SIZE + CS_WORD_WIDTH + TAG_WIDTH // default =  4 + 4 + 32 + 16 = 56

    ) (
    input wire clk,
    input wire reset,

     // memory fill
    input wire                           fill_valid,
    input wire [MSHR_ADDR_WIDTH-1:0]     fill_id,
    output wire [CS_LINE_ADDR_WIDTH-1:0] fill_addr,

    // dequeue
    output wire                          dequeue_valid,
    output wire [CS_LINE_ADDR_WIDTH-1:0] dequeue_addr,
    output wire                          dequeue_rw,
    output wire [DATA_WIDTH-1:0]         dequeue_data,
    output wire [MSHR_ADDR_WIDTH-1:0]    dequeue_id,
    input wire                           dequeue_ready,

    // allocate
    input wire                          allocate_valid,
    output wire                         allocate_ready,
    input wire [CS_LINE_ADDR_WIDTH-1:0] allocate_addr,
    input wire                          allocate_rw,
    input wire [DATA_WIDTH-1:0]         allocate_data,
    output wire [MSHR_ADDR_WIDTH-1:0]   allocate_id,
    output wire                         allocate_pending,
    output wire [MSHR_ADDR_WIDTH-1:0]   allocate_previd,

    // finalize
    input wire                          finalize_valid,
    input wire [MSHR_ADDR_WIDTH-1:0]    finalize_id
);

    // Internal storage for MSHR entries
    reg [CS_LINE_ADDR_WIDTH-1:0] cs_line_addr_table [0:MSHR_SIZE-1];
    reg [MSHR_SIZE-1:0] entry_valid_table_q, entry_valid_table_d;
    reg [MSHR_SIZE-1:0] is_write_table;

    // Next pointer flag and pointer table
    reg [MSHR_SIZE-2:0] next_ptr_valid_table_q, next_ptr_valid_table_d;
    reg [MSHR_ADDR_WIDTH-1:0] next_index_ptr [0:MSHR_SIZE-1]; // pointer to the next entry

    // Allocation pending signals
    reg  allocate_pending_q, allocate_pending_d;
    reg [MSHR_ADDR_WIDTH-1:0] allocate_id_q, allocate_id_d;
    wire [MSHR_ADDR_WIDTH-1:0] prev_idx ;
    reg [MSHR_ADDR_WIDTH-1:0]  prev_idx_q;

    // Dequeue interface temporary registers
    reg dequeue_valid_q, dequeue_valid_d ;
    reg [MSHR_ADDR_WIDTH-1:0] dequeue_id_q, dequeue_id_d ;

    // New registers for the dequeue state machine
    // state: 0 = IDLE, 1 = DEQUEUEING
    reg [1:0] state;
    reg [MSHR_ADDR_WIDTH-1:0] deq_ptr;

    // Allocation control signal: new request valid and ready
    wire allocate_fire = allocate_valid && allocate_ready;

    // Insert code here to determine when dequeue operation should occur

    // Address lookup: find any existing entry with the same cache line address
    wire [MSHR_SIZE-1:0] addr_matches;
    genvar i;
    generate
        for (i = 0; i < MSHR_SIZE; i = i + 1) begin : g_addr_matches
            assign addr_matches[i] = entry_valid_table_q[i] && (cs_line_addr_table[i] == allocate_addr) && allocate_fire;
        end
    endgenerate

    wire [MSHR_SIZE-1:0] match_with_no_next = addr_matches & ~next_ptr_valid_table_q ;
    wire full_d ; 

    // Leading zero counter to find first free slot
    leading_zero_cnt #(
            .DATA_WIDTH (MSHR_SIZE),
            .REVERSE (1)
    ) allocate_idx (
            .data   (~entry_valid_table_q),
            .leading_zeros  (allocate_id_d),
            .all_zeros (full_d)
    );

    // Leading zero counter to find the first entry in the chain with no next pointer
    leading_zero_cnt #(
            .DATA_WIDTH (MSHR_SIZE),
            .REVERSE (1)
    ) allocate_prev_idx (
            .data   (match_with_no_next),
            .leading_zeros  (prev_idx),
            `NOTCONNECTED_PIN(all_zeros) // not connected
    );

    // Combinational logic update for allocation and finalize operations
    always @(*) begin
        entry_valid_table_d     = entry_valid_table_q;
        next_ptr_valid_table_d  = next_ptr_valid_table_q;

        // No combinational logic needed for dequeue here as it's handled in a separate state machine.

        if (finalize_valid) begin
            entry_valid_table_d[finalize_id] = 0;
        end

        if (allocate_fire) begin
            entry_valid_table_d[allocate_id_d] = 1;
            next_ptr_valid_table_d[allocate_id_d] = 0;
        end

        if (allocate_pending_d) begin
            next_ptr_valid_table_d[prev_idx] = 1;
        end
    end

    // Clocked process: update valid tables and pointers
    always @(posedge clk) begin
        if (reset) begin
            entry_valid_table_q  <= '0;
            next_ptr_valid_table_q  <=  0;
            allocate_pending_q <= 0 ;
        end else begin
            entry_valid_table_q  <= entry_valid_table_d;
            next_ptr_valid_table_q  <=  next_ptr_valid_table_d;
            allocate_pending_q <= allocate_pending_d ; 
        end

        if (allocate_fire) begin
            cs_line_addr_table[allocate_id_d]   <= allocate_addr;
            is_write_table[allocate_id_d]       <= allocate_rw;
        end

        if (allocate_pending_d) begin
            next_index_ptr[prev_idx] <= allocate_id_d;
        end
    end

    // Clocked process: update allocation ID and previous index signals
    always @(posedge clk) begin
        if (reset) begin
            allocate_id_q       <=  0 ;
            prev_idx_q          <= 0 ;
        end else begin
            if (allocate_fire) begin
                allocate_id_q       <=  allocate_id_d       ;
                prev_idx_q          <= prev_idx ;
            end 
        end
    end

    // Single-Port RAM to store request data
    reg [DATA_WIDTH-1:0] ram [0:MSHR_SIZE-1];
    reg [DATA_WIDTH-1:0] dequeue_data_int;
    always @(posedge clk) begin
        if (allocate_fire) begin
            ram[allocate_id_d] <= allocate_data ;
        end
    end

    // Dequeue state machine: when a fill request is received, start dequeuing the chain
    always @(posedge clk) begin
        if (reset) begin
            state <= 0;
            deq_ptr <= 0;
        end else begin
            if (state == 0 && fill_valid) begin
                // Start the dequeue chain using the fill_id provided
                state <= 1;
                deq_ptr <= fill_id;
            end else if (state == 1) begin
                if (dequeue_ready) begin
                    // Dequeue the current entry and move to the next if available
                    if (next_ptr_valid_table_q[deq_ptr]) begin
                        deq_ptr <= next_index_ptr[deq_ptr];
                    end else begin
                        // End of chain reached; go back to idle
                        state <= 0;
                        deq_ptr <= 0;
                    end
                end
            end
        end
    end

    // Output assignments for allocation interface
    assign  allocate_pending_d = |addr_matches;
    assign allocate_id = allocate_id_q ;
    assign allocate_ready = ~full_d ;
    assign allocate_previd = prev_idx_q;

    assign allocate_pending = allocate_pending_q;

    // Fill interface: output the cache line address for the fill request
    assign fill_addr = fill_valid ? cs_line_addr_table[fill_id] : '0;

    // Dequeue interface: output the current entry from the dequeue chain
    assign dequeue_valid = (state == 1);
    assign dequeue_addr = cs_line_addr_table[deq_ptr];
    assign dequeue_rw = is_write_table[deq_ptr];
    assign dequeue_data = ram[deq_ptr];
    assign dequeue_id = deq_ptr;

endmodule


module leading_zero_cnt #(
    parameter DATA_WIDTH = 32,
    parameter REVERSE = 0 
)(
    input  [DATA_WIDTH -1:0] data,
    output  [$clog2(DATA_WIDTH)-1:0] leading_zeros,
    output all_zeros 
);
    localparam NIBBLES_NUM = DATA_WIDTH/4 ; 
    reg [NIBBLES_NUM-1 :0] all_zeros_flag ;
    reg [1:0]  zeros_cnt_per_nibble [NIBBLES_NUM-1 :0]  ;

    genvar i;
    integer k ;
    // Divide data into nibbles
    reg [3:0]  data_per_nibble [NIBBLES_NUM-1 :0]  ;
    generate
        for (i=0; i < NIBBLES_NUM ; i=i+1) begin
            always @* begin
                data_per_nibble[i] = data[(i*4)+3: (i*4)] ;
            end
        end
    endgenerate

    generate
        for (i=0; i < NIBBLES_NUM ; i=i+1) begin : g_nibble
            if (REVERSE) begin : g_trailing
                always @* begin
                        zeros_cnt_per_nibble[i] [1] = ~(data_per_nibble[i][1] | data_per_nibble[i][0]); 
                        zeros_cnt_per_nibble[i] [0] = (~data_per_nibble[i][0]) &
                                                      ((~data_per_nibble[i][2]) | data_per_nibble[i][1]);
                        all_zeros_flag[i] = (data_per_nibble[i] == 4'b0000);
                end
            end else begin :g_leading
                always @* begin
                    zeros_cnt_per_nibble[NIBBLES_NUM-1-i][1] = ~(data_per_nibble[i][3] | data_per_nibble[i][2]); 
                    zeros_cnt_per_nibble[NIBBLES_NUM-1-i][0] = (~data_per_nibble[i][3]) &
                                     ((~data_per_nibble[i][1]) | data_per_nibble[i][2]);

                    all_zeros_flag[NIBBLES_NUM-1-i] = (data_per_nibble[i] == 4'b0000);
                end
            end
        end
    endgenerate

    reg [$clog2(NIBBLES_NUM)-1:0] index ; 
    reg [1:0]    choosen_nibbles_zeros_count ;
    reg [ $clog2(NIBBLES_NUM*4)-1:0] zeros_count_result ;
    wire [NIBBLES_NUM-1:0]         all_zeros_flag_decoded;

    assign all_zeros_flag_decoded[0] = all_zeros_flag[0] ;
    genvar j;
        generate
            for (j=1; j < NIBBLES_NUM; j=j+1) begin
                assign all_zeros_flag_decoded[j] = all_zeros_flag_decoded[j-1] & all_zeros_flag[j];
            end
        endgenerate

    always@ * begin
        index = 0 ;
        for ( k =0 ; k< NIBBLES_NUM ; k =k +1) begin
            index = index + all_zeros_flag_decoded[k] ;
        end
    end

    always@* begin
        choosen_nibbles_zeros_count = zeros_cnt_per_nibble[index]  ;  
        zeros_count_result = choosen_nibbles_zeros_count + (index <<2) ; 
    end

    assign leading_zeros =  zeros_count_result ;
    assign all_zeros = (data ==0) ;

endmodule

output.rtl/serial_line_code_converter.sv:
module serial_line_code_converter #(parameter CLK_DIV = 16)(
    input  logic clk,             // System clock
    input  logic reset_n,         // Active-low reset
    input  logic serial_in,       // Serial input signal
    input  logic [2:0] mode,      // Mode selector
    output logic serial_out       // Serial output signal
);

    // Internal signals
    logic [3:0] clk_counter;      // Clock divider counter
    logic clk_pulse;              // Clock pulse for sampling
    logic prev_serial_in;         // Previous serial input for edge detection
    logic prev_value;             // Holds the previous value of serial_in
    logic nrz_out;                // NRZ encoding output
    logic rz_out;                 // Return-to-Zero encoding output
    logic diff_out;               // Differential encoding output
    logic inv_nrz_out;            // Inverted NRZ output
    logic alt_invert_out;         // NRZ with alternating bit inversion output
    logic alt_invert_state;       // State for alternating inversion
    logic parity_out;             // Parity Bit Output
    logic scrambled_out;          // Scrambled NRZ output
    logic edge_triggered_out;     // Edge-Triggered NRZ output

    // Clock Pulse Generation
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            clk_counter <= 0;
            clk_pulse   <= 0;
        end else begin
            if (clk_counter == CLK_DIV - 1) begin
                clk_counter <= 0;
                clk_pulse   <= 1;
            end else begin
                clk_counter <= clk_counter + 1;
                clk_pulse   <= 0;
            end
        end
    end

    // Previous Serial Input Tracking
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            prev_value     <= 0;
            prev_serial_in <= 0;
        end else begin
            prev_value     <= serial_in;
            prev_serial_in <= prev_value;
        end
    end

    // NRZ Pass-Through (direct output of serial input)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            nrz_out <= 0;
        else
            nrz_out <= serial_in;
    end

    // Return-to-Zero (RZ) Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            rz_out <= 0;
        else begin
            if (clk_pulse)
                rz_out <= serial_in;
            else
                rz_out <= 0;
        end
    end

    // Differential Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            diff_out <= 0;
        else
            diff_out <= serial_in ^ prev_serial_in;
    end

    // Inverted NRZ Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            inv_nrz_out <= 0;
        else
            inv_nrz_out <= ~serial_in;
    end

    // NRZ with Alternating Bit Inversion
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            alt_invert_state <= 0;
            alt_invert_out   <= 0;
        end else begin
            alt_invert_state <= ~alt_invert_state; // Toggle state each clock cycle
            if (alt_invert_state)
                alt_invert_out <= ~serial_in;
            else
                alt_invert_out <= serial_in;
        end
    end

    // Parity Bit Output (Odd Parity Calculation)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            parity_out <= 0;
        else
            parity_out <= parity_out ^ serial_in;
    end

    // Scrambled NRZ (Simple XOR with a fixed pattern)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            scrambled_out <= 0;
        else
            scrambled_out <= serial_in ^ clk_counter[0];
    end

    // Edge-Triggered NRZ
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            edge_triggered_out <= 0;
        else
            edge_triggered_out <= (serial_in & ~prev_serial_in);
    end

    // Output Multiplexer
    always_comb begin
        case (mode)
            3'b000: serial_out = nrz_out;
            3'b001: serial_out = rz_out;
            3'b010: serial_out = diff_out;
            3'b011: serial_out = inv_nrz_out;
            3'b100: serial_out = alt_invert_out;
            3'b101: serial_out = parity_out;
            3'b110: serial_out = scrambled_out;
            3'b111: serial_out = edge_triggered_out;
            default: serial_out = 0;
        endcase
    end

endmodule

module serial_line_code_converter #(parameter CLK_DIV = 16)(
    input  logic clk,             // System clock
    input  logic reset_n,         // Active-low asynchronous reset
    input  logic serial_in,       // Serial input signal
    input  logic enable,          // Module enable signal
    input  logic [2:0] mode,      // Mode selector
    output logic serial_out,      // Encoded output signal
    output logic error_flag,      // Error flag output
    output logic [15:0] diagnostic_bus  // 16-bit diagnostic bus
);

    // Internal signals
    logic [3:0] clk_counter;      // Clock divider counter
    logic clk_pulse;              // Clock pulse for timing-specific encodings
    logic prev_serial_in;         // Previous serial input for edge detection
    logic prev_value;             // Holds the previous value of serial_in
    logic nrz_out;                // NRZ encoding output
    logic rz_out;                 // Return-to-Zero encoding output
    logic diff_out;               // Differential encoding output
    logic inv_nrz_out;            // Inverted NRZ output
    logic alt_invert_out;         // NRZ with alternating bit inversion output
    logic alt_invert_state;       // State for alternating inversion
    logic parity_out;             // Parity Bit Output
    logic scrambled_out;          // Scrambled NRZ output
    logic edge_triggered_out;     // Edge-Triggered NRZ output
    logic [7:0] error_counter;    // 8-bit error counter

    // Clock pulse generation (gated by enable)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            clk_counter <= 0;
            clk_pulse   <= 0;
        end else if (enable) begin
            if (clk_counter == CLK_DIV - 1) begin
                clk_counter <= 0;
                clk_pulse   <= 1;
            end else begin
                clk_counter <= clk_counter + 1;
                clk_pulse   <= 0;
            end
        end
        // else: hold state when enable is low
    end

    // Previous serial input tracking (gated by enable)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            prev_value     <= 0;
            prev_serial_in <= 0;
        end else if (enable) begin
            prev_value     <= serial_in;
            prev_serial_in <= prev_value;
        end
        // else: hold state when enable is low
    end

    // NRZ (Non-Return-to-Zero) encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            nrz_out <= 0;
        end else if (enable) begin
            nrz_out <= serial_in;
        end
        // else: hold state when enable is low
    end

    // RZ (Return-to-Zero) encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            rz_out <= 0;
        end else if (enable) begin
            rz_out <= serial_in & clk_pulse;
        end
        // else: hold state when enable is low
    end

    // Differential Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            diff_out <= 0;
        end else if (enable) begin
            diff_out <= serial_in ^ prev_serial_in;
        end
        // else: hold state when enable is low
    end

    // Inverted NRZ encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            inv_nrz_out <= 0;
        end else if (enable) begin
            inv_nrz_out <= ~serial_in;
        end
        // else: hold state when enable is low
    end

    // NRZ with Alternating Bit Inversion
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            alt_invert_out  <= 0;
            alt_invert_state<= 0;
        end else if (enable) begin
            alt_invert_state<= ~alt_invert_state;
            alt_invert_out  <= (alt_invert_state ? ~serial_in : serial_in);
        end
        // else: hold state when enable is low
    end

    // Parity Bit Output (Odd Parity)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            parity_out <= 0;
        end else if (enable) begin
            // Compute odd parity: XOR current serial_in with previous parity_out
            parity_out <= serial_in ^ parity_out;
        end
        // else: hold state when enable is low
    end

    // Scrambled NRZ encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            scrambled_out <= 0;
        end else if (enable) begin
            scrambled_out <= serial_in ^ clk_counter[0];
        end
        // else: hold state when enable is low
    end

    // Edge-Triggered NRZ encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            edge_triggered_out <= 0;
        end else if (enable) begin
            edge_triggered_out <= (serial_in & ~prev_serial_in);
        end
        // else: hold state when enable is low
    end

    // Error Detection: Check for invalid serial_in values (1'bx or 1'bz)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            error_flag   <= 0;
            error_counter<= 0;
        end else if (enable) begin
            if (serial_in !== 0 && serial_in !== 1) begin
                error_flag   <= 1;
                error_counter<= error_counter + 1;
            end else begin
                error_flag <= 0;
            end
        end
        // else: hold state when enable is low
    end

    // Output Assignment and Diagnostic Bus Generation
    always_comb begin
        if (!enable) begin
            // When disabled, force outputs to 0
            serial_out         = 0;
            diagnostic_bus     = 16'b0;
        end else begin
            // Select encoded output based on mode selector
            case (mode)
                3'b000: serial_out = nrz_out;                
                3'b001: serial_out = rz_out;                 
                3'b010: serial_out = diff_out;               
                3'b011: serial_out = inv_nrz_out;            
                3'b100: serial_out = alt_invert_out;         
                3'b101: serial_out = parity_out;             
                3'b110: serial_out = scrambled_out;          
                3'b111: serial_out = edge_triggered_out;     
                default: serial_out = 0;                     
            endcase

            // Pack diagnostic information into the 16-bit bus:
            // [15:13]  - Current mode (3 bits)
            // [12]     - Error flag (1 bit)
            // [11:4]   - Error counter (8 bits)
            // [3]      - Clock pulse status (1 bit)
            // [2]      - Encoded output (1 bit)
            // [1]      - Alternating inversion output (1 bit)
            // [0]      - Parity bit output (1 bit)
            diagnostic_bus = { mode, error_flag, error_counter, clk_pulse, serial_out, alt_invert_out, parity_out };
        end
    end

endmodule

input.rtl/String_to_ASCII_Converter.sv:
module String_to_ASCII_Converter (
    input wire clk,                       // Clock signal
    input wire reset,                     // Reset signal
    input wire start,                     // Start conversion
    input wire [7:0] char_in [7:0],       // 8-character input string (7 bits per character: 0-95)
    output reg [7:0] ascii_out,           // Final latched ASCII output
    output reg valid,                     // Indicates valid output
    output reg ready                      // Indicates module ready to accept input
);
    // Parameters for character type identification
    localparam DIGIT   = 2'd0;
    localparam UPPER   = 2'd1;
    localparam LOWER   = 2'd2;
    localparam SPECIAL = 2'd3;
    // ASCII Offsets
    localparam DIGIT_OFFSET   = 8'd48;    // '0' = 48
    localparam UPPER_OFFSET   = 8'd65;    // 'A' = 65
    localparam LOWER_OFFSET   = 8'd97;    // 'a' = 97
    localparam SPECIAL_OFFSET = 8'd33;   // First special character '!' = 33
    // Registers
    reg [3:0] index;                      // Index for current character
    reg active;                           // Indicates active conversion
    reg [1:0] char_type;                  // Current character type
    reg [7:0] intermediate_ascii;         // Combinational ASCII value
    // Function to determine character type
    function [1:0] determine_char_type;
        input [7:0] char;
        begin
            if (char < 8'd10)
                determine_char_type = DIGIT;    // '0'-'9'
            else if (char < 8'd36)
                determine_char_type = UPPER;    // 'A'-'Z'
            else if (char < 8'd62)
                determine_char_type = LOWER;    // 'a'-'z'
            else
                determine_char_type = SPECIAL;  // Special characters
        end
    endfunction
    // Combinational logic for ASCII calculation
    always @(*) begin
        // Determine character type
        char_type = determine_char_type(char_in[index]);
        // Calculate ASCII based on character type
        case (char_type)
            DIGIT:   intermediate_ascii = char_in[index] + DIGIT_OFFSET;          // '0'-'9'
            UPPER:   intermediate_ascii = (char_in[index] - 8'd10) + UPPER_OFFSET; // 'A'-'Z'
            LOWER:   intermediate_ascii = (char_in[index] - 8'd36) + LOWER_OFFSET; // 'a'-'z'
            SPECIAL: intermediate_ascii = (char_in[index] - 8'd62) + SPECIAL_OFFSET; // Special characters
            default: intermediate_ascii = 8'd0;
        endcase
    end
    // Sequential logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            index       <= 4'd0;
            ascii_out   <= 8'd0;
            valid       <= 1'b0;
            ready       <= 1'b1;
            active      <= 1'b0;
        end else begin
            if (start && ready) begin
                // Start conversion
                ready <= 1'b0;
                active <= 1'b1;
                index <= 4'd0;
                valid <= 1'b0;
            end else if (active) begin
                // Process current character
                if (index < 8) begin
                    ascii_out <= intermediate_ascii; // Latch current ASCII value
                    valid <= 1'b1; // Indicate valid output
                    index <= index + 1;
                end else begin
                    // Finish conversion
                    active <= 1'b0;
                    ready <= 1'b1;
                    valid <= 1'b0;
                end
            end
        end
    end
endmodule

