output.rtl/ahb_clock_counter.sv:
module ahb_clock_counter #(
    parameter ADDR_WIDTH = 32, // Width of the address bus
    parameter DATA_WIDTH = 32  // Width of the data bus
)(
    input  wire                 HCLK,      // AHB Clock
    input  wire                 HRESETn,   // AHB Reset (Active Low)
    input  wire                 HSEL,      // AHB Select
    input  wire [ADDR_WIDTH-1:0] HADDR,    // AHB Address
    input  wire                 HWRITE,    // AHB Write Enable
    input  wire [DATA_WIDTH-1:0] HWDATA,   // AHB Write Data
    input  wire                 HREADY,    // AHB Ready Signal
    output reg  [DATA_WIDTH-1:0] HRDATA,   // AHB Read Data
    output reg                 HRESP,     // AHB Response (OKAY = 0)
    output reg  [DATA_WIDTH-1:0] COUNTER   // Counter Output
);

  // Define the memory-mapped addresses.
  localparam [ADDR_WIDTH-1:0] ADDR_START   = 32'h00000000; // Write 1 to start/resume counter
  localparam [ADDR_WIDTH-1:0] ADDR_STOP    = 32'h00000004; // Write 1 to stop the counter
  localparam [ADDR_WIDTH-1:0] ADDR_COUNTER = 32'h00000008; // Read current counter value
  localparam [ADDR_WIDTH-1:0] ADDR_OVERFLOW= 32'h0000000C; // Read overflow flag
  localparam [ADDR_WIDTH-1:0] ADDR_MAXCNT  = 32'h00000010; // Write new maximum count value

  // Internal registers for control and configuration.
  reg                         enable;       // Counter enable signal
  reg                         overflow_flag;// Overflow flag (remains set until reset)
  reg [DATA_WIDTH-1:0]        max_cnt;      // Maximum count value for overflow condition

  // Synchronous logic: register updates, counter operations, and AHB interface handling.
  // Asynchronous reset: when HRESETn is low, all registers and the counter are reset to 0.
  always_ff @(posedge HCLK or negedge HRESETn) begin
    if (!HRESETn) begin
      enable            <= 1'b0;
      overflow_flag     <= 1'b0;
      COUNTER           <= {DATA_WIDTH{1'b0}};
      max_cnt           <= {DATA_WIDTH{1'b0}};
      HRESP             <= 1'b0;
    end
    else begin
      // Only process transactions when the slave is selected and ready.
      if (HSEL && HREADY) begin
        // Write operations.
        if (HWRITE) begin
          case (HADDR)
            ADDR_START:   if (HWDATA[0] == 1'b1) enable <= 1'b1;  // Start/resume counter
            ADDR_STOP:    if (HWDATA[0] == 1'b1) enable <= 1'b0;  // Stop counter
            ADDR_MAXCNT:  max_cnt <= HWDATA;                       // Configure maximum count value
            default:      ; // Ignore writes to undefined addresses.
          endcase
        end

        // Counter update (synchronous logic).
        // If the counter is enabled, increment it.
        // When the counter reaches the maximum count value, set the overflow flag and wrap around.
        if (enable) begin
          if (COUNTER == max_cnt) begin
            overflow_flag <= 1'b1;
            COUNTER       <= {DATA_WIDTH{1'b0}};
          end
          else begin
            COUNTER <= COUNTER + 1;
          end
        end
      end

      // Always indicate an OKAY response.
      HRESP <= 1'b0;
    end
  end

  // Combinational logic: Generate HRDATA based on the accessed address.
  always_comb begin
    // Default read data is zero.
    HRDATA = {DATA_WIDTH{1'b0}};
    if (HSEL && HREADY && !HWRITE) begin
      case (HADDR)
        ADDR_START:   HRDATA = 1'b0;  // Read returns 0 (no start command pending)
        ADDR_STOP:    HRDATA = 1'b0;  // Read returns 0 (no stop command pending)
        ADDR_COUNTER: HRDATA = COUNTER;
        ADDR_OVERFLOW: HRDATA = { {DATA_WIDTH-1{1'b0}}, overflow_flag };
        ADDR_MAXCNT:  HRDATA = max_cnt;
        default:      HRDATA = {DATA_WIDTH{1'b0}};
      endcase
    end
  end

endmodule

input.rtl/alphablending.sv:
module alphablending #(
    parameter H = 5,
    parameter N = 3,
    parameter W = 8
) (
    input clk,
    input reset,
    input start,
    input [(24*H*W)-1:0] pixel_in,    // N pixels, each 24-bit RGB
    input [(8*H*W)-1:0] alpha_in,     // N alpha values, each 8-bit
    input [(24*H*W)-1:0] bg_pixel_in, // N background pixels, each 24-bit RGB
    output reg [(24*H*W)-1:0] blended_out, // N blended output pixels
    output reg done
);

// State Encoding
localparam IDLE     = 2'b00;
localparam LOAD     = 2'b01;
localparam COMPUTE  = 2'b10;
localparam COMPLETE = 2'b11;
localparam STORE    = 2'b11;

reg [1:0] state, next_state;

// Registers for inputs and outputs
reg [23:0] pixel [0:H*W-1];       // Individual pixels (24-bit each)
reg [7:0] alpha [0:H*W-1];        // Individual alpha values (8-bit each)
reg [23:0] bg_pixel [0:H*W-1];    // Individual background pixels (24-bit each)
reg [23:0] blended [0:H*W-1];     // Individual blended results (24-bit each)

// Pixel count and padding logic
integer i;
integer pixel_count;
integer total_pixels;
integer padded_pixels;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        pixel_count <= 0;
        total_pixels <= 0;
        padded_pixels <= 0;
    end else if (state == IDLE && start) begin
        pixel_count <= 0;
        total_pixels <= H * W;
        padded_pixels <= (((H * W + N - 1) / N) * N) - (H * W);
    end else if (state == COMPUTE && pixel_count < total_pixels + padded_pixels) begin
        pixel_count <= pixel_count + N;
    end
end

// State Transition Logic
always @(posedge clk or posedge reset) begin
    if (reset) 
        state <= IDLE;
    else 
        state <= next_state;
end

// Next State Logic
always @(state or start) begin
    case (state)
        IDLE: next_state = (start) ? LOAD : IDLE;
        LOAD: next_state = COMPUTE;
        COMPUTE: next_state = (pixel_count < total_pixels + padded_pixels) ? LOAD : COMPLETE;
        COMPLETE: next_state = IDLE;
        STORE:  next_state = IDLE;
    endcase
end

// Alpha Blending Calculation
// Formula: blended = (alpha * pixel + (255 - alpha) * bg_pixel) / 255
always @(posedge clk) begin
    if (state == LOAD) begin
        // Unpack inputs into arrays
        for (i = 0; i < N; i = i + 1) begin
            if (pixel_count + i < total_pixels) begin
                pixel[i] <= pixel_in[(pixel_count + i)*24 +: 24];
                alpha[i] <= alpha_in[(pixel_count + i)*8 +: 8];
                bg_pixel[i] <= bg_pixel_in[(pixel_count + i)*24 +: 24];
            end 
            else begin
                pixel[i] <= 24'd0; // Pad with 0 if out of bounds
                alpha[i] <= 8'd0;
                bg_pixel[i] <= 24'd0;
            end
        end
    end
    else if (state == COMPUTE) begin
        for (i = 0; i < N; i = i + 1) begin
            blended[pixel_count + i][23:16] <= (alpha[i] * pixel[i][23:16] + (255 - alpha[i]) * bg_pixel[i][23:16]) / 255;
            blended[pixel_count + i][15:8]  <= (alpha[i] * pixel[i][15:8]  + (255 - alpha[i]) * bg_pixel[i][15:8])  / 255;
            blended[pixel_count + i][7:0]   <= (alpha[i] * pixel[i][7:0]   + (255 - alpha[i]) * bg_pixel[i][7:0])   / 255;
        end
    end
    else if (state == COMPLETE) begin
        // Pack blended results into output
        for (i = 0; i < H*W; i = i + 1) begin
            blended_out[i*24 +: 24] <= blended[i][23:0];
        end
    end
end

// Output Logic
always @(posedge clk) begin
    if (reset) begin
        done <= 0;
        blended_out <= 0;
    end
    else if (state == COMPLETE) begin
        done <= 1;
    end
    else begin
        done <= 0;
    end
end

endmodule

output.rtl/alphablending.sv:
module alphablending #(
    parameter H = 5,
    parameter N = 3,
    parameter W = 8
) (
    input         clk,
    input         reset,
    input         start,
    input [(24*H*W)-1:0] pixel_in,    // N pixels, each 24-bit RGB
    input [(8*H*W)-1:0]  alpha_in,     // N alpha values, each 8-bit
    input [(24*H*W)-1:0] bg_pixel_in, // N background pixels, each 24-bit RGB
    output reg [(24*H*W)-1:0] blended_out, // N blended output pixels
    output reg     done
);

  // State Encoding (removed overlapping STORE state)
  localparam IDLE     = 2'b00;
  localparam LOAD     = 2'b01;
  localparam COMPUTE  = 2'b10;
  localparam COMPLETE = 2'b11;

  reg [1:0] state, next_state;

  // Registers for inputs and outputs
  reg [23:0] pixel [0:H*W-1];       // Individual pixels (24-bit each)
  reg [7:0]  alpha [0:H*W-1];        // Individual alpha values (8-bit each)
  reg [23:0] bg_pixel [0:H*W-1];     // Individual background pixels (24-bit each)
  reg [23:0] blended [0:H*W-1];      // Individual blended results (24-bit each)

  // Pixel count and padding logic
  integer i;
  integer pixel_count;
  integer total_pixels;
  integer padded_pixels;

  // Update pixel_count, total_pixels, and padded_pixels on reset or during operation.
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      pixel_count    <= 0;
      total_pixels   <= 0;
      padded_pixels  <= 0;
    end 
    else if (state == IDLE && start) begin
      pixel_count    <= 0;
      total_pixels   <= H * W;
      padded_pixels  <= (((H * W + N - 1) / N) * N) - (H * W);
    end 
    else if (state == COMPUTE && pixel_count < total_pixels + padded_pixels) begin
      pixel_count <= pixel_count + N;
    end
  end

  // Combined state update and output logic to avoid multiple asynchronous drivers.
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      state         <= IDLE;
      done          <= 0;
      blended_out   <= 0;
    end 
    else begin
      state <= next_state;
      if (state == COMPLETE) begin
        done <= 1;
        // Pack blended results into output
        for (i = 0; i < H*W; i = i + 1) begin
          blended_out[i*24 +: 24] <= blended[i];
        end
      end 
      else begin
        done <= 0;
      end
    end
  end

  // Next state logic (removed overlapping STORE state)
  always @(state or start or pixel_count or total_pixels or padded_pixels) begin
    case (state)
      IDLE:   next_state = (start) ? LOAD : IDLE;
      LOAD:   next_state = COMPUTE;
      COMPUTE: next_state = (pixel_count < total_pixels + padded_pixels) ? LOAD : COMPLETE;
      COMPLETE: next_state = IDLE;
      default: next_state = IDLE;
    endcase
  end

  // Alpha Blending Calculation
  // Formula: blended = (alpha * pixel + (255 - alpha) * bg_pixel) / 255
  always @(posedge clk) begin
    if (state == LOAD) begin
      // Unpack inputs into arrays
      for (i = 0; i < N; i = i + 1) begin
        if (pixel_count + i < total_pixels) begin
          pixel[i]   <= pixel_in[(pixel_count + i)*24 +: 24];
          alpha[i]   <= alpha_in[(pixel_count + i)*8 +: 8];
          bg_pixel[i] <= bg_pixel_in[(pixel_count + i)*24 +: 24];
        end 
        else begin
          pixel[i]   <= 24'd0; // Pad with 0 if out of bounds
          alpha[i]   <= 8'd0;
          bg_pixel[i] <= 24'd0;
        end
      end
    end 
    else if (state == COMPUTE) begin
      for (i = 0; i < N; i = i + 1) begin
        blended[pixel_count + i][23:16] <= (alpha[i] * pixel[i][23:16] + (255 - alpha[i]) * bg_pixel[i][23:16]) / 255;
        blended[pixel_count + i][15:8]  <= (alpha[i] * pixel[i][15:8]  + (255 - alpha[i]) * bg_pixel[i][15:8])  / 255;
        blended[pixel_count + i][7:0]   <= (alpha[i] * pixel[i][7:0]   + (255 - alpha[i]) * bg_pixel[i][7:0])   / 255;
      end
    end
  end

endmodule

input.rtl/apb_dsp_op.sv:
// APB DSP Operation Module
module apb_dsp_op #(
    parameter ADDR_WIDTH = 'd8,
    parameter DATA_WIDTH = 'd32
) (
    input  logic                  clk_dsp,    // Faster clock to DSP operation
    input  logic                  en_clk_dsp, // Enable DSP operation with faster clock
    input  logic                  PCLK,       // APB clock
    input  logic                  PRESETn,    // Active low asynchronous APB Reset
    input  logic [ADDR_WIDTH-1:0] PADDR,      // APB address
    input  logic                  PWRITE,     // Write/Read enable
    input  logic [DATA_WIDTH-1:0] PWDATA,     // Write data
    input  logic                  PSEL,       // DSP selector
    input  logic                  PENABLE,    // APB enable
    output logic [DATA_WIDTH-1:0] PRDATA,     // Read data
    output logic                  PREADY      // Ready signal
);

    // Clock sel logic
    assign dsp_clk_sel = (en_clk_dsp) ? clk_dsp : PCLK;

    // Internal registers address map
    localparam ADDRESS_A         = 32'h0;  // 0x00
    localparam ADDRESS_B         = 32'h4;  // 0x04
    localparam ADDRESS_C         = 32'h8;  // 0x08
    localparam ADDRESS_O         = 32'hC;  // 0x0C
    localparam ADDRESS_CONTROL   = 32'h10; // 0x10
    localparam ADDRESS_WDATA     = 32'h14; // 0x14
    localparam ADDRESS_SRAM_ADDR = 32'h18; // 0x18

    // Control modes
    localparam SRAM_WRITE     = 32'd1;
    localparam SRAM_READ      = 32'd2;
    localparam DSP_READ_OP_A  = 32'd3;
    localparam DSP_READ_OP_B  = 32'd4;
    localparam DSP_READ_OP_C  = 32'd5;
    localparam DSP_WRITE_OP_O = 32'd6;

    // Internal signals
    logic [DATA_WIDTH-1:0] reg_operand_a;
    logic [DATA_WIDTH-1:0] reg_operand_b;
    logic [DATA_WIDTH-1:0] reg_operand_c;
    logic [DATA_WIDTH-1:0] reg_operand_o;
    logic [DATA_WIDTH-1:0] reg_control;
    logic [DATA_WIDTH-1:0] reg_wdata_sram;
    logic [DATA_WIDTH-1:0] reg_addr_sram;

    logic signed [DATA_WIDTH-1:0] wire_op_a;
    logic signed [DATA_WIDTH-1:0] wire_op_b;
    logic signed [DATA_WIDTH-1:0] wire_op_c;
    logic signed [DATA_WIDTH-1:0] wire_op_o;
    logic        [DATA_WIDTH-1:0] sram_data_in;
    logic                         sram_we;
    logic        [DATA_WIDTH-1:0] sram_addr;
    logic        [DATA_WIDTH-1:0] sram_data_out;

    // APB interface logic
    always_ff @(posedge PCLK or negedge PRESETn) begin
        if (!PRESETn) begin
            reg_operand_a  <= 'd0;
            reg_operand_b  <= 'd0;
            reg_operand_c  <= 'd0;
            reg_operand_o  <= 'd0;
            reg_control    <= 'd0;
            reg_wdata_sram <= 'd0;
            reg_addr_sram  <= 'd0;
            PREADY <= 1'b0;
        end else if (PENABLE & PSEL) begin
            PREADY <= 1'b1;
            if (PWRITE) begin
                case (PADDR)
                    ADDRESS_A         : reg_operand_a  <= PWDATA;
                    ADDRESS_B         : reg_operand_b  <= PWDATA;
                    ADDRESS_C         : reg_operand_c  <= PWDATA;
                    ADDRESS_O         : reg_operand_o  <= PWDATA;
                    ADDRESS_CONTROL   : reg_control    <= PWDATA;
                    ADDRESS_WDATA     : reg_wdata_sram <= PWDATA;
                    ADDRESS_SRAM_ADDR : reg_addr_sram  <= PWDATA;
                endcase
            end else begin
                if (reg_control == SRAM_READ) begin
                    PRDATA <= sram_data_out;
                end else begin
                    case (PADDR)
                        ADDRESS_A         : PRDATA <= reg_operand_a;
                        ADDRESS_B         : PRDATA <= reg_operand_b;
                        ADDRESS_C         : PRDATA <= reg_operand_c;
                        ADDRESS_O         : PRDATA <= reg_operand_o;
                        ADDRESS_CONTROL   : PRDATA <= reg_control;
                        ADDRESS_WDATA     : PRDATA <= reg_wdata_sram;
                        ADDRESS_SRAM_ADDR : PRDATA <= reg_addr_sram;
                    endcase
                end               
            end
        end
    end

    // SRAM logic
    logic [DATA_WIDTH-1:0] mem [63:0];

    always_comb begin
        sram_data_in = (reg_control == SRAM_WRITE) ? reg_wdata_sram : wire_op_o;

        if ((reg_control == SRAM_WRITE) || (reg_control == DSP_WRITE_OP_O)) begin
            sram_we = 1'b1;
        end else begin
            sram_we = 1'b0;
        end

        case (reg_control)
            DSP_READ_OP_A  : sram_addr = reg_operand_a;
            DSP_READ_OP_B  : sram_addr = reg_operand_b;
            DSP_READ_OP_C  : sram_addr = reg_operand_c;
            DSP_WRITE_OP_O : sram_addr = reg_operand_o;
            default        : sram_addr = reg_addr_sram;
        endcase
    end

    always_ff @(posedge PCLK) begin
        if (sram_we) begin
            mem[sram_addr] <= sram_data_in;
        end else begin
            sram_data_out <= mem[sram_addr];
        end
    end

    // DSP operation
    always_ff @(posedge dsp_clk_sel) begin
        case (reg_control)
            DSP_READ_OP_A  : wire_op_a <= sram_data_out;
            DSP_READ_OP_B  : wire_op_b <= sram_data_out;
            DSP_READ_OP_C  : wire_op_c <= sram_data_out;
        endcase
    end

    assign wire_op_o = (wire_op_a * wire_op_b) + wire_op_c;

endmodule

output.rtl/apb_dsp_unit.v:
module apb_dsp_unit (
  input  wire         pclk,      // APB clock
  input  wire         presetn,   // Active-low asynchronous reset
  input  wire [9:0]   paddr,     // 10-bit address bus
  input  wire         pselx,     // APB select signal
  input  wire         penable,   // APB enable signal
  input  wire         pwrite,    // Write enable: 1 = write, 0 = read
  input  wire [7:0]   pwdata,    // 8-bit write data bus
  input  wire         sram_valid,// Trigger for SRAM write operation
  output reg          pready,    // APB ready signal (always high)
  output reg [7:0]    prdata,    // 8-bit read data bus
  output reg          pslverr    // Error signal for invalid address/access
);

  //-------------------------------------------------------------------------
  // Internal Configuration Registers
  //-------------------------------------------------------------------------
  // r_operand_1: Holds the memory address of the first operand (10 bits)
  reg [9:0] r_operand_1;
  // r_operand_2: Holds the memory address of the second operand (10 bits)
  reg [9:0] r_operand_2;
  // r_Enable: Mode register (2 bits)
  //   0: DSP disabled
  //   1: Addition mode
  //   2: Multiplication mode
  //   3: Data Writing mode
  reg [1:0] r_Enable;
  // r_write_address: Memory address for data write (10 bits)
  reg [9:0] r_write_address;
  // r_write_data: Data to be written (8 bits)
  reg [7:0] r_write_data;
  // result_reg: Holds the computed result (8 bits), accessible at address 0x5
  reg [7:0] result_reg;

  //-------------------------------------------------------------------------
  // Internal Memory Array (1KB SRAM)
  //-------------------------------------------------------------------------
  // A simple 8-bit wide memory array of 1024 words
  reg [7:0] mem [0:1023];

  //-------------------------------------------------------------------------
  // APB Transaction Handling
  //-------------------------------------------------------------------------
  // This always block handles APB read and write transactions.
  // Only addresses 0x0 to 0x5 (decimal 0 to 5) are valid.
  // paddr is interpreted as:
  //   0x0: r_operand_1
  //   0x1: r_operand_2
  //   0x2: r_Enable
  //   0x3: r_write_address
  //   0x4: r_write_data
  //   0x5: result_reg (read-only)
  // Any access with paddr >= 6 sets pslverr high.
  //-------------------------------------------------------------------------
  always_ff @(posedge pclk or negedge presetn) begin
    if (!presetn) begin
      // Asynchronous reset: initialize all configuration registers and outputs
      r_operand_1         <= 10'd0;
      r_operand_2         <= 10'd0;
      r_Enable            <= 2'd0;
      r_write_address     <= 10'd0;
      r_write_data        <= 8'd0;
      result_reg          <= 8'd0;
      prdata              <= 8'd0;
      pslverr             <= 1'b0;
      pready              <= 1'b0;
    end else begin
      // Default assignments: ready signal always high and no error
      pready  <= 1'b1;
      pslverr <= 1'b0;
      // Only process APB transactions when pselx and penable are asserted.
      if (pselx && penable) begin
        if (pwrite) begin
          // Write operation: update configuration register based on paddr
          case (paddr)
            4'd0: r_operand_1         <= {2'b0, pwdata};  // Extend 8-bit to 10-bit
            4'd1: r_operand_2         <= {2'b0, pwdata};
            4'd2: r_Enable            <= pwdata[1:0];      // Only lower 2 bits used
            4'd3: r_write_address     <= {2'b0, pwdata};
            4'd4: r_write_data        <= pwdata;
            4'd5: ;                   // result_reg is read-only; ignore write
            default: pslverr          <= 1'b1;            // Invalid address
          endcase
        end else begin
          // Read operation: drive prdata based on paddr
          case (paddr)
            4'd0: prdata <= r_operand_1[7:0];
            4'd1: prdata <= r_operand_2[7:0];
            4'd2: prdata <= r_Enable;
            4'd3: prdata <= r_write_address[7:0];
            4'd4: prdata <= r_write_data;
            4'd5: prdata <= result_reg;
            default: pslverr <= 1'b1;                // Invalid address
          endcase
        end
      end
    end
  end

  //-------------------------------------------------------------------------
  // Arithmetic Operation Handling
  //-------------------------------------------------------------------------
  // When r_Enable is set to:
  //   1: Addition mode --> Compute: mem[r_operand_1] + mem[r_operand_2]
  //   2: Multiplication mode --> Compute: mem[r_operand_1] * mem[r_operand_2]
  // The computed result is stored in result_reg (address 0x5).
  //-------------------------------------------------------------------------
  always_ff @(posedge pclk or negedge presetn) begin
    if (!presetn) begin
      result_reg <= 8'd0;
    end else begin
      if (r_Enable == 2'd1 || r_Enable == 2'd2) begin
        if (r_Enable == 2'd1) begin
          // Addition mode
          result_reg <= mem[r_operand_1] + mem[r_operand_2];
        end else begin
          // Multiplication mode
          result_reg <= mem[r_operand_1] * mem[r_operand_2];
        end
      end
      // In other modes (DSP disabled or Data Writing mode), result_reg remains unchanged.
    end
  end

  //-------------------------------------------------------------------------
  // SRAM Write Operation
  //-------------------------------------------------------------------------
  // When r_Enable is 3 (Data Writing mode) and sram_valid is asserted,
  // the value in r_write_data is written to the memory location specified by
  // r_write_address.
  //-------------------------------------------------------------------------
  always_ff @(posedge pclk or negedge presetn) begin
    if (!presetn) begin
      // Optionally, initialize the memory array to 0 on reset.
      integer i;
      for (i = 0; i < 1024; i = i + 1) begin
        mem[i] <= 8'd0;
      end
    end else begin
      if (r_Enable == 2'd3 && sram_valid) begin
        mem[r_write_address] <= r_write_data;
      end
    end
  end

endmodule

output.rtl/cvdp_copilot_apb_gpio.sv:
module compliant with the Advanced Peripheral Bus (APB)
    protocol. Supports a configurable GPIO width, bidirectional operation,
    interrupt generation (both edge- and level-sensitive), and robust input
    synchronization using two-stage flip-flops.

  Register Map:
    Address   Description
    0x00      GPIO Input Data (Read-only): Synchronized state of gpio_in.
    0x04      GPIO Output Data: Controls gpio_out signals.
    0x08      GPIO Output Enable: Configures direction (High = output, Low = input).
    0x0C      GPIO Interrupt Enable: Enables/disables individual GPIO interrupts.
    0x10      GPIO Interrupt Type: 0 = Level Sensitive, 1 = Edge Sensitive.
    0x14      GPIO Interrupt Polarity: 0 = Active High, 1 = Active Low.
    0x18      GPIO Interrupt State (Read-only): Reflects current interrupt status.

  APB Protocol:
    - pclk: Rising edge clock.
    - preset_n: Active-low asynchronous reset (resets all registers/outputs to 0).
    - psel: Peripheral select.
    - paddr[7:2]: APB address bus (valid addresses: 0x00, 0x04, 0x08, 0x0C, 0x10, 0x14, 0x18).
    - penable: Transfer control signal.
    - pwrite: Write control signal (high = write, low = read).
    - pwdata[31:0]: Write data bus.
    - prdata[31:0]: Read data bus (lower 8 bits used for registers; upper bits = 0).
    - pready: Always high.
    - pslverr: Always low.

  GPIO Behavior:
    - gpio_out is driven by the output data register.
    - gpio_enable configures pin direction (High = output, Low = input).
    - gpio_in is synchronized using a two-stage flip-flop (gpio_in_sync, gpio_in_sync2)
      to mitigate metastability.
    - Interrupts are generated based on configuration:
         • Level Sensitive: Active if gpio_in (after sync) matches the configured polarity.
         • Edge Sensitive: Active on rising or falling edge transitions (detected using gpio_prev).

  Note:
    - Undefined APB addresses return prdata = 0.
    - Writes to read-only registers (GPIO Input Data and GPIO Interrupt State) are ignored.
    - All outputs respond within one clock cycle.
*/

module cvdp_copilot_apb_gpio #(parameter GPIO_WIDTH = 8) (
    input  logic           pclk,
    input  logic           preset_n,
    input  logic           psel,
    input  logic [7:0]     paddr,  // Only lower 6 bits used for address decoding.
    input  logic           penable,
    input  logic           pwrite,
    input  logic [31:0]    pwdata,
    input  logic [GPIO_WIDTH-1:0] gpio_in,
    output logic [31:0]    prdata,
    output logic           pready,
    output logic           pslverr,
    output logic [GPIO_WIDTH-1:0] gpio_out,
    output logic [GPIO_WIDTH-1:0] gpio_enable,
    output logic [GPIO_WIDTH-1:0] gpio_int,
    output logic           comb_int
);

  //-------------------------------------------------------------------------
  // Internal Registers and Wires
  //-------------------------------------------------------------------------
  // Read-only registers (lower 8 bits used; upper bits are 0)
  logic [GPIO_WIDTH-1:0] reg_gpio_in;       // Synchronized GPIO input (0x00)
  logic [GPIO_WIDTH-1:0] reg_out;           // Output data register (0x04)
  logic [GPIO_WIDTH-1:0] reg_out_enable;    // Output enable register (0x08)
  logic [GPIO_WIDTH-1:0] reg_int_enable;    // Interrupt enable register (0x0C)
  logic [GPIO_WIDTH-1:0] reg_int_type;      // Interrupt type register (0x10)
  logic [GPIO_WIDTH-1:0] reg_int_polarity;  // Interrupt polarity register (0x14)
  logic [GPIO_WIDTH-1:0] reg_int_state;     // Interrupt state register (0x18; read-only)
  logic [GPIO_WIDTH-1:0] gpio_prev;         // Previous state for edge detection

  // Two-stage synchronization for gpio_in
  logic [GPIO_WIDTH-1:0] gpio_in_sync;
  logic [GPIO_WIDTH-1:0] gpio_in_sync2;

  //-------------------------------------------------------------------------
  // APB Read Data Logic
  //-------------------------------------------------------------------------
  // prdata is assigned based on the decoded address.
  // Only the lower 8 bits of prdata are used; upper bits are zero.
  always_comb begin
    prdata = 32'd0;
    case (paddr[7:2])
      6'd0: begin
        prdata[7:0] = reg_gpio_in;
      end
      6'd4: begin
        prdata[7:0] = reg_out;
      end
      6'd8: begin
        prdata[7:0] = reg_out_enable;
      end
      6'd12: begin
        prdata[7:0] = reg_int_enable;
      end
      6'd16: begin
        prdata[7:0] = reg_int_type;
      end
      6'd20: begin
        prdata[7:0] = reg_int_polarity;
      end
      6'd24: begin
        prdata[7:0] = reg_int_state;
      end
      default: prdata = 32'd0;
    endcase
  end

  //-------------------------------------------------------------------------
  // APB Write and Register Update Logic
  //-------------------------------------------------------------------------
  // All registers and internal states are updated on the rising edge of pclk.
  // An asynchronous reset (preset_n low) sets all registers to 0.
  always_ff @(posedge pclk or negedge preset_n) begin
    if (!preset_n) begin
      // Asynchronous reset: initialize all registers and outputs to 0.
      reg_gpio_in        <= {GPIO_WIDTH{1'b0}};
      reg_out            <= {GPIO_WIDTH{1'b0}};
      reg_out_enable     <= {GPIO_WIDTH{1'b0}};
      reg_int_enable     <= {GPIO_WIDTH{1'b0}};
      reg_int_type       <= {GPIO_WIDTH{1'b0}};
      reg_int_polarity   <= {GPIO_WIDTH{1'b0}};
      reg_int_state      <= {GPIO_WIDTH{1'b0}};
      gpio_prev          <= {GPIO_WIDTH{1'b0}};
    end else begin
      // Two-stage synchronization for gpio_in.
      gpio_in_sync  <= gpio_in;
      gpio_in_sync2 <= gpio_in_sync;
      // Update the read-only GPIO input register.
      reg_gpio_in <= gpio_in_sync2;

      // Update previous state for edge detection.
      gpio_prev <= gpio_in_sync2;

      // Process APB write transactions.
      if (psel && penable) begin
        if (pwrite) begin
          case (paddr[7:2])
            6'd0: begin
              // GPIO Input Data: read-only, ignore write.
            end
            6'd4: begin
              reg_out <= pwdata[7:0];
            end
            6'd8: begin
              reg_out_enable <= pwdata[7:0];
            end
            6'd12: begin
              reg_int_enable <= pwdata[7:0];
            end
            6'd16: begin
              reg_int_type <= pwdata[7:0];
            end
            6'd20: begin
              reg_int_polarity <= pwdata[7:0];
            end
            6'd24: begin
              // GPIO Interrupt State: read-only, ignore write.
            end
            default: ;
          endcase
        end
      end
    end
  end

  //-------------------------------------------------------------------------
  // Interrupt Logic
  //-------------------------------------------------------------------------
  // Compute the interrupt state for each GPIO pin.
  // For level-sensitive mode (reg_int_type = 0), the interrupt is active
  // if gpio_in_sync2 matches the configured polarity.
  // For edge-sensitive mode (reg_int_type = 1), the interrupt is active on
  // a rising edge (if reg_int_polarity = 0) or a falling edge (if reg_int_polarity = 1).
  always_comb begin
    reg_int_state = {GPIO_WIDTH{1'b0}};
    for (int i = 0; i < GPIO_WIDTH; i = i + 1) begin
      if (reg_int_enable[i]) begin
        if (reg_int_type[i] == 1'b0) begin
          // Level Sensitive Mode
          if (reg_int_polarity[i] == 1'b0)
            reg_int_state[i] = gpio_in_sync2[i];
          else
            reg_int_state[i] = ~gpio_in_sync2[i];
        end else begin
          // Edge Sensitive Mode
          if (reg_int_polarity[i] == 1'b0) begin
            // Rising edge: transition from 0 to 1.
            reg_int_state[i] = (gpio_prev[i] == 1'b0 && gpio_in_sync2[i] == 1'b1);
          end else begin
            // Falling edge: transition from 1 to 0.
            reg_int_state[i] = (gpio_prev[i] == 1'b1 && gpio_in_sync2[i] == 1'b0);
          end
        end
      end else begin
        reg_int_state[i] = 1'b0;
      end
    end
  end

  // Drive the individual GPIO interrupt outputs.
  assign gpio_int = reg_int_state;
  // Combined interrupt signal is the logical OR of all individual interrupts.
  assign comb_int = |gpio_int;

  //-------------------------------------------------------------------------
  // Output Assignments
  //-------------------------------------------------------------------------
  // Drive gpio_out with the output data register.
  assign gpio_out = reg_out;
  // Drive gpio_enable with the output enable register.
  assign gpio_enable = reg_out_enable;

  // APB Ready and Error signals.
  assign pready = 1'b1;
  assign pslverr = 1'b0;

endmodule

input.rtl/cvdp_copilot_apb_gpio.sv:
module cvdp_copilot_apb_gpio #(
  parameter GPIO_WIDTH = 8
)(
  // Clock and Reset Signals
  input logic pclk,       // Clock signal
  input logic preset_n,   // Active-low reset signal

  // APB Interface Inputs
  input logic psel,           // Peripheral select
  input logic [7:2] paddr,    // APB address bus (bits [7:2])
  input logic penable,        // Transfer control signal
  input logic pwrite,         // Write control signal
  input logic [31:0] pwdata,  // Write data bus

  // APB Interface Outputs
  output logic [31:0] prdata, // Read data bus
  output logic pready,        // Device ready signal
  output logic pslverr,       // Device error response

  // GPIO Interface Inputs and Outputs
  input logic [GPIO_WIDTH-1:0] gpio_in,     // GPIO input signals
  output logic [GPIO_WIDTH-1:0] gpio_out,   // GPIO output signals
  output logic [GPIO_WIDTH-1:0] gpio_enable, // GPIO output enable signals

  // Interrupt Outputs
  output logic [GPIO_WIDTH-1:0] gpio_int, // Individual interrupt outputs
  output logic comb_int                   // Combined interrupt output
);

  // Signals for Read/Write Controls
  logic read_enable;                     // Read enable signal
  logic write_enable;                    // Write enable signal
  logic write_enable_reg_04;             // Write enable for Data Output register
  logic write_enable_reg_08;             // Write enable for Output Enable register
  logic write_enable_reg_0C;             // Write enable for Interrupt Enable register
  logic write_enable_reg_10;             // Write enable for Interrupt Type register
  logic write_enable_reg_14;             // Write enable for Interrupt Polarity register
  logic write_enable_reg_18;             // Write enable for Interrupt State register
  logic [GPIO_WIDTH-1:0] read_mux;       // Read data multiplexer
  logic [GPIO_WIDTH-1:0] read_mux_d1;    // Registered read data

  // Control Registers
  logic [GPIO_WIDTH-1:0] reg_dout;       // Data Output register
  logic [GPIO_WIDTH-1:0] reg_dout_en;    // Output Enable register
  logic [GPIO_WIDTH-1:0] reg_int_en;     // Interrupt Enable register
  logic [GPIO_WIDTH-1:0] reg_int_type;   // Interrupt Type register
  logic [GPIO_WIDTH-1:0] reg_int_pol;    // Interrupt Polarity register
  logic [GPIO_WIDTH-1:0] reg_int_state;  // Interrupt State register

  // I/O Signal Path and Interrupt Logic
  logic [GPIO_WIDTH-1:0] data_in_sync1;            // First stage of input synchronization
  logic [GPIO_WIDTH-1:0] data_in_sync2;            // Second stage of input synchronization
  logic [GPIO_WIDTH-1:0] data_in_pol_adjusted;     // Polarity-adjusted input data
  logic [GPIO_WIDTH-1:0] data_in_pol_adjusted_dly; // Delayed version of polarity-adjusted input data
  logic [GPIO_WIDTH-1:0] edge_detect;              // Edge detection signals
  logic [GPIO_WIDTH-1:0] raw_int;                  // Raw interrupt signals
  logic [GPIO_WIDTH-1:0] int_masked;               // Masked interrupt signals
  logic [GPIO_WIDTH-1:0] clear_interrupt;          // Clear interrupt signals

  // Read and Write Control Signals
  assign read_enable = psel & (~pwrite); // Read enable
  assign write_enable = psel & (~penable) & pwrite; // Write enable

  // Write Enable Signals for Specific Registers
  assign write_enable_reg_04 = write_enable & (paddr[7:2] == 6'd1); // Address 0x04
  assign write_enable_reg_08 = write_enable & (paddr[7:2] == 6'd2); // Address 0x08
  assign write_enable_reg_0C = write_enable & (paddr[7:2] == 6'd3); // Address 0x0C
  assign write_enable_reg_10 = write_enable & (paddr[7:2] == 6'd4); // Address 0x10
  assign write_enable_reg_14 = write_enable & (paddr[7:2] == 6'd5); // Address 0x14
  assign write_enable_reg_18 = write_enable & (paddr[7:2] == 6'd6); // Address 0x18

  // Write Operations for Control Registers

  // Data Output Register (reg_dout)
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_dout <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_04)
      reg_dout <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Output Enable Register (reg_dout_en)
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_dout_en <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_08)
      reg_dout_en <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Interrupt Enable Register (reg_int_en)
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_en <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_0C)
      reg_int_en <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Interrupt Type Register (reg_int_type)
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_type <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_10)
      reg_int_type <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Interrupt Polarity Register (reg_int_pol)
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_pol <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_14)
      reg_int_pol <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Read Operation: Multiplexing Register Data Based on Address
  always_comb begin
    case (paddr[7:2])
      6'd0: read_mux = data_in_sync2;   // Input Data Register at address 0x00
      6'd1: read_mux = reg_dout;        // Data Output Register at address 0x04
      6'd2: read_mux = reg_dout_en;     // Output Enable Register at address 0x08
      6'd3: read_mux = reg_int_en;      // Interrupt Enable Register at address 0x0C
      6'd4: read_mux = reg_int_type;    // Interrupt Type Register at address 0x10
      6'd5: read_mux = reg_int_pol;     // Interrupt Polarity Register at address 0x14
      6'd6: read_mux = reg_int_state;   // Interrupt State Register at address 0x18
      default: read_mux = {GPIO_WIDTH{1'b0}}; // Default to zeros if address is invalid
    endcase
  end

  // Registering Read Data for Timing Alignment
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      read_mux_d1 <= {GPIO_WIDTH{1'b0}};
    else
      read_mux_d1 <= read_mux;
  end

  // Output Read Data to APB Interface
  assign prdata = (read_enable) ? {{(32-GPIO_WIDTH){1'b0}}, read_mux_d1} : {32{1'b0}};
  assign pready = 1'b1; // Always ready
  assign pslverr = 1'b0; // No error

  // Driving GPIO Outputs and Output Enables
  assign gpio_enable = reg_dout_en; // Output enable signals
  assign gpio_out = reg_dout;       // Output data signals

  // Input Synchronization to Avoid Metastability
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n) begin
      data_in_sync1 <= {GPIO_WIDTH{1'b0}};
      data_in_sync2 <= {GPIO_WIDTH{1'b0}};
    end else begin
      data_in_sync1 <= gpio_in;
      data_in_sync2 <= data_in_sync1;
    end
  end

  // Interrupt Logic

  // Adjusting Input Data Based on Interrupt Polarity
  assign data_in_pol_adjusted = data_in_sync2 ^ reg_int_pol; // Polarity adjustment

  // Registering Polarity-Adjusted Input Data and Delaying for Edge Detection
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n) begin
      data_in_pol_adjusted_dly <= {GPIO_WIDTH{1'b0}};
    end else begin
      data_in_pol_adjusted_dly <= data_in_pol_adjusted;
    end
  end

  // Edge Detection Logic for Interrupts
  assign edge_detect = data_in_pol_adjusted & (~data_in_pol_adjusted_dly); // Rising edge detection

  // Selecting Interrupt Type (Edge or Level-Triggered)
  assign raw_int = (reg_int_type & edge_detect) | (~reg_int_type & data_in_pol_adjusted); // Interrupt source

  // Applying Interrupt Enable Mask
  assign int_masked = raw_int & reg_int_en; // Masked interrupts

  // Clear Interrupt Signals
  assign clear_interrupt = pwdata[GPIO_WIDTH-1:0] & {GPIO_WIDTH{write_enable_reg_18}};

  // Updating Interrupt State Register (Corrected Logic)
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n) begin
      reg_int_state <= {GPIO_WIDTH{1'b0}};
    end else begin
      integer i;
      for (i = 0; i < GPIO_WIDTH; i = i + 1) begin
        if (reg_int_type[i]) begin
          // Edge-triggered interrupt
          if (clear_interrupt[i]) begin
            reg_int_state[i] <= 1'b0;
          end else if (int_masked[i]) begin
            reg_int_state[i] <= 1'b1;
          end
        end else begin
          // Level-triggered interrupt
          reg_int_state[i] <= int_masked[i];
        end
      end
    end
  end

  // Connecting Interrupt Outputs
  assign gpio_int = reg_int_state;     // Individual interrupt outputs
  assign comb_int = |reg_int_state;    // Combined interrupt output

endmodule

output.rtl/cvdp_copilot_apb_gpio.sv:
module cvdp_copilot_apb_gpio #(
  parameter GPIO_WIDTH = 8
)(
  // Clock and Reset Signals
  input  logic pclk,       
  input  logic preset_n,   

  // APB Interface Inputs
  input  logic psel,           
  input  logic [7:2] paddr,    
  input  logic penable,        
  input  logic pwrite,         
  input  logic [31:0] pwdata,  

  // Bidirectional GPIO Port (updated to support input and output)
  inout  logic [GPIO_WIDTH-1:0] gpio,  

  // APB Interface Outputs
  output logic [31:0] prdata,       
  output logic pready,        
  output logic pslverr,       

  // Interrupt Outputs
  output logic [GPIO_WIDTH-1:0] gpio_int,     
  output logic comb_int                  
);

  //-------------------------------------------------------------------------
  // Internal Signal for Bidirectional GPIO Capture
  // Capture the external value when gpio is not driven.
  wire [GPIO_WIDTH-1:0] gpio_buf;
  assign gpio_buf = gpio;

  //-------------------------------------------------------------------------
  // APB Read/Write Control Signals
  logic read_enable;                     
  logic write_enable;                    
  // Write enable signals for existing registers
  logic write_enable_reg_04;             
  logic write_enable_reg_0C;             
  logic write_enable_reg_10;             
  logic write_enable_reg_14;             
  logic write_enable_reg_18;             
  // Write enable signals for new registers
  logic write_enable_reg_1C;             
  logic write_enable_reg_20;             
  logic write_enable_reg_24;             

  //-------------------------------------------------------------------------
  // Control Registers
  logic [GPIO_WIDTH-1:0] reg_dout;       // Data Output register (0x04)
  // Removed reg_dout_en – direction control now replaces output enable.
  logic [GPIO_WIDTH-1:0] reg_dir;        // Direction Control Register (0x1C)
  logic [GPIO_WIDTH-1:0] reg_int_en;     // Interrupt Enable register (0x0C)
  logic [GPIO_WIDTH-1:0] reg_int_type;   // Interrupt Type register (0x10)
  logic [GPIO_WIDTH-1:0] reg_int_pol;    // Interrupt Polarity register (0x14)
  logic [GPIO_WIDTH-1:0] reg_int_state;  // Interrupt State register (0x18)
  // New registers:
  logic [31:0] reg_power;                // Power Management Register (0x20)
  logic [GPIO_WIDTH-1:0] reg_int_reset;  // Interrupt Reset Register (0x24)

  //-------------------------------------------------------------------------
  // I/O Signal Path and Interrupt Logic
  logic [GPIO_WIDTH-1:0] data_in_sync1;            
  logic [GPIO_WIDTH-1:0] data_in_sync2;            
  logic [GPIO_WIDTH-1:0] data_in_pol_adjusted;     
  logic [GPIO_WIDTH-1:0] data_in_pol_adjusted_dly; 
  logic [GPIO_WIDTH-1:0] edge_detect;              
  logic [GPIO_WIDTH-1:0] raw_int;                  
  logic [GPIO_WIDTH-1:0] int_masked;               
  logic [GPIO_WIDTH-1:0] clear_interrupt;          

  //-------------------------------------------------------------------------
  // APB Read/Write Control
  assign read_enable = psel & (~pwrite); // Read enable
  assign write_enable = psel & (~penable) & pwrite; // Write enable

  // Write enable signals based on APB address decoding:
  assign write_enable_reg_04 = write_enable & (paddr[7:2] == 6'd1); // Address 0x04
  assign write_enable_reg_0C = write_enable & (paddr[7:2] == 6'd3); // Address 0x0C
  assign write_enable_reg_10 = write_enable & (paddr[7:2] == 6'd4); // Address 0x10
  assign write_enable_reg_14 = write_enable & (paddr[7:2] == 6'd5); // Address 0x14
  assign write_enable_reg_18 = write_enable & (paddr[7:2] == 6'd6); // Address 0x18
  assign write_enable_reg_1C = write_enable & (paddr[7:2] == 6'd7); // Address

