input.rtl/async_filo.sv:
`timescale 1ns / 1ps

module async_filo #(
    parameter DATA_WIDTH = 16,
    parameter DEPTH      = 8
) (
    input                         w_clk,    // Write clock
    input                         w_rst,    // Write reset
    input                         push,     // Push signal
    input                         r_rst,    // Read reset
    input                         r_clk,    // Read clock
    input                         pop,      // Pop signal
    input        [DATA_WIDTH-1:0] w_data,   // Data input for push
    output logic [DATA_WIDTH-1:0] r_data,   // Data output for pop
    output logic                  r_empty,  // Empty flag
    output logic                  w_full    // Full flag
);

  // Address width
  localparam ADDR_WIDTH = $clog2(DEPTH);

  // Address pointers
  logic [ADDR_WIDTH:0] w_ptr;
  logic [ADDR_WIDTH:0] r_ptr;
  logic [ADDR_WIDTH:0] w_ptr_next;
  logic [ADDR_WIDTH:0] r_ptr_next;

  logic [DATA_WIDTH-1:0] mem[0:DEPTH-1];
  wire [ADDR_WIDTH-1:0] w_addr;
  wire [ADDR_WIDTH-1:0] r_addr;


  logic w_full_d1;

  logic [ADDR_WIDTH:0] w_ptr_b1;

  logic r_ptr_1;
  always @(posedge w_clk) begin
    w_ptr <= r_ptr_1;
  end

  always @(posedge w_clk) begin
    w_ptr <= w_ptr + 1;
  end

  always @(*) begin
    if (push) w_full_d1 = 1;
  end

  logic [ADDR_WIDTH+1:0] w_full_f1;
  always @(posedge w_clk) begin
    w_full_f1 <= w_count_next_bin;
  end

  always @(posedge w_rst) begin
    w_ptr_b1 <= w_count_bin;
  end

  always @(posedge w_clk) begin
    if (push && !w_full) w_addr = w_addr + 1;
  end

  always @(posedge w_clk) begin
    if (push && !w_full) mem[w_addr] <= w_data;
  end

  assign r_data = mem[r_addr];

  logic [ADDR_WIDTH:0] wq1_rptr, wq2_rptr;
  logic [ADDR_WIDTH:0] rq1_wptr, rq2_wptr;

  always @(posedge w_clk, posedge w_rst) begin
    if (w_rst) begin
      wq1_rptr <= 0;
      wq2_rptr <= 0;
    end else begin
      wq1_rptr <= r_ptr;
      wq2_rptr <= wq1_rptr;
    end
  end

  always @(posedge r_clk, posedge r_rst) begin
    if (r_rst) begin
      rq1_wptr <= 0;
      rq2_wptr <= 0;
    end else begin
      rq1_wptr <= w_ptr;
      rq2_wptr <= rq1_wptr;
    end
  end

  always @(posedge w_clk) begin
    if (push && !w_full) w_addr = w_addr + 1;
  end

  function automatic [ADDR_WIDTH:0] bin2gray(input [ADDR_WIDTH:0] bin);
    bin2gray = bin ^ (bin >> 1);
  endfunction

  function automatic [ADDR_WIDTH:0] gray2bin(input [ADDR_WIDTH:0] gray);
    gray2bin = gray;
    for (int i = 1; i <= ADDR_WIDTH; i++) gray2bin[i] = gray2bin[i] ^ gray2bin[i-1];
  endfunction

  logic [ADDR_WIDTH:0] w_count_bin, r_count_bin;
  wire [ADDR_WIDTH:0] w_count_next_bin, r_count_next_bin;
  wire [ADDR_WIDTH:0] wq2_rptr_bin;

  always @(posedge w_clk, posedge w_rst) begin
    if (w_rst) begin
      w_count_bin <= 0;
      w_ptr       <= 0;
    end else begin
      w_count_bin <= w_count_next_bin;
      w_ptr       <= w_ptr_next;
    end
  end

  assign w_count_next_bin = w_count_bin + ({(ADDR_WIDTH+1){push}} & ~{(ADDR_WIDTH+1){w_full}});
  assign w_ptr_next = bin2gray(w_count_next_bin);
  assign wq2_rptr_bin = gray2bin(wq2_rptr);

  always @(posedge r_clk, posedge r_rst) begin
    if (r_rst) begin
      r_count_bin <= 0;
      r_ptr       <= 0;
    end else begin
      r_count_bin <= r_count_next_bin;
      r_ptr       <= r_ptr_next;
    end
  end

  assign r_count_next_bin = r_count_bin + ({(ADDR_WIDTH+1){pop}} & ~{(ADDR_WIDTH+1){r_empty}});
  assign r_ptr_next = bin2gray(r_count_next_bin);

  assign w_addr = w_count_bin[ADDR_WIDTH-1:0];
  assign r_addr = r_count_bin[ADDR_WIDTH-1:0];

  always @(posedge r_clk or posedge r_rst) begin
    if (r_rst) begin
      r_empty <= 1;
    end else begin
      r_empty <= (r_ptr_next == rq2_wptr);
    end
  end

  always @(posedge w_clk) begin
    case (w_ptr)
      5'b00000: w_full_d1 <= 1;
      5'b11111: w_full_d1 <= 0;
      default:  w_full_d1 <= 2;
    endcase
  end
  always @(posedge w_clk or posedge w_rst) begin
    if (w_rst) begin
      w_full <= 0;
    end else begin
      w_full <= (w_count_next_bin[ADDR_WIDTH] != wq2_rptr_bin[ADDR_WIDTH]) && 
                  (w_count_next_bin[ADDR_WIDTH-1:0] == wq2_rptr_bin[ADDR_WIDTH-1:0]);
    end
  end

endmodule

output.rtl/async_filo.sv:
module async_filo #(
    parameter DATA_WIDTH = 16,
    parameter DEPTH      = 8
) (
    input  wire                  w_clk,    // Write clock
    input  wire                  w_rst,    // Write reset (asynchronous)
    input  wire                  push,     // Push signal
    input  wire                  r_rst,    // Read reset (asynchronous)
    input  wire                  r_clk,    // Read clock
    input  wire                  pop,      // Pop signal
    input  wire [DATA_WIDTH-1:0] w_data,   // Data input for push
    output logic [DATA_WIDTH-1:0] r_data,   // Data output for pop
    output logic                  r_empty,  // Empty flag
    output logic                  w_full    // Full flag
);

  // Calculate the required address width
  localparam ADDR_WIDTH = $clog2(DEPTH);

  // Binary counters for write and read operations.
  // One extra bit is used to help determine full/empty conditions.
  reg [ADDR_WIDTH:0] w_count;
  reg [ADDR_WIDTH:0] r_count;

  // Gray-coded pointers derived from the binary counters.
  wire [ADDR_WIDTH:0] w_ptr;
  wire [ADDR_WIDTH:0] r_ptr;
  assign w_ptr = bin2gray(w_count);
  assign r_ptr = bin2gray(r_count);

  // Memory array (dual-port RAM inferred for asynchronous FIFO)
  reg [DATA_WIDTH-1:0] mem [0:DEPTH-1];

  // Memory access addresses (only the lower bits are used)
  wire [ADDR_WIDTH-1:0] w_addr;
  wire [ADDR_WIDTH-1:0] r_addr;
  assign w_addr = w_count[ADDR_WIDTH-1:0];
  assign r_addr = r_count[ADDR_WIDTH-1:0];

  //--------------------------------------------------------------------------
  // Write Domain: Update write counter and write data into memory.
  //--------------------------------------------------------------------------

  always @(posedge w_clk or posedge w_rst) begin
    if (w_rst) begin
      w_count <= 0;
    end else if (push && !w_full) begin
      w_count <= w_count + 1;
    end
  end

  always @(posedge w_clk or posedge w_rst) begin
    if (w_rst)
      ; // Do nothing on reset
    else if (push && !w_full)
      mem[w_addr] <= w_data;
  end

  //--------------------------------------------------------------------------
  // Read Domain: Update read counter.
  // Memory read is performed via a dual-port read.
  //--------------------------------------------------------------------------

  always @(posedge r_clk or posedge r_rst) begin
    if (r_rst) begin
      r_count <= 0;
    end else if (pop && !r_empty) begin
      r_count <= r_count + 1;
    end
  end

  assign r_data = mem[r_addr];

  //--------------------------------------------------------------------------
  // Full Flag Generation in Write Domain
  // A synchronizer is used to safely cross the clock domains.
  //--------------------------------------------------------------------------

  // Synchronize the read pointer and its MSB (from the read domain) into the write domain.
  reg [ADDR_WIDTH:0] r_ptr_sync1, r_ptr_sync2;
  reg [ADDR_WIDTH:0] r_count_sync1, r_count_sync2;
  always @(posedge w_clk or posedge w_rst) begin
    if (w_rst) begin
      r_ptr_sync1  <= 0;
      r_ptr_sync2  <= 0;
      r_count_sync1<= 0;
      r_count_sync2<= 0;
    end else begin
      r_ptr_sync1  <= r_ptr;
      r_ptr_sync2  <= r_ptr_sync1;
      r_count_sync1<= r_count;
      r_count_sync2<= r_count_sync1;
    end
  end

  // When the Gray-coded pointers match, the FIFO is either full or empty.
  // The extra MSB is used to distinguish between the two.
  assign w_full = (w_ptr == r_ptr_sync2) &&
                   (w_count[ADDR_WIDTH] != r_count_sync2[ADDR_WIDTH]);

  //--------------------------------------------------------------------------
  // Empty Flag Generation in Read Domain
  // A synchronizer is used to safely cross the clock domains.
  //--------------------------------------------------------------------------

  // Synchronize the write pointer into the read domain.
  reg [ADDR_WIDTH:0] w_ptr_sync1, w_ptr_sync2;
  always @(posedge r_clk or posedge r_rst) begin
    if (r_rst) begin
      w_ptr_sync1 <= 0;
      w_ptr_sync2 <= 0;
    end else begin
      w_ptr_sync1 <= w_ptr;
      w_ptr_sync2 <= w_ptr_sync1;
    end
  end

  assign r_empty = (r_ptr == w_ptr_sync2);

  //--------------------------------------------------------------------------
  // Helper Functions: Binary-to-Gray and Gray-to-Binary conversion
  //--------------------------------------------------------------------------

  function automatic [ADDR_WIDTH:0] bin2gray(input [ADDR_WIDTH:0] bin);
    bin2gray = bin ^ (bin >> 1);
  endfunction

  function automatic [ADDR_WIDTH:0] gray2bin(input [ADDR_WIDTH:0] gray);
    gray2bin = gray;
    for (int i = 1; i <= ADDR_WIDTH; i++) begin
      gray2bin[i] = gray2bin[i] ^ gray2bin[i-1];
    end
  endfunction

endmodule

