module signed_unsigned_comparator #(parameter WIDTH = 5)(
    input  logic [WIDTH-1:0] i_A,
    input  logic [WIDTH-1:0] i_B,
    input  logic             i_enable,
    input  logic             i_mode,      // High = signed mode, Low = magnitude mode
    output logic             o_greater,   // High when i_A > i_B
    output logic             o_less,      // High when i_A < i_B
    output logic             o_equal      // High when i_A == i_B
);

    always_comb begin
        // When disabled, all outputs are low.
        if (!i_enable) begin
            o_greater = 1'b0;
            o_less    = 1'b0;
            o_equal   = 1'b0;
        end else begin
            if (i_mode) begin
                // Signed mode: interpret inputs as signed integers.
                if ($signed(i_A) > $signed(i_B)) begin
                    o_greater = 1'b1;
                    o_less    = 1'b0;
                    o_equal   = 1'b0;
                end else if ($signed(i_A) < $signed(i_B)) begin
                    o_greater = 1'b0;
                    o_less    = 1'b1;
                    o_equal   = 1'b0;
                end else begin
                    o_greater = 1'b0;
                    o_less    = 1'b0;
                    o_equal   = 1'b1;
                end
            end else begin
                // Magnitude mode: treat inputs as unsigned.
                if (i_A > i_B) begin
                    o_greater = 1'b1;
                    o_less    = 1'b0;
                    o_equal   = 1'b0;
                end else if (i_A < i_B) begin
                    o_greater = 1'b0;
                    o_less    = 1'b1;
                    o_equal   = 1'b0;
                end else begin
                    o_greater = 1'b0;
                    o_less    = 1'b0;
                    o_equal   = 1'b1;
                end
            end
        end
    end

endmodule

output.rtl/complex_multiplier.sv:
module complex_multiplier (
    input  logic         clk,
    input  logic         arst_n,
    input  logic [15:0]  a_real,
    input  logic [15:0]  a_imag,
    input  logic [15:0]  b_real,
    input  logic [15:0]  b_imag,
    output logic [31:0]  result_real,
    output logic [31:0]  result_imag
);

    // One-cycle latency: compute and register the result on the next clock cycle.
    always_ff @(posedge clk or negedge arst_n) begin
        if (!arst_n) begin
            result_real <= 32'b0;
            result_imag <= 32'b0;
        end else begin
            // Compute the real part: (a_real * b_real) - (a_imag * b_imag)
            result_real <= (a_real * b_real) - (a_imag * b_imag);
            // Compute the imaginary part: (a_real * b_imag) + (a_imag * b_real)
            result_imag <= (a_real * b_imag) + (a_imag * b_real);
        end
    end

endmodule

output.rtl/compression_engine.sv:
module compression_engine (
  input   logic        clk,
  input   logic        reset,
  input   logic [23:0] num_i,
  output  logic [11:0] mantissa_o,
  output  logic [3:0]  exponent_o
);

  // --------------------------------------------------------
  // Internal wires and registers
  // --------------------------------------------------------
  logic [23:12] exp_oh;         // One-hot encoded exponent (for bits 23 downto 12)
  logic [3:0]   exp_bin;        // Binary exponent (index within the one-hot vector)
  logic [3:0]   exponent;       // Adjusted exponent output
  logic [11:0]  mantissa;       // Mantissa output

  // --------------------------------------------------------
  // One-Hot Encoding of the Exponent
  // --------------------------------------------------------
  // For each bit i (from 22 downto 12), generate:
  //   exp_oh[i] = num_i[i] & ~(|num_i[23:i+1])
  genvar i;
  generate
    for (i = 22; i >= 12; i = i - 1) begin : onehot_gen
      assign exp_oh[i] = num_i[i] & ~(|num_i[23:i+1]);
    end
  endgenerate

  // Highest bit is assigned separately
  assign exp_oh[23] = num_i[23];

  // --------------------------------------------------------
  // One-Hot to Binary Conversion
  // --------------------------------------------------------
  // The onehot_to_bin module converts the one-hot vector into the zero-based index.
  onehot_to_bin #(
    .ONE_HOT_W(12),
    .BIN_W(4)
  ) exp_oh_bin (
    .oh_vec_i(exp_oh),
    .bin_vec_o(exp_bin)
  );

  // Adjust the exponent: if any one-hot bit is detected, add 1; otherwise, exponent remains 0.
  assign exponent = (|exp_oh) ? exp_bin + 4'h1 : exp_bin;

  // --------------------------------------------------------
  // Mantissa Extraction Logic
  // --------------------------------------------------------
  // If the input vector is zero, output mantissa = 0.
  // If exponent is 0, the most significant set bit is in the lower 12 bits so:
  //   mantissa = num_i[11:0]
  // Otherwise, extract the most significant 12 bits starting from the bit (exponent - 1).
  assign mantissa = (num_i == 24'd0) ? 12'd0 :
                    (exponent == 4'd0) ? num_i[11:0] :
                    num_i[(exponent - 1) +: 12];

  // --------------------------------------------------------
  // Output Registering
  // --------------------------------------------------------
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      exponent_o <= 4'd0;
      mantissa_o <= 12'd0;
    end else begin
      exponent_o <= exponent;
      mantissa_o <= mantissa;
    end
  end

endmodule

// ------------------------------------------------------------
// onehot_to_bin Module
// ------------------------------------------------------------
module onehot_to_bin #(
  parameter ONE_HOT_W = 32,  // Width of the one-hot input
  parameter BIN_W     = 5    // Width of the binary output
)(
  input   wire [ONE_HOT_W-1:0]  oh_vec_i,  // One-hot encoded input
  output  logic [BIN_W-1:0]     bin_vec_o  // Binary encoded output
);

  integer i;
  // Convert the one-hot vector to a binary index.
  // Iterate over the one-hot vector and output the index of the set bit.
  always_comb begin
    bin_vec_o = 0;
    for (i = 0; i < ONE_HOT_W; i = i + 1) begin
      if (oh_vec_i[i])
        bin_vec_o = i;
    end
  end

endmodule

output.rtl/enhanced_fsm_signal_processor.v:
module enhanced_fsm_signal_processor (
    input  wire         i_clk,
    input  wire         i_rst_n,
    input  wire         i_enable,
    input  wire         i_clear,
    input  wire         i_ack,
    input  wire         i_fault,
    input  wire [4:0]   i_vector_1,
    input  wire [4:0]   i_vector_2,
    input  wire [4:0]   i_vector_3,
    input  wire [4:0]   i_vector_4,
    input  wire [4:0]   i_vector_5,
    input  wire [4:0]   i_vector_6,
    output reg          o_ready,
    output reg          o_error,
    output reg [1:0]    o_fsm_status,
    output reg [7:0]    o_vector_1,
    output reg [7:0]    o_vector_2,
    output reg [7:0]    o_vector_3,
    output reg [7:0]    o_vector_4
);

  // State encoding
  localparam IDLE   = 2'b00;
  localparam PROCESS = 2'b01;
  localparam READY   = 2'b10;
  localparam FAULT   = 2'b11;

  reg [1:0] state, next_state;

  // Concatenate six 5-bit vectors and append two 1's at the LSB to form a 32-bit bus.
  // The order is: MSB: i_vector_1, then i_vector_2, ..., then i_vector_6, and finally 2'b11.
  wire [31:0] bus32;
  assign bus32 = { i_vector_1, i_vector_2, i_vector_3, i_vector_4, i_vector_5, i_vector_6, 2'b11 };

  // Next state combinational logic.
  // Note: i_fault takes precedence over any other input.
  always @(*) begin
    if (i_fault)
      next_state = FAULT;
    else
      case (state)
        IDLE: begin
          if (i_enable)
            next_state = PROCESS;
          else
            next_state = IDLE;
        end
        PROCESS: begin
          next_state = READY;
        end
        READY: begin
          if (i_ack)
            next_state = IDLE;
          else
            next_state = READY;
        end
        FAULT: begin
          if (i_clear && !i_fault)
            next_state = IDLE;
          else
            next_state = FAULT;
        end
        default: next_state = IDLE;
      endcase
  end

  // Sequential always block: state register update and output assignments.
  // All outputs and state transitions are synchronous to i_clk.
  always @(posedge i_clk or negedge i_rst_n) begin
    if (!i_rst_n) begin
      state          <= IDLE;
      o_ready        <= 1'b0;
      o_error        <= 1'b0;
      o_fsm_status   <= IDLE;
      o_vector_1     <= 8'b0;
      o_vector_2     <= 8'b0;
      o_vector_3     <= 8'b0;
      o_vector_4     <= 8'b0;
    end
    else begin
      // If i_clear is asserted, clear outputs.
      if (i_clear) begin
        o_ready        <= 1'b0;
        o_error        <= 1'b0;
        o_vector_1     <= 8'b0;
        o_vector_2     <= 8'b0;
        o_vector_3     <= 8'b0;
        o_vector_4     <= 8'b0;
      end
      else begin
        case (state)
          IDLE: begin
            o_ready        <= 1'b0;
            o_error        <= 1'b0;
            o_fsm_status   <= IDLE;
            o_vector_1     <= 8'b0;
            o_vector_2     <= 8'b0;
            o_vector_3     <= 8'b0;
            o_vector_4     <= 8'b0;
          end
          PROCESS: begin
            // In PROCESS state, form the 32-bit bus and split it into four 8-bit outputs.
            o_vector_1     <= bus32[31:24];
            o_vector_2     <= bus32[23:16];
            o_vector_3     <= bus32[15:8];
            o_vector_4     <= bus32[7:0];
            o_ready        <= 1'b0;
            o_error        <= 1'b0;
            o_fsm_status   <= PROCESS;
          end
          READY: begin
            // In READY state, indicate that processing is complete.
            o_ready        <= 1'b1;
            o_error        <= 1'b0;
            o_fsm_status   <= READY;
            // Outputs remain valid as produced in PROCESS.
          end
          FAULT: begin
            // In FAULT state, assert error and clear outputs.
            o_ready        <= 1'b0;
            o_error        <= 1'b1;
            o_fsm_status   <= FAULT;
            o_vector_1     <= 8'b0;
            o_vector_2     <= 8'b0;
            o_vector_3     <= 8'b0;
            o_vector_4     <= 8'b0;
          end
          default: begin
            o_ready        <= 1'b0;
            o_error        <= 1'b0;
            o_fsm_status   <= IDLE;
            o_vector_1     <= 8'b0;
            o_vector_2     <= 8'b0;
            o_vector_3     <= 8'b0;
            o_vector_4     <= 8'b0;
          end
        endcase
      end
      state <= next_state;
    end
  end

endmodule

output.rtl/low_pass_filter.sv:
module low_pass_filter #(
  parameter integer DATA_WIDTH = 16,       // Bit-width of the input data
  parameter integer COEFF_WIDTH = 16,      // Bit-width of the filter coefficients
  parameter integer NUM_TAPS = 8           // Number of filter taps
) (
  input  logic                        clk,
  input  logic                        reset,
  input  logic [DATA_WIDTH*NUM_TAPS-1:0] data_in,  // Packed input data: NUM_TAPS samples
  input  logic                        valid_in,
  input  logic [COEFF_WIDTH*NUM_TAPS-1:0] coeffs, // Packed coefficients: NUM_TAPS coefficients
  output logic [NBW_MULT + $clog2(NUM_TAPS)-1:0] data_out, // Filtered output data
  output logic                        valid_out
);

  // Derived parameters
  localparam integer NBW_MULT    = DATA_WIDTH + COEFF_WIDTH;  // Intermediate multiplication width
  localparam integer TAPS_LOG2   = $clog2(NUM_TAPS);           // Bits needed for tap count in summation
  localparam integer OUTPUT_WIDTH = NBW_MULT + TAPS_LOG2;      // Final output width

  //-------------------------------------------------------------------------
  // Internal registers for input data and coefficients
  //-------------------------------------------------------------------------
  // Registered data samples (each NUM_TAPS sample stored as a signed value)
  logic signed [DATA_WIDTH-1:0] data_reg [0:NUM_TAPS-1];
  // Registered coefficients (each NUM_TAPS coefficient stored as a signed value)
  logic signed [COEFF_WIDTH-1:0] coeff_reg [0:NUM_TAPS-1];

  //-------------------------------------------------------------------------
  // Combinational logic: Element-wise multiplication and summation
  //-------------------------------------------------------------------------
  // Each product is computed with width NBW_MULT bits.
  logic signed [NBW_MULT-1:0] product [0:NUM_TAPS-1];
  // Summation result computed as a combinational sum of all products.
  // The output width is OUTPUT_WIDTH to account for the sum of NUM_TAPS terms.
  logic signed [OUTPUT_WIDTH-1:0] sum_comb;

  //-------------------------------------------------------------------------
  // Registers for the computed sum and valid signal (1-cycle latency)
  //-------------------------------------------------------------------------
  logic signed [OUTPUT_WIDTH-1:0] sum_reg;
  logic valid_reg;

  //-------------------------------------------------------------------------
  // Registering input data and coefficients when valid_in is high.
  // If reset is asserted, all internal registers are cleared to zero.
  //-------------------------------------------------------------------------
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      for (int i = 0; i < NUM_TAPS; i = i + 1) begin
        data_reg[i] <= '0;
        coeff_reg[i] <= '0;
      end
      valid_reg <= 1'b0;
    end else if (valid_in) begin
      for (int i = 0; i < NUM_TAPS; i = i + 1) begin
        // Unpack each tap from the packed bus using the "-:" operator.
        data_reg[i] <= data_in[(i+1)*DATA_WIDTH-1 -: DATA_WIDTH];
        coeff_reg[i] <= coeffs[(i+1)*COEFF_WIDTH-1 -: COEFF_WIDTH];
      end
      valid_reg <= valid_in; // Propagate validity with one-cycle latency
    end
  end

  //-------------------------------------------------------------------------
  // Combinational block for performing element-wise multiplication and summation.
  // Note: The coefficients are applied in reverse order relative to the data.
  //-------------------------------------------------------------------------
  always_comb begin
    sum_comb = '0;
    for (int i = 0; i < NUM_TAPS; i = i + 1) begin
      // Multiply data_reg[i] with the coefficient in reverse order:
      // i.e., first data sample with last coefficient, etc.
      product[i] = data_reg[i] * coeff_reg[NUM_TAPS-1-i];
      sum_comb = sum_comb + product[i];
    end
  end

  //-------------------------------------------------------------------------
  // Register the computed sum to introduce a one-cycle latency.
  // The valid_out signal is also registered here.
  //-------------------------------------------------------------------------
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      sum_reg <= '0;
      valid_reg <= 1'b0;
    end else begin
      sum_reg <= sum_comb;
      valid_reg <= valid_in;
    end
  end

  //-------------------------------------------------------------------------
  // Output assignments
  //-------------------------------------------------------------------------
  assign data_out = sum_reg;
  assign valid_out = valid_reg;

endmodule

output.rtl/decimator_and_peak_detector.sv:
module advanced_decimator_with_adaptive_peak_detection #(
  parameter int N           = 8,
  parameter int DATA_WIDTH  = 16,
  parameter int DEC_FACTOR  = 4
)(
  input  logic                   clk,
  input  logic                   reset,
  input  logic                   valid_in,
  input  logic [DATA_WIDTH*N-1:0] data_in,
  output logic                   valid_out,
  output logic [DATA_WIDTH*(N/DEC_FACTOR)-1:0] data_out,
  output logic [DATA_WIDTH-1:0]  peak_value
);

  // Ensure that DEC_FACTOR divides N. Uncomment the following static assertion if your tool supports it.
  // static_assert((N % DEC_FACTOR) == 0, "DEC_FACTOR must be a divisor of N");

  // Register to hold the unpacked input samples.
  logic signed [DATA_WIDTH-1:0] samples_reg [0:N-1];
  // Register to hold the valid signal.
  logic valid_reg;

  // Register the input samples and valid signal on the rising edge of clk.
  // When reset is active, clear the registers.
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      valid_reg <= 1'b0;
      for (int i = 0; i < N; i++) begin
        samples_reg[i] <= '0;
      end
    end
    else if (valid_in) begin
      valid_reg <= 1'b1;
      // Unpack the packed data_in into individual samples.
      for (int i = 0; i < N; i++) begin
        samples_reg[i] <= data_in[((i+1)*DATA_WIDTH)-1 -: DATA_WIDTH];
      end
    end
  end

  // Combinational logic to generate the decimated output and peak detection.
  always_comb begin
    // Propagate the registered valid signal.
    valid_out = valid_reg;

    // Pack the decimated samples into data_out.
    // For each decimated sample, select samples_reg[i*DEC_FACTOR].
    for (int i = 0; i < N/DEC_FACTOR; i++) begin
      data_out[((i+1)*DATA_WIDTH)-1 -: DATA_WIDTH] = samples_reg[i*DEC_FACTOR];
    end

    // Peak detection: find the maximum value among the decimated samples.
    // Initialize peak_value with the first decimated sample.
    peak_value = samples_reg[0];
    for (int i = 1; i < N/DEC_FACTOR; i++) begin
      if (samples_reg[i*DEC_FACTOR] > peak_value)
        peak_value = samples_reg[i*DEC_FACTOR];
    end
  end

endmodule

