    endcase
  end

  // Outputs
  assign s_valid_o = (state_q == ST_TX);

  // LSB-first => s_data_o = shift_reg_q[0]
  // MSB-first => s_data_o = shift_reg_q[SHIFT_W-1]
  assign s_data_o  = (BIT_ORDER == 0) ? shift_reg_q[0] : shift_reg_q[SHIFT_W-1];

  assign p_ready_o = (state_q == ST_RX);

endmodule

output.rtl/data_width_converter.sv:
module data_width_converter (
    input  logic         clk,
    input  logic         reset,
    input  logic [31:0]  data_in,
    input  logic         data_valid,
    output logic [127:0] o_data_out,
    output logic         o_data_out_valid
);

    // Internal counter to track number of valid inputs received (0 to 3)
    logic [1:0] counter;
    // Buffer to accumulate the four 32-bit inputs into a 128-bit word
    logic [127:0] data_buffer;

    // Sequential process: operates on the positive edge of clk with asynchronous reset
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            counter         <= 2'd0;
            data_buffer     <= 128'd0;
            o_data_out_valid<= 1'b0;
            o_data_out      <= 128'd0;
        end
        else begin
            if (data_valid) begin
                if (counter < 2'd3) begin
                    // Shift in the new 32-bit data sample into the lower 32 bits of data_buffer
                    data_buffer <= {data_buffer[95:0], data_in};
                    counter     <= counter + 1;
                end
                else begin
                    // Fourth valid input received: concatenate and generate output
                    data_buffer     <= {data_buffer[95:0], data_in};
                    o_data_out      <= data_buffer;
                    o_data_out_valid<= 1'b1;
                    // Reset internal state for next aggregation cycle
                    counter         <= 2'd0;
                    data_buffer     <= 128'd0;
                end
            end
            else begin
                // Ensure that output valid is de-asserted when no new valid input is received
                o_data_out_valid<= 1'b0;
            end
        end
    end

endmodule

output.rtl/dbi_enc.sv:
module that inverts data groups based on the number
 * of bit differences with the previous data.
 *
 * The 40-bit input data is split into two 20-bit groups:
 *   - Group-1: data_in[39:20]
 *   - Group-0: data_in[19:0]
 *
 * For each group, the number of bit differences compared to the previous cycle's
 * corresponding group (stored in prev_data) is counted. If more than 10 bits differ,
 * the corresponding control bit is set (1), and the data is inverted; otherwise, it
 * remains unchanged.
 *
 * On reset (rst_n low), all outputs and the stored previous data are reset to 0.
 */

module dbi_enc (
    input  logic         clk,
    input  logic         rst_n,
    input  logic [39:0]  data_in,
    output logic [39:0]  data_out,
    output logic [1:0]   dbi_cntrl
);

    // Register to store previous data_out for comparison
    logic [39:0] prev_data;

    // Internal signals for the two 20-bit groups
    logic [19:0] group1, group0;
    logic [19:0] out_group1, out_group0;

    // Counters for bit differences (max value 20, so 5 bits are sufficient)
    logic [4:0] diff1_count, diff0_count;

    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            // Asynchronous reset: clear all registers
            prev_data      <= 40'b0;
            data_out       <= 40'b0;
            dbi_cntrl      <= 2'b00;
        end else begin
            // Split the 40-bit input into two 20-bit groups
            group1 = data_in[39:20];
            group0 = data_in[19:0];

            // Initialize difference counters
            diff1_count = 5'b0;
            diff0_count = 5'b0;

            // Count the number of bit differences between current groups and previous data
            for (int i = 0; i < 20; i++) begin
                diff1_count += (group1[i] !== prev_data[39:20][i]);
                diff0_count += (group0[i] !== prev_data[19:0][i]);
            end

            // Determine output groups: invert if more than 10 bits differ
            out_group1 = (diff1_count > 5'd10) ? ~group1 : group1;
            out_group0 = (diff0_count > 5'd10) ? ~group0 : group0;

            // Combine groups to form data_out
            data_out  <= {out_group1, out_group0};

            // Set control bits: bit1 for group1, bit0 for group0
            dbi_cntrl <= { (diff1_count > 5'd10), (diff0_count > 5'd10) };

            // Update previous data with current data_out for next cycle comparison
            prev_data <= data_out;
        end
    end

endmodule

output.rtl/dbi_dec.sv:
module dbi_dec (
   // Inputs
   input  wire        rst_n,     // Asynchronous reset
   input  wire        clk,       // Clock
   input  wire [39:0] data_in,   // Data input before DBI decoder logic
   input  wire [1:0]  dbi_cntrl, // Indicate data inversion enabled for each group 
   // Outputs
   output wire [39:0] data_out   // Output data after DBI logic
);

   // Register to hold the decoded data
   reg [39:0] data_reg;

   // Connect the register output to the module output
   assign data_out = data_reg;

   // Asynchronous reset and synchronous data processing
   always @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         data_reg <= 40'h00000000;
      end else begin
         // Split data_in into two 20-bit groups:
         // Group-1: bits [39:20] (MSBs)
         // Group-0: bits [19:0]  (LSBs)
         // Decode each group based on the corresponding control bit.
         // For Group-1, use dbi_cntrl[1]. For Group-0, use dbi_cntrl[0].
         data_reg <= { (dbi_cntrl[1] ? ~data_in[39:20] : data_in[39:20]),
                       (dbi_cntrl[0] ? ~data_in[19:0]  : data_in[19:0]) };
      end
   end

endmodule

output.rtl/cvdp_copilot_decode_firstbit.sv:
module implements a first‐bit decoder that, given an input data vector (In_Data)
//   of configurable width (InWidth_g), finds the index of the lowest set bit. The design
//   pads the input to the next power‐of‐two width, computes the first set bit in a
//   combinational function, and then passes the result through a configurable number of
//   pipeline stages (PlRegs_g). Input and output registers are optionally added based on
//   InReg_g and OutReg_g. The valid signal (Out_Valid) is generated only when a new valid
//   input is processed and the result passes through all pipeline stages.
//
//   On reset (Rst = 1), all pipeline and output registers are cleared.
//
// Parameters:
//   InWidth_g : Width of the input data vector (default 32)
//   InReg_g   : Enable input register (default 1)
//   OutReg_g  : Enable output register (default 1)
//   PlRegs_g  : Number of pipeline registers for the decoding logic (default 1)
//
// Note:
//   The module pads the input vector to PadWidth = 2^(clog2(InWidth_g)) bits.
//   The output index (Out_FirstBit) is represented using BinBits_c = clog2(InWidth_g) bits.
//   If no bit is set in the input data, then Out_Found is deasserted (0) and Out_FirstBit is 0.
//
module cvdp_copilot_decode_firstbit
  #(parameter InWidth_g = 32,
    parameter InReg_g   = 1,
    parameter OutReg_g  = 1,
    parameter PlRegs_g  = 1)
  (input  logic                    Clk,
   input  logic                    Rst,
   input  logic [InWidth_g-1:0]     In_Data,
   input  logic                    In_Valid,
   output logic [clog2(InWidth_g)-1:0] Out_FirstBit,
   output logic                    Out_Found,
   output logic                    Out_Valid);

   // Compute the number of bits required to encode the index.
   localparam int BinBits_c = $clog2(InWidth_g);
   // Pad the input to the next power-of-two width.
   localparam int PadWidth = (1 << BinBits_c);

   //-------------------------------------------------------------------------
   // Input Register Stage (if enabled)
   //-------------------------------------------------------------------------
   logic [InWidth_g-1:0] in_data_reg;
   logic                 in_valid_reg;
   always_ff @(posedge Clk or posedge Rst) begin
      if (Rst) begin
         in_data_reg  <= '0;
         in_valid_reg <= 1'b0;
      end
      else begin
         in_data_reg  <= In_Data;
         in_valid_reg <= In_Valid;
      end
   end

   //-------------------------------------------------------------------------
   // Compute Padded Data
   //-------------------------------------------------------------------------
   // Pad the input vector with zeros on the MSB side so that its width equals PadWidth.
   logic [PadWidth-1:0] data_padded;
   assign data_padded = { {(PadWidth - InWidth_g){1'b0}}, in_data_reg };

   //-------------------------------------------------------------------------
   // Function: find_first_set
   // Returns the index (0-indexed) of the first '1' bit in the input vector.
   //-------------------------------------------------------------------------
   function automatic [BinBits_c-1:0] find_first_set(input logic [PadWidth-1:0] data);
      integer i;
      begin
         find_first_set = '0;
         for (i = 0; i < PadWidth; i = i + 1) begin
            if (data[i] == 1'b1) begin
               find_first_set = i;
               return;
            end
         end
      end
   endfunction

   //-------------------------------------------------------------------------
   // Combinational Decoding Logic
   //-------------------------------------------------------------------------
   // found_comb is high if any bit in data_padded is set.
   // first_bit_comb holds the index of the first set bit (or 0 if none found).
   // valid_comb asserts only if the input was valid and a set bit was detected.
   logic [BinBits_c-1:0] first_bit_comb;
   logic                  found_comb;
   logic                  valid_comb;
   assign found_comb    = |data_padded;
   assign first_bit_comb = find_first_set(data_padded);
   assign valid_comb    = in_valid_reg & found_comb;

   //-------------------------------------------------------------------------
   // Pipeline Registers for Decoding Logic
   //-------------------------------------------------------------------------
   generate
      if (PlRegs_g > 0) begin : pipeline
         // Declare pipeline register arrays.
         genvar i;
         logic [BinBits_c-1:0] pipe_first [0:PlRegs_g-1];
         logic                 pipe_found [0:PlRegs_g-1];
         logic                 pipe_valid [0:PlRegs_g-1];

         // Pipeline register update: if a valid input is present, update stage 0 with
         // the combinational result and shift the registers; otherwise, flush the registers.
         always_ff @(posedge Clk or posedge Rst) begin
            if (Rst) begin
               for (i = 0; i < PlRegs_g; i = i + 1) begin
                  pipe_first[i]  <= '0;
                  pipe_found[i]  <= 1'b0;
                  pipe_valid[i]  <= 1'b0;
               end
            end
            else begin
               if (in_valid_reg) begin
                  pipe_first[0]  <= first_bit_comb;
                  pipe_found[0]  <= found_comb;
                  pipe_valid[0]  <= valid_comb;
                  // Shift the pipeline registers.
                  for (i = PlRegs_g-1; i > 0; i = i - 1) begin
                     pipe_first[i]  <= pipe_first[i-1];
                     pipe_found[i]  <= pipe_found[i-1];
                     pipe_valid[i]  <= pipe_valid[i-1];
                  end
               end
               else begin
                  // Flush pipeline registers when input is not valid.
                  pipe_first[0]  <= '0;
                  pipe_found[0]  <= 1'b0;
                  pipe_valid[0]  <= 1'b0;
                  for (i = PlRegs_g-1; i > 0; i = i - 1) begin
                     pipe_first[i]  <= pipe_first[i-1];
                     pipe_found[i]  <= pipe_found[i-1];
                     pipe_valid[i]  <= pipe_valid[i-1];
                  end
               end
            end
         end

         //-------------------------------------------------------------------------
         // Output Register Stage (if enabled)
         //-------------------------------------------------------------------------
         logic [BinBits_c-1:0] out_reg_first;
         logic                  out_reg_found;
         logic                  out_reg_valid;
         always_ff @(posedge Clk or posedge Rst) begin
            if (Rst) begin
               out_reg_first  <= '0;
               out_reg_found  <= 1'b0;
               out_reg_valid  <= 1'b0;
            end
            else if (OutReg_g) begin
               out_reg_first  <= pipe_first[PlRegs_g-1];
               out_reg_found  <= pipe_found[PlRegs_g-1];
               out_reg_valid  <= pipe_valid[PlRegs_g-1];
            end
         end

         // Drive module outputs.
         assign Out_FirstBit = OutReg_g ? out_reg_first : pipe_first[PlRegs_g-1];
         assign Out_Found    = OutReg_g ? out_reg_found : pipe_found[PlRegs_g-1];
         assign Out_Valid    = OutReg_g ? out_reg_valid : pipe_valid[PlRegs_g-1];

      end
      else begin : no_pipeline
         // No pipeline registers: use the combinational result directly.
         // Optionally register the output if OutReg_g is enabled.
         logic [BinBits_c-1:0] out_reg_first;
         logic                  out_reg_found;
         logic                  out_reg_valid;
         always_ff @(posedge Clk or posedge Rst) begin
            if (Rst) begin
               out_reg_first  <= '0;
               out_reg_found  <= 1'b0;
               out_reg_valid  <= 1'b0;
            end
            else if (OutReg_g) begin
               out_reg_first  <= first_bit_comb;
               out_reg_found  <= found_comb;
               out_reg_valid  <= valid_comb;
            end
         end

         assign Out_FirstBit = OutReg_g ? out_reg_first : first_bit_comb;
         assign Out_Found    = OutReg_g ? out_reg_found : found_comb;
         assign Out_Valid    = OutReg_g ? out_reg_valid : valid_comb;
      end
   endgenerate

endmodule

output.rtl/decoder_8b10b.sv:
module decoder_8b10b (
    input  logic        clk_in,       // trigger on rising edge
    input  logic        reset_in,     // reset_in, assert HI
    input  logic [9:0]  decoder_in,   // 10-bit input
    output logic [7:0]  decoder_out,  // 8-bit decoded output
    output logic        control_out   // control char, assert HI for control words
);

  // Internal registers
  logic [9:0] s_in_10b_reg;  
  logic [7:0] s_decoder_out; 
  logic       s_control_out;     

  always_ff @(posedge clk_in or posedge reset_in) begin
    if (reset_in) begin
      s_in_10b_reg    <= 10'b0000000000;
      s_decoder_out   <= 8'b00000000;
      s_control_out   <= 1'b0;
    end else begin
      s_in_10b_reg    <= decoder_in;
      // Default assignments
      s_decoder_out   <= 8'b00000000;
      s_control_out   <= 1'b0;

      // Decode valid control symbols
      if ((decoder_in == 10'b0011110100) || (decoder_in == 10'b1100001011)) begin
        s_decoder_out  <= 8'h1C;
        s_control_out  <= 1'b1;
      end else if ((decoder_in == 10'b0011111001) || (decoder_in == 10'b1100000110)) begin
        s_decoder_out  <= 8'h3C;
        s_control_out  <= 1'b1;
      end else if ((decoder_in == 10'b0011110101) || (decoder_in == 10'b1100001010)) begin
        s_decoder_out  <= 8'h5C;
        s_control_out  <= 1'b1;
      end else if ((decoder_in == 10'b0011110011) || (decoder_in == 10'b1100001100)) begin
        s_decoder_out  <= 8'h7C;
        s_control_out  <= 1'b1;
      end else if ((decoder_in == 10'b0011110010) || (decoder_in == 10'b1100001101)) begin
        s_decoder_out  <= 8'h9C;
        s_control_out  <= 1'b1;
      end else if ((decoder_in == 10'b0011111010) || (decoder_in == 10'b1100000101)) begin
        s_decoder_out  <= 8'hBC;
        s_control_out  <= 1'b1;
      end else if ((decoder_in == 10'b0011110110) || (decoder_in == 10'b1100001001)) begin
        s_decoder_out  <= 8'hDC;
        s_control_out  <= 1'b1;
      end else if ((decoder_in == 10'b0011111000) || (decoder_in == 10'b1100000111)) begin
        s_decoder_out  <= 8'hFC;
        s_control_out  <= 1'b1;
      end else if ((decoder_in == 10'b1110101000) || (decoder_in == 10'b0001010111)) begin
        s_decoder_out  <= 8'hF7;
        s_control_out  <= 1'b1;
      end else if ((decoder_in == 10'b1101101000) || (decoder_in == 10'b0010010111)) begin
        s_decoder_out  <= 8'hFB;
        s_control_out  <= 1'b1;
      end else if ((decoder_in == 10'b1011101000) || (decoder_in == 10'b0100010111)) begin
        s_decoder_out  <= 8'hFD;
        s_control_out  <= 1'b1;
      end else if ((decoder_in == 10'b0111101000) || (decoder_in == 10'b1000010111)) begin
        s_decoder_out  <= 8'hFE;
        s_control_out  <= 1'b1;
      end else begin
        // Invalid control symbol: leave outputs as default (0)
        s_decoder_out  <= 8'b00000000;
        s_control_out  <= 1'b0;
      end
    end
  end

  // Output assignments
  assign decoder_out = s_decoder_out;
  assign control_out = s_control_out;

endmodule

output.rtl/digital_dice_roller.sv:
module digital_dice_roller(
  input  logic         clk,
  input  logic         reset_n,
  input  logic         button,
  output logic [2:0]   dice_value
);

  // Define FSM states
  typedef enum logic [1:0] {
    IDLE  = 2'b00,
    ROLLING = 2'b01
  } state_t;

  state_t current_state, next_state;

  // Internal counter to hold dice value (1 to 6)
  logic [2:0] counter;

  // Next state combinational logic
  always_comb begin
    next_state = current_state;
    case (current_state)
      IDLE: begin
        if (button)
          next_state = ROLLING;
      end
      ROLLING: begin
        if (!button)
          next_state = IDLE;
      end
      default: next_state = IDLE;
    endcase
  end

  // Sequential block: update state, counter, and output
  always_ff @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      current_state  <= IDLE;
      counter        <= 3'b0;   // On reset, counter is 0 (dice_value = 000)
      dice_value     <= 3'b0;
    end else begin
      current_state <= next_state;

      // When in ROLLING state and button is HIGH, increment the counter
      if (current_state == ROLLING && button) begin
        if (counter == 3'b110) // If counter == 6
          counter <= 3'b001;  // Roll over to 1
        else
          counter <= counter + 1;
      end

      // Output assignment: when in ROLLING, update dice_value to counter;
      // when in IDLE, hold the last dice value.
      if (current_state == ROLLING)
        dice_value <= counter;
      else
        dice_value <= dice_value;
    end
  end

endmodule

input.rtl/digital_dice_roller.sv:
module digital_dice_roller #(
    parameter int DICE_MAX  = 6,                    // Maximum dice value
    parameter int BIT_WIDTH = $clog2(DICE_MAX) + 1  // Bit width to represent dice value
) (
    input wire clk,
    input wire reset,  // Asynchronous reset signal
    input wire button,
    output reg [BIT_WIDTH-1:0] dice_value
);

  // State encoding
  typedef enum logic [1:0] {
    IDLE    = 2'b00,
    ROLLING = 2'b01
  } state_t;

  state_t current_state, next_state;
  reg [BIT_WIDTH-1:0] counter;  // Counter to represent dice values

  // State transition and asynchronous reset logic (sequential)
  always_ff @(posedge clk or negedge reset) begin
    if (!reset) begin
      // Reset to initial values when async_reset is asserted
      current_state <= IDLE;
      counter <= 1;
      dice_value <= 1;
    end else begin
      current_state <= next_state;
    end
  end

  // Next state logic and counter increment (combinational)
  always_comb begin
    next_state = current_state;

    case (current_state)
      IDLE: begin
        if (button) next_state = ROLLING;
      end

      ROLLING: begin
        if (!button) next_state = IDLE;
      end
    endcase
  end

  // Counter logic to simulate rolling dice values from 1 to DICE_MAX
  always_ff @(posedge clk or negedge reset) begin
    if (!reset) begin
      // Reset counter and dice value when async_reset is asserted
      counter <= 1;
      dice_value <= 1;
    end else if (current_state == ROLLING) begin
      if (counter == DICE_MAX) counter <= 1;  // Reset to 1 after reaching DICE_MAX
      else counter <= counter + 1;
    end else if (current_state == IDLE) begin
      dice_value <= counter;  // Latch the final value
    end
  end
endmodule

