            default :  pwm_duty_cycle <= 8'd255; // Full speed (100% duty cycle)
            endcase

        end
    end

    assign speed_control = (temp_adc_in < TEMP_LOW ? 3'd1 : 
                           (temp_adc_in < TEMP_MED ? 3'd2 : 
                           (temp_adc_in < TEMP_HIGH ? 3'd3 : 3'd4)));

    // PWM generation logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            pwm_counter <= 8'd0;
            fan_pwm_out <= 1'b0;
        end else begin
            pwm_counter <= pwm_counter + 1;
            fan_pwm_out <= (pwm_counter < pwm_duty_cycle) ? 1'b1 : 1'b0;
        end
    end

endmodule

output.rtl/fan_controller.sv:
module fan_controller (
    input wire clk,                 // System clock
    input wire reset,               // Reset signal
    output reg fan_pwm_out,         // PWM output for fan control

    // APB signals
    input  wire         psel,       // Slave select
    input  wire         penable,    // Enable signal
    input  wire         pwrite,     // Write control
    input  wire [7:0]   paddr,      // Address bus
    input  wire [7:0]   pwdata,     // Write data bus
    output reg  [7:0]   prdata,     // Read data bus
    output reg          pready,      // Ready signal
    output reg          pslverr     // Slave error
);

    // Parameters for temperature thresholds
    reg [7:0] TEMP_LOW ;      // Low temperature threshold
    reg [7:0] TEMP_MED ;      // Medium temperature threshold
    reg [7:0] TEMP_HIGH;      // High temperature threshold
    reg [7:0]  temp_adc_in;   // Temperature sensor input (0-255)

    reg setup;
    // APB Protocol States
    always @(posedge clk or posedge reset)
    begin
        if (reset)
        begin
            prdata   <= 8'b0;
            pready   <= 1'b0;
            pslverr  <= 1'b0;
            TEMP_LOW <= 8'd30;
            TEMP_MED <= 8'd60;
            TEMP_HIGH<=8'd90;
            setup    <= 1'b0;
        end
        else
        begin
            if (psel && !penable && !setup)
            begin
                // Setup phase: Indicate the slave is not yet ready
                pready <= 1'b0;
                setup  <= 1'b1;
            end
            else if (psel && penable && setup)
            begin
                // Access phase: Perform read/write operation and indicate ready
                pready <= 1'b1; // Slave is ready for the current operation
                setup  <= 1'b0;
                if (pwrite)
                begin
                    // Write Operation
                    case(paddr)
                        8'h0a: begin 
                                TEMP_LOW    <= pwdata;
                                pslverr     <= 1'b0;
                             end
                        8'h0b: begin 
                                TEMP_MED    <= pwdata;
                                pslverr     <= 1'b0;
                             end
                        8'h0c: begin
                                TEMP_HIGH   <= pwdata;
                                pslverr     <= 1'b0;
                             end
                        8'h0f: begin
                                temp_adc_in <= pwdata;
                                pslverr     <= 1'b0;
                             end
                        default: pslverr <= 1'b1;
                    endcase
                end
                else 
                begin
                    // Read Operation
                    case(paddr)
                        8'h0a: begin
                                prdata   <= TEMP_LOW ;
                                pslverr  <= 1'b0;
                             end
                        8'h0b: begin 
                                prdata   <= TEMP_MED ;
                                pslverr  <= 1'b0;
                             end
                        8'h0c: begin
                                prdata   <= TEMP_HIGH;
                                pslverr  <= 1'b0;
                             end
                        8'h0f: begin
                                prdata   <= temp_adc_in;
                                pslverr  <= 1'b0;
                             end
                        default: pslverr <= 1'b1;
                    endcase
                end
            end
            else
            begin
                // Default case: Clear ready signal when not selected
                pready <= 1'b0;
                setup  <= 1'b0;
            end
        end
    end

    // PWM control
    reg [7:0] pwm_duty_cycle;    // Duty cycle (0-255)
    reg [7:0] pwm_counter;       // Counter for PWM generation

    // Optimized PWM control: Removed intermediate combinational signal "speed_control"
    // Directly compute the PWM duty cycle based on temperature thresholds.
    always @(posedge clk or posedge reset) begin
        if (reset)
            pwm_duty_cycle <= 8'd0;  // Fan off by default
        else begin
            if (temp_adc_in < TEMP_LOW)
                pwm_duty_cycle <= 8'd64;  // Low speed (25% duty cycle)
            else if (temp_adc_in < TEMP_MED)
                pwm_duty_cycle <= 8'd128; // Medium speed (50% duty cycle)
            else if (temp_adc_in < TEMP_HIGH)
                pwm_duty_cycle <= 8'd192; // High speed (75% duty cycle)
            else
                pwm_duty_cycle <= 8'd255; // Full speed (100% duty cycle)
        end
    end

    // PWM generation logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            pwm_counter <= 8'd0;
            fan_pwm_out <= 1'b0;
        end else begin
            pwm_counter <= pwm_counter + 1;
            fan_pwm_out <= (pwm_counter < pwm_duty_cycle) ? 1'b1 : 1'b0;
        end
    end

endmodule

output.rtl/fibonacci_series.sv:
module fibonacci_series (
  input  logic         clk,
  input  logic         rst,
  output logic [31:0]  fib_out,
  output logic         overflow_flag
);

  // Registers to hold previous Fibonacci numbers
  logic [31:0] RegA, RegB;
  // One-cycle flag to indicate that overflow was detected in the previous cycle
  logic        overflow_detected;

  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      // Reset behavior: initialize sequence and clear flags
      RegA        <= 32'd0;  // F(0) = 0
      RegB        <= 32'd1;  // F(1) = 1
      fib_out     <= 32'd0;  // Output starts with F(0)
      overflow_flag <= 1'b0;
      overflow_detected <= 1'b0;
    end
    else begin
      // Compute next Fibonacci number using 33-bit addition to detect overflow.
      logic [32:0] next_fib;
      next_fib = {1'b0, RegA} + {1'b0, RegB};

      if (overflow_detected) begin
        // This cycle follows an overflow detection.
        // Propagate the last valid Fibonacci number from the previous cycle.
        // Then reset the sequence and set the overflow flag.
        RegA        <= 32'd0;  // Restart sequence: F(0) = 0
        RegB        <= 32'd1;  // Restart sequence: F(1) = 1
        fib_out     <= 32'd0;  // Reset output
        overflow_flag <= 1'b1; // Indicate overflow occurred
        overflow_detected <= 1'b0;
      end
      else if (next_fib[32]) begin
        // Overflow detected in this cycle: the computed sum exceeds 32 bits.
        // Propagate the last valid Fibonacci number.
        fib_out     <= RegB;
        // Set the one-cycle flag so that on the next cycle, the sequence resets.
        overflow_detected <= 1'b1;
        // Do not update registers normally.
      end
      else begin
        // Normal Fibonacci calculation without overflow.
        RegA        <= RegB;
        RegB        <= next_fib[31:0];
        fib_out     <= RegB;
        overflow_detected <= 1'b0;
        overflow_flag <= 1'b0;
      end
    end
  end

endmodule

output.rtl/fifo_async.sv:
module fifo_async #(
  parameter DATA_WIDTH = 8,
  parameter DEPTH      = 16
)(
  input  logic                     w_clk,
  input  logic                     w_rst,
  input  logic                     w_inc,
  input  logic [DATA_WIDTH-1:0]    w_data,
  input  logic                     r_clk,
  input  logic                     r_rst,
  input  logic                     r_inc,
  output logic                     w_full,
  output logic                     r_empty,
  output logic [DATA_WIDTH-1:0]    r_data
);

  // Determine pointer width: one extra bit for overflow
  localparam PTR_WIDTH = $clog2(DEPTH) + 1;

  // Internal pointer signals (binary and Gray)
  logic [PTR_WIDTH-1:0] w_ptr_bin_local; // Write pointer in binary
  logic [PTR_WIDTH-1:0] w_ptr_gray;       // Write pointer in Gray code

  logic [PTR_WIDTH-1:0] r_ptr_bin_local; // Read pointer in binary
  logic [PTR_WIDTH-1:0] r_ptr_gray;       // Read pointer in Gray code

  // Dual-port memory declaration
  logic [DATA_WIDTH-1:0] mem [0:DEPTH-1];

  // Synchronizer signals for cross-clock pointer passing
  // Synchronizer for r_ptr from read to write domain
  logic [PTR_WIDTH-1:0] r_ptr_sync_stage0, r_ptr_sync_wire;
  // Synchronizer for w_ptr from write to read domain
  logic [PTR_WIDTH-1:0] w_ptr_sync_stage0, w_ptr_sync_wire;

  // Wires to pass pointer outputs from each domain
  wire [PTR_WIDTH-1:0] r_ptr_gray_from_read = r_ptr_gray;
  wire [PTR_WIDTH-1:0] w_ptr_gray_from_write = w_ptr_gray;

  // Binary conversion of synchronized pointers
  logic [PTR_WIDTH-1:0] r_ptr_sync_bin;
  logic [PTR_WIDTH-1:0] w_ptr_sync_bin;

  assign r_ptr_sync_bin = gray_to_bin(r_ptr_sync_wire);
  assign w_ptr_sync_bin = gray_to_bin(w_ptr_sync_wire);

  //----------------------------------------------------------------------------
  // Write Domain: Update write pointer, generate full flag, and write to memory
  //----------------------------------------------------------------------------
  always_ff @(posedge w_clk or posedge w_rst) begin
    if (w_rst) begin
      w_ptr_bin_local <= 0;
      w_ptr_gray      <= 0;
      w_full          <= 0;
    end
    else begin
      // Increment write pointer if enabled and FIFO not full
      if (w_inc && !w_full) begin
        w_ptr_bin_local <= w_ptr_bin_local + 1;
        // Convert binary to Gray code: gray = binary ^ (binary >> 1)
        w_ptr_gray <= w_ptr_bin_local ^ (w_ptr_bin_local >> 1);
      end

      // Full flag calculation:
      // FIFO is full if the MSB (overflow bit) differs while lower bits are equal.
      w_full <= ((w_ptr_bin_local[PTR_WIDTH-1] != r_ptr_sync_bin[PTR_WIDTH-1]) &&
                 (w_ptr_bin_local[PTR_WIDTH-2:0] == r_ptr_sync_bin[PTR_WIDTH-2:0]));

      // Write data to memory if not full
      if (w_inc && !w_full)
        mem[w_ptr_bin_local] <= w_data;
    end
  end

  //----------------------------------------------------------------------------
  // Read Domain: Update read pointer, generate empty flag, and read from memory
  //----------------------------------------------------------------------------
  always_ff @(posedge r_clk or posedge r_rst) begin
    if (r_rst) begin
      r_ptr_bin_local <= 0;
      r_ptr_gray      <= 0;
      r_empty         <= 0;
    end
    else begin
      // Increment read pointer if enabled and FIFO not empty
      if (r_inc && !r_empty) begin
        r_ptr_bin_local <= r_ptr_bin_local + 1;
        r_ptr_gray <= r_ptr_bin_local ^ (r_ptr_bin_local >> 1);
      end

      // Empty flag calculation:
      // FIFO is empty if the binary read pointer equals the synchronized write pointer.
      r_empty <= (r_ptr_bin_local == w_ptr_sync_bin);

      // Read data from memory if not empty
      if (r_inc && !r_empty)
        r_data <= mem[r_ptr_bin_local];
    end
  end

  //----------------------------------------------------------------------------
  // Synchronizer for r_ptr: Pass read pointer (Gray code) from read to write domain
  //----------------------------------------------------------------------------
  always_ff @(posedge w_clk or posedge w_rst) begin
    if (w_rst)
      r_ptr_sync_stage0 <= 0;
    else
      r_ptr_sync_stage0 <= r_ptr_gray_from_read; // Asynchronous capture from read domain
  end

  always_ff @(posedge w_clk or posedge w_rst) begin
    if (w_rst)
      r_ptr_sync_wire <= 0;
    else
      r_ptr_sync_wire <= r_ptr_sync_stage0;
  end

  //----------------------------------------------------------------------------
  // Synchronizer for w_ptr: Pass write pointer (Gray code) from write to read domain
  //----------------------------------------------------------------------------
  always_ff @(posedge r_clk or posedge r_rst) begin
    if (r_rst)
      w_ptr_sync_stage0 <= 0;
    else
      w_ptr_sync_stage0 <= w_ptr_gray_from_write; // Asynchronous capture from write domain
  end

  always_ff @(posedge r_clk or posedge r_rst) begin
    if (r_rst)
      w_ptr_sync_wire <= 0;
    else
      w_ptr_sync_wire <= w_ptr_sync_stage0;
  end

  //----------------------------------------------------------------------------
  // Function: Convert Gray code to binary
  //----------------------------------------------------------------------------
  function automatic [PTR_WIDTH-1:0] gray_to_bin(input [PTR_WIDTH-1:0] gray);
    integer i;
    logic [PTR_WIDTH-1:0] bin;
    begin
      bin = gray;
      for (i = PTR_WIDTH-2; i >= 0; i = i - 1)
        bin[i] = bin[i+1] ^ gray[i];
      gray_to_bin = bin;
    end
  endfunction

endmodule

output.rtl/ping_pong_fifo_2_axi_stream.sv:
module ping_pong_fifo_2_axi_stream #(
  parameter logic                              DATA_WIDTH          = 24,
  parameter logic                              STROBE_WIDTH        = DATA_WIDTH / 8,
  parameter logic                              USE_KEEP            = 0,
  parameter logic                              USER_IN_DATA        = 1
)(
  input  logic                                 rst,

  // Ping Pong FIFO Read Interface
  input  logic                                 i_block_fifo_rdy,
  output logic                                 o_block_fifo_act,
  input  logic [23:0]                          i_block_fifo_size,
  // Note: Although the port is declared as [(DATA_WIDTH+1)-1:0] (i.e. DATA_WIDTH bits),
  // the design specification indicates that i_block_fifo_data includes a “last” flag.
  // For this implementation we assume that the most-significant bit (MSB) of i_block_fifo_data
  // represents the “last” flag and the remaining DATA_WIDTH-1 bits are the actual data.
  input  logic [(DATA_WIDTH + 1) - 1:0]        i_block_fifo_data,
  output logic                                 o_block_fifo_stb,
  input  logic [3:0]                           i_axi_user,

  // AXI Stream Output
  input  logic                                 i_axi_clk,
  output logic [3:0]                           o_axi_user,
  input  logic                                 i_axi_ready,
  output logic [DATA_WIDTH - 1:0]              o_axi_data,
  output logic                                 o_axi_last,
  output logic                                 o_axi_valid
);

  // Internal signals
  // fifo_data_buffer holds the actual data from FIFO (excluding the MSB “last” flag)
  logic [DATA_WIDTH - 1:0] fifo_data_buffer;
  logic fifo_valid_buffer;
  logic fifo_last_buffer;

  // State machine states: IDLE and WAIT_AXI
  typedef enum logic {IDLE, WAIT_AXI} state_t;
  state_t state;

  // Reset and state machine
  always_ff @(posedge i_axi_clk or posedge rst) begin
    if (rst) begin
      state                   <= IDLE;
      fifo_valid_buffer       <= 1'b0;
      fifo_data_buffer        <= {DATA_WIDTH{1'b0}};
      fifo_last_buffer        <= 1'b0;
      o_block_fifo_act        <= 1'b0;
      o_block_fifo_stb        <= 1'b0;
      o_axi_valid             <= 1'b0;
      o_axi_data              <= {DATA_WIDTH{1'b0}};
      o_axi_last              <= 1'b0;
      o_axi_user              <= 4'd0;
    end
    else begin
      // Pass through user signal
      o_axi_user              <= i_axi_user;

      // Default assignments for FIFO control signals
      o_block_fifo_act        <= 1'b0;
      // We will drive o_block_fifo_stb only when a FIFO read is initiated.
      // It remains asserted until the AXI handshake completes.
      // (If AXI is not ready the strobe remains high.)

      case (state)
        IDLE: begin
          // Only initiate a FIFO read if FIFO is ready
          if (i_block_fifo_rdy) begin
            // Capture FIFO data:
            // Assume that i_block_fifo_data is organized as:
            // [DATA_WIDTH-1:1] = actual data, and bit [DATA_WIDTH] = last flag.
            fifo_data_buffer <= i_block_fifo_data[DATA_WIDTH - 1:1];
            fifo_last_buffer <= i_block_fifo_data[DATA_WIDTH];
            fifo_valid_buffer<= 1'b1;
            // Assert FIFO activate and strobe to indicate a read operation
            o_block_fifo_act  <= 1'b1;
            o_block_fifo_stb  <= 1'b1;
            // Move to WAIT_AXI state to transfer data to AXI
            state             <= WAIT_AXI;
          end
          else begin
            // FIFO not ready: remain idle.
            state             <= IDLE;
          end
        end

        WAIT_AXI: begin
          if (i_axi_ready) begin
            // AXI is ready to accept data: drive AXI outputs
            o_axi_data       <= fifo_data_buffer;
            o_axi_last       <= fifo_last_buffer;
            o_axi_valid      <= 1'b1;
            // Clear the FIFO valid buffer and deassert FIFO strobe after transfer
            fifo_valid_buffer<= 1'b0;
            o_block_fifo_stb <= 1'b0;
            // Return to IDLE to capture the next FIFO word
            state            <= IDLE;
          end
          else begin
            // AXI not ready: hold the valid signal and data until ready
            o_axi_data       <= fifo_data_buffer;
            o_axi_last       <= fifo_last_buffer;
            o_axi_valid      <= 1'b1;
            // Keep FIFO strobe asserted (indicating that a read has occurred)
            state            <= WAIT_AXI;
          end
        end

        default: state <= IDLE;
      endcase
    end
  end

endmodule

input.rtl/ping_pong_fifo_2_axi_stream.sv:
module ping_pong_fifo_2_axi_stream #( 
    parameter DATA_WIDTH = 32
)(
    input  logic                                 rst,

    // Ping Pong FIFO Read Interface
    input  logic                                 i_block_fifo_rdy,
    output logic                                 o_block_fifo_act,
    input  logic [23:0]                          i_block_fifo_size,
    input  logic [(DATA_WIDTH + 1) - 1:0]        i_block_fifo_data,
    output logic                                 o_block_fifo_stb,
    input  logic [3:0]                           i_axi_user,

    // AXI Stream Output
    input  logic                                 i_axi_clk,
    output logic [3:0]                           o_axi_user,
    input  logic                                 i_axi_ready,
    output logic [DATA_WIDTH - 1:0]              o_axi_data,
    output logic                                 o_axi_last,
    output logic                                 o_axi_valid
);

    // Internal Registers
    logic [23:0] block_size_reg;
    logic [23:0] data_count;
    logic        fifo_active;
    logic        data_valid;

    typedef enum logic [1:0] {
        IDLE,
        READ_FIFO,
        SEND_AXI
    } state_t;

    state_t current_state, next_state;

    always_ff @(posedge i_axi_clk or posedge rst) begin
        if (rst) begin
            current_state      <= IDLE;
            block_size_reg     <= 24'd0;
            data_count         <= 24'd0;
            fifo_active        <= 1'b0;
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_data         <= {DATA_WIDTH{1'b0}};
            o_axi_last         <= 1'b0;
            o_axi_user         <= 4'd0;
        end else begin
            current_state      <= next_state;
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_last         <= 1'b0;

            case (current_state)
                IDLE: begin
                    if (i_block_fifo_rdy) begin
                        o_block_fifo_act <= 1'b1; 
                        block_size_reg    <= i_block_fifo_size;
                        fifo_active       <= 1'b1;
                        data_count        <= 24'd0;
                        next_state        <= READ_FIFO;
                    end else begin
                        next_state <= IDLE;
                    end
                end

                READ_FIFO: begin
                    if (fifo_active && i_block_fifo_rdy) begin
                        o_block_fifo_stb <= 1'b1; 
                        data_count       <= data_count + 24'd1;
                        next_state       <= SEND_AXI;
                    end else begin
                        next_state <= READ_FIFO;
                    end
                end

                SEND_AXI: begin
                    if (fifo_active && i_axi_ready) begin
                        o_axi_valid  <= 1'b1;
                        o_axi_data   <= i_block_fifo_data[DATA_WIDTH-1:0];
                        o_axi_user   <= i_axi_user;

                        if (data_count + 24'd1 >= block_size_reg) begin
                            o_axi_last <= 1'b1;
                            fifo_active <= 1'b0; 
                            next_state  <= IDLE;
                        end else begin
                            next_state <= READ_FIFO;
                        end
                    end else begin
                        next_state <= SEND_AXI;
                    end
                end

                default: next_state <= IDLE;
            endcase
        end
    end

endmodule

output.rtl/ping_pong_fifo_2_axi_stream.sv:
module ping_pong_fifo_2_axi_stream #(
    parameter DATA_WIDTH = 32
)(
    input  logic                                 rst,
    input  logic                                 i_flush,    // Flush control input
    input  logic                                 i_pause,    // Pause control input
    // Ping Pong FIFO Read Interface
    input  logic                                 i_block_fifo_rdy,
    output logic                                 o_block_fifo_act,
    input  logic [23:0]                          i_block_fifo_size,
    input  logic [(DATA_WIDTH + 1) - 1:0]        i_block_fifo_data,
    output logic                                 o_block_fifo_stb,
    input  logic [3:0]                           i_axi_user,
    // AXI Stream Output
    input  logic                                 i_axi_clk,
    output logic [3:0]                           o_axi_user,
    input  logic                                 i_axi_ready,
    output logic [DATA_WIDTH - 1:0]              o_axi_data,
    output logic                                 o_axi_last,
    output logic                                 o_axi_valid
);

    // Internal Registers
    logic [23:0] block_size_reg;
    logic [23:0] data_count;
    logic        fifo_active;

    // Enhanced Data Handling Signals
    logic [DATA_WIDTH - 1:0] fifo_data_reg;
    logic        fifo_data_valid;
    logic        data_pending;

    typedef enum logic [1:0] {
        IDLE,
        READ_FIFO,
        SEND_AXI
    } state_t;

    state_t current_state, next_state;

    always_ff @(posedge i_axi_clk or posedge rst) begin
        if (rst) begin
            current_state      <= IDLE;
            block_size_reg     <= 24'd0;
            data_count         <= 24'd0;
            fifo_active        <= 1'b0;
            fifo_data_valid    <= 1'b0;
            data_pending       <= 1'b0;
            fifo_data_reg      <= {DATA_WIDTH{1'b0}};
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_last         <= 1'b0;
            o_axi_data         <= {DATA_WIDTH{1'b0}};
            o_axi_user         <= 4'd0;
        end 
        else if (i_flush) begin
            // Flush: immediately reset state and clear all registers/outputs.
            current_state      <= IDLE;
            block_size_reg     <= 24'd0;
            data_count         <= 24'd0;
            fifo_active        <= 1'b0;
            fifo_data_valid    <= 1'b0;
            data_pending       <= 1'b0;
            fifo_data_reg      <= {DATA_WIDTH{1'b0}};
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_last         <= 1'b0;
            o_axi_data         <= {DATA_WIDTH{1'b0}};
            o_axi_user         <= 4'd0;
        end 
        else begin
            // Default assignments for stable outputs
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_last         <= 1'b0;
            o_axi_data         <= {DATA_WIDTH{1'b0}};
            o_axi_user         <= 4'd0;

            case (current_state)
                IDLE: begin
                    if (i_block_fifo_rdy) begin
                        o_block_fifo_act <= 1'b1;
                        block_size_reg    <= i_block_fifo_size;
                        fifo_active       <= 1'b1;
                        data_count        <= 24'd0;
                        next_state        <= READ_FIFO;
                    end 
                    else begin
                        next_state <= IDLE;
                    end
                end

                READ_FIFO: begin
                    if (fifo_active && i_block_fifo_rdy) begin
                        o_block_fifo_stb <= 1'b1;
                        // Capture the FIFO data into the intermediate register
                        fifo_data_reg    <= i_block_fifo_data[DATA_WIDTH-1:0];
                        fifo_data_valid  <= 1'b1;
                        data_pending     <= 1'b1;
                        data_count       <= data_count + 24'd1;
                        next_state       <= SEND_AXI;
                    end 
                    else begin
                        next_state <= READ_FIFO;
                    end
                end

                SEND_AXI: begin
                    // If pause is asserted, hold the state and do not send data
                    if (i_pause) begin
                        next_state <= SEND_AXI;
                    end 
                    else if (fifo_data_valid && i_axi_ready) begin
                        o_axi_valid  <= 1'b1;
                        o_axi_data   <= fifo_data_reg;
                        o_axi_user   <= i_axi_user;
                        // Clear the data validity flag after sending
                        fifo_data_valid <= 1'b0;
                        data_pending    <= 1'b0;

                        if (data_count + 24'd1 >= block_size_reg) begin
                            o_axi_last  <= 1'b1;
                            fifo_active <= 1'b0;
                            next_state  <= IDLE;
                        end 
                        else begin
                            next_state <= READ_FIFO;
                        end
                    end 
                    else begin
                        next_state <= SEND_AXI;
                    end
                end

                default: next_state <= IDLE;
            endcase
            current_state <= next_state;
        end
    end

endmodule

output.rtl/FILO_RTL.sv:
module FILO_RTL #(
  parameter DATA_WIDTH = 8,
  parameter FILO_DEPTH = 16
)(
  input  logic                     clk,
  input  logic                     reset,
  input  logic                     push,
  input  logic                     pop,
  input  logic [DATA_WIDTH-1:0]    data_in,
  output logic [DATA_WIDTH-1:0]    data_out,
  output logic                     full,
  output logic                     empty
);

  // Calculate address width for the pointer based on FILO_DEPTH.
  localparam ADDR_WIDTH = $clog2(FILO_DEPTH);

  // Memory to store FILO data elements.
  reg [DATA_WIDTH-1:0] mem [0:FILO_DEPTH-1];

  // Stack pointer indicating the next free location.
  reg [ADDR_WIDTH-1:0] top;

  // Intermediate register used for simultaneous push & pop operations.
  reg [ADDR_WIDTH-1:0] temp_top;

  // Sequential process: operations occur on rising edge of clk or asynchronous reset.
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      // Reset: clear pointer and memory, and set status signals.
      top          <= 0;
      integer i;
      for (i = 0; i < FILO_DEPTH; i = i + 1) begin
        mem[i] <= '0;
      end
      full   <= 0;
      empty  <= 1;
      data_out <= '0;
    end
    else begin
      // Check for simultaneous push and pop.
      if (push && pop) begin
        if (top == 0) begin
          // Feedthrough case: FILO is empty.
          // Pass input data directly to output without storing it.
          data_out <= data_in;
          // Pointer remains unchanged.
        end
        else begin
          // When buffer is not empty, perform both push and pop.
          // The net effect is that data_in is pushed and then immediately popped,
          // so the stack pointer remains unchanged.
          temp_top <= top;              // Save current top index.
          mem[temp_top] <= data_in;     // Store data_in at current top.
          top <= temp_top + 1;          // Push: increment pointer.
          top <= temp_top;              // Pop: decrement pointer back to original.
          data_out <= data_in;          // Output the pushed data.
        end
      end
      // Only push operation.
      else if (push) begin
        if (top != (FILO_DEPTH-1)) begin
          mem[top] <= data_in;
          top <= top + 1;
        end
        // If full, do nothing.
      end
      // Only pop operation.
      else if (pop) begin
        if (top != 0) begin
          top <= top - 1;
          data_out <= mem[top];
        end
        // If empty, do nothing.
      end
    end
  end

  // Combinational assignments for status signals.
  assign full  = (top == FILO_DEPTH);
  assign empty = (top == 0);

endmodule

input.rtl/FILO_RTL.sv:
module FILO_RTL #(
    parameter DATA_WIDTH = 8,  // Width of the data entries
    parameter FILO_DEPTH = 16  // Depth of the FILO buffer
) (
    input  wire                  clk,       // Clock signal
    input  wire                  reset,     // Asynchronous reset signal
    input  wire                  push,      // Push control signal
    input  wire                  pop,       // Pop control signal
    input  wire [DATA_WIDTH-1:0] data_in,   // Data input
    output reg  [DATA_WIDTH-1:0] data_out,  // Data output
    output reg                   full,      // Full status signal
    output reg                   empty      // Empty status signal
);


  reg [DATA_WIDTH-1:0] memory[FILO_DEPTH-1:0];  
  reg [$clog2(FILO_DEPTH):0] top;  

  reg feedthrough_valid;
  reg [DATA_WIDTH-1:0] feedthrough_data;


  always @(posedge clk or posedge reset) begin
    if (reset) begin
      top <= 0;
      empty <= 1;
      full <= 0;
      feedthrough_valid <= 0;
      data_out <= 0;  
    end else begin

      if (push && pop && empty) begin
        data_out <= data_in; 
        feedthrough_data <= data_in;
        feedthrough_valid <= 1;
      end else begin

        if (push && !full) begin
          memory[top] <= data_in;  
          top <= top + 1;  
          feedthrough_valid <= 0;
        end

        if (pop && !empty) begin
          if (feedthrough_valid) begin
            data_out <= feedthrough_data;  
            feedthrough_valid <= 0;
          end else begin
            top <= top; 
            data_out <= memory[top-1]; 
          end
        end
      end

      empty <= (top == 0);
      full  <= (top == FILO_DEPTH);  
    end
  end
endmodule

output.rtl/FILO_RTL.sv:
module FILO_RTL #(
    parameter DATA_WIDTH = 8,  // Width of the data entries
    parameter FILO_DEPTH = 16  // Depth of the FILO buffer
) (
    input  wire                  clk,       // Clock signal
    input  wire                  reset,     // Asynchronous reset signal
    input  wire                  push,      // Push control signal
    input  wire                  pop,       // Pop control signal
    input  wire [DATA_WIDTH-1:0] data_in,   // Data input
    output reg  [DATA_WIDTH-1:0] data_out,  // Data output
    output reg                   full,      // Full status signal
    output reg                   empty      // Empty status signal
);

  reg [DATA_WIDTH-1:0] memory[FILO_DEPTH-1:0];  
  reg [$clog2(FILO_DEPTH):0] top;  

  reg feedthrough_valid;
  reg [DATA_WIDTH-1:0] feedthrough_data;


  always @(posedge clk or posedge reset) begin
    if (reset) begin
      top <= 0;
      empty <= 1;
      full <= 0;
      feedthrough_valid <= 0;
      data_out <= 0;  
    end else begin

      // Handle simultaneous push/pop on an empty stack (feedthrough)
      if (push && pop && empty) begin
        data_out <= data_in; 
        feedthrough_data <= data_in;
        feedthrough_valid <= 1;
      end else begin

        // Push operation: store data and increment stack pointer
        if (push && !full) begin
          memory[top] <= data_in;  
          top <= top + 1;  
          feedthrough_valid <= 0;
        end

        // Pop operation: read from stack and decrement stack pointer
        if (pop && !empty) begin
          if (feedthrough_valid) begin
            data_out <= feedthrough_data;  
            feedthrough_valid <= 0;
          end else begin
            data_out <= memory[top-1]; 
            top <= top - 1; // Fix: decrement stack pointer on pop
          end
        end
      end

      // Update status signals
      empty <= (top == 0);
      full  <= (top == FILO_DEPTH);  
    end
  end
endmodule

output.rtl/findfasterclock.sv:
module FindFasterClock(
    input  wire clk_A,
    input  wire clk_B,
    input  wire rst_n,            // Active-low reset
    output reg  A_faster_than_B,  // 1 if clk_A is measured faster
    output reg  valid             // 1 once both clocks have measured a period
);

    //----------------------------------------
    // Internal signals
    //----------------------------------------
    reg        measure_B;          
    reg [31:0] b_count;            
    reg [31:0] periodA;            
    reg        done_A;             
    reg        measure_A;
    reg [31:0] a_count;
    reg [31:0] periodB;            
    reg        done_B;

    // A-domain FSM for measuring "periodA"
    reg [1:0] stateA;  
    localparam A_IDLE    = 2'd0,
               A_COUNT   = 2'd1,
               A_DONE    = 2'd2;
    // B-domain FSM for measuring "periodB"
    reg [1:0] stateB;
    localparam B_IDLE    = 2'd0,
               B_COUNT   = 2'd1,
               B_DONE    = 2'd2;

    // Clock A FSM
    always @(posedge clk_A or negedge rst_n) begin
        if (!rst_n) begin
            stateA         <= A_IDLE;
            measure_B      <= 0;
            b_count        <= 0;
            periodA        <= 0;
            done_A         <= 0;
        end else begin
            case (stateA)
                A_IDLE: begin
                    // Start measurement: enable counting in the B domain
                    measure_B <= 1;
                    stateA    <= A_COUNT;
                end
                A_COUNT: begin
                    // Capture the count from the B domain and finalize periodA
                    periodA  <= b_count;
                    done_A   <= 1;
                    stateA   <= A_DONE;
                end
                A_DONE: begin
                    // Remain in DONE state; measurement is complete
                    stateA <= A_DONE;
                end
                default: stateA <= A_IDLE;
            endcase
        end
    end

    // Clock B FSM
    always @(posedge clk_B or negedge rst_n) begin
        if (!rst_n) begin
            stateB         <= B_IDLE;
            measure_A      <= 0;
            a_count        <= 0;
            periodB        <= 0;
            done_B         <= 0;
        end else begin
            case (stateB)
                B_IDLE: begin
                    // Start measurement: enable counting in the A domain
                    measure_A <= 1;
                    stateB    <= B_COUNT;
                end
                B_COUNT: begin
                    // Capture the count from the A domain and finalize periodB
                    periodB  <= a_count;
                    done_B   <= 1;
                    stateB   <= B_DONE;
                end
                B_DONE: begin
                    // Remain in DONE state; measurement is complete
                    stateB <= B_DONE;
                end
                default: stateB <= B_IDLE;
            endcase
        end
    end

    // In B-domain, if measure_B=1, increment b_count on each clk_B rising edge
    always @(posedge clk_B or negedge rst_n) begin
        if (!rst_n) begin
            b_count <= 0;
        end else if (measure_B) begin
            b_count <= b_count + 1;
        end
    end

    // In A-domain, if measure_A=1, increment a_count on each clk_A rising edge
    always @(posedge clk_A or negedge rst_n) begin
        if (!rst_n) begin
            a_count <= 0;
        end else if (measure_A) begin
            a_count <= a_count + 1;
        end
    end

    // Combine results: valid = done_A && done_B, and compare periodA and periodB
    always @(*) begin
        if (!rst_n) begin
            valid            = 0;
            A_faster_than_B = 0;
        end else begin
            valid = (done_A && done_B);
            if (valid) begin
                // If periodB > periodA, then clk_A toggles faster
                A_faster_than_B = (periodB > periodA);
            end else begin
                A_faster_than_B = 0;
            end
        end
    end

endmodule

output.rtl/SR_flipflop.sv:
module SR_flipflop(
    input i_S,        // Set input
    input i_R,        // Reset input
    input i_clk,      // Clock input
    input i_rst_b,    // Asynchronous active-low reset input
    output reg o_Q,   // Output Q
    output reg o_Q_b  // Inverted output Q
);

    // Always block triggered on the positive edge of the clock
    always @(posedge i_clk or negedge i_rst_b)
    begin
        if (!i_rst_b) // Asynchronous reset active-low
        begin
            o_Q   <= 1'b0;  // Force output Q to low
            o_Q_b <= 1'b1;  // Force inverted output Q to high
        end
        else
        begin
            // Synchronous operation based on i_S and i_R
            if (i_S && i_R) begin
                // Invalid state: both set and reset are high.
                // For safety, force outputs to a defined state.
                o_Q   <= 1'b0;
                o_Q_b <= 1'b1;
            end
            else if (i_S) begin
                // Set operation: set output Q to high.
                o_Q   <= 1'b1;
                o_Q_b <= 1'b0;
            end
            else if (i_R) begin
                // Reset operation: reset output Q to low.
                o_Q   <= 1'b0;
                o_Q_b <= 1'b1;
            end
            else begin
                // Hold state: retain previous value when both inputs are low.
            end
        end
    end

endmodule

output.rtl/JK_flipflop.sv:
module JK_flipflop(
    input i_J,       // J input of the JK flip-flop
    input i_K,       // K input of the JK flip-flop
    input i_clk,     // Clock input
    input i_rst_b,   // Asynchronous reset, active low
    output reg o_Q,  // Q output
    output reg o_Q_b // Inverted Q output
);

    // Always block triggered on the rising edge of the clock or the falling edge of the reset
    always @(posedge i_clk or negedge i_rst_b) begin
        if (!i_rst_b) begin
            o_Q   <= 1'b0;
            o_Q_b <= 1'b1;
        end else begin
            // Declare a temporary variable to compute the new state
            bit new_Q;
            case ({i_J, i_K})
                2'b00: new_Q = o_Q;     // Hold state
                2'b01: new_Q = 1'b0;    // Reset state
                2'b10: new_Q = 1'b1;    // Set state
                2'b11: new_Q = ~o_Q;    // Toggle state
            endcase
            o_Q   <= new_Q;
            o_Q_b <= ~new_Q;
        end
    end

endmodule

output.rtl/fsm_seq_detector.sv:
module fsm_seq_detector (
    input  bit         clk_in,    // 50% duty cycle clock
    input  logic       rst_in,    // asynchronous active-high reset
    input  logic       seq_in,    // serial input bit (0 or 1)
    output logic       seq_detected // asserted high for one clk when sequence detected
);

  // Define the 3-bit state encoding for 8 states: S0 to S7
  typedef enum logic [2:0] {
    S0 = 3'b000,
    S1 = 3'b001,
    S2 = 3'b010,
    S3 = 3'b011,
    S4 = 3'b100,
    S5 = 3'b101,
    S6 = 3'b110,
    S7 = 3'b111
  } state_t;

  state_t state, next_state;
  logic seq_detected_w;  // combinational signal for seq_detected

  // Next state and output logic (combinational)
  always_comb begin
    // Default assignments
    next_state = state;
    seq_detected_w = 1'b0;
    case (state)
      S0: begin
        if (seq_in)
          next_state = S1;
        else
          next_state = S0;
      end
      S1: begin
        if (!seq_in)
          next_state = S2;
        else
          next_state = S1;  // if input is 1, remain in S1 (pattern prefix "1")
      end
      S2: begin
        if (seq_in)
          next_state = S3;
        else
          next_state = S0;
      end
      S3: begin
        if (seq_in)
          next_state = S4;
        else
          next_state = S1;
      end
      S4: begin
        if (!seq_in)
          next_state = S5;
        else
          next_state = S1;
      end
      S5: begin
        if (!seq_in)
          next_state = S6;
        else
          next_state = S2;
      end
      S6: begin
        if (!seq_in)
          next_state = S7;
        else
          next_state = S2;
      end
      S7: begin
        if (seq_in) begin
          next_state = S0;
          seq_detected_w = 1'b1;  // sequence detected: output high this cycle
        end
        else begin
          next_state = S0;
        end
      end
      default: begin
        next_state = S0;
      end
    endcase
  end

  // Sequential always block: state register and registered output
  always_ff @(posedge clk_in or posedge rst_in) begin
    if (rst_in) begin
      state      <= S0;
      seq_detected <= 1'b0;
    end
    else begin
      state      <= next_state;
      seq_detected <= seq_detected_w;
    end
  end

endmodule

