logic [NBW_WORD-1:0] data_in_ff      [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimes2_nx [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimes3_nx [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimes9_nx [LINES][COLUMNS];
