logic [NBW_WORD-1:0] data_out_nx     [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimes2_ff [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimes3_ff [LINES][COLUMNS];
logic [NBW_WORD-1:0] data_xtimes9_ff [LINES][COLUMNS];
