module gcd_3_ip #(
   parameter WIDTH = 4
   )(
   input                     clk,
   input                     rst,
   input  [WIDTH-1:0]        A,
   input  [WIDTH-1:0]        B,
   input  [WIDTH-1:0]        C,
   input                     go,
   output logic  [WIDTH-1:0] OUT,
   output logic              done
);

logic [WIDTH-1:0] gcd_ab;
logic [WIDTH-1:0] gcd_bc;
logic             go_abc;
logic             done_ab;
logic             done_bc;
logic             done_ab_latched;
logic             done_bc_latched;

// GCD is calculated for AB and BC in parallel. The GCD for two numbers is lower than the numbers themselves in most cases.
// And calculating GCD for smaller numbers is comparatively faster using the implemented algorithm.
// Hence in order to reduce GCD computation latency the calculation is broken up in this fashion.

gcd_top
#( .WIDTH(WIDTH)
) gcd_A_B_inst (
   .clk           (clk),
   .rst           (rst),
   .A             (A),
   .B             (B),
   .go            (go),
   .OUT           (gcd_ab),
   .done          (done_ab)
);

gcd_top
#( .WIDTH(WIDTH)
) gcd_B_C_inst (
   .clk           (clk),
   .rst           (rst),
   .A             (B),
   .B             (C),
   .go            (go),
   .OUT           (gcd_bc),
   .done          (done_bc)
);

gcd_top
#( .WIDTH(WIDTH)
) gcd_ABC_inst (
   .clk           (clk),
   .rst           (rst),
   .A             (gcd_ab),
   .B             (gcd_bc),
   .go            (go_abc),
   .OUT           (OUT),
   .done          (done)
);

always_ff @ (posedge clk) begin
   if (rst) begin
      done_ab_latched    <= 0;
      done_bc_latched    <= 0;
   end else begin
      if(done_ab) begin
         done_ab_latched <= done_ab;
      end else if (go_abc) begin
         done_ab_latched <= 0;
      end

      if(done_bc) begin
         done_bc_latched <= done_bc;
      end else if (go_abc) begin
         done_bc_latched <= 0;
      end
   end
end

assign go_abc = done_ab_latched & done_bc_latched;

endmodule

