    always_ff @(posedge clk_in or posedge rst_in) begin
        if (rst_in) begin
            count <= {N{1'b0}};
        end else if (enable_in) begin
            case (mode_in)
                BINARY_UP: begin
                    count <= count + 1;
                end
                BINARY_DOWN: begin
                    count <= count - 1;
                end
                MODULO_256: begin
                    if (count == ref_modulo)
                        count <= {N{1'b0}};
                    else
                        count <= count + 1;
                end
                JOHNSON: begin
                    count <= {~count[0], count[N-1:1]};
                end
                GRAY: begin
                    // In GRAY mode, update count normally (like BINARY_UP)
                    count <= count + 1;
                end
                RING: begin
                    if (count == {N{1'b0}})
                        count <= {{(N-1){1'b0}}, 1'b1};
                    else
                        count <= {count[N-2:0], count[N-1]};
                end		
                default: begin
                    count <= {N{1'b0}};
