output.rtl/gmii_rx_to_axi_stream.sv:
module gmii_rx_to_axi_stream (
    // GMII Input Signals:
    input  wire        gmii_rx_clk,
    input  wire [7:0]  gmii_rxd,
    input  wire        gmii_rx_dv,

    // AXI-Stream Output Signals:
    output wire [7:0]  m_axis_tdata,
    output wire        m_axis_tvalid,
    input  wire        m_axis_tready,
    output wire        m_axis_tlast
);

    // State definitions
    localparam IDLE      = 2'b00,
               RECEIVING = 2'b01,
               FINISHED  = 2'b10;

    reg [1:0] state;
    reg [7:0] data_reg;
    // tvalid and tlast are derived from state and m_axis_tready

    // State machine: clocked by gmii_rx_clk
    always @(posedge gmii_rx_clk) begin
        case (state)
            IDLE: begin
                // Wait for start of frame indicated by gmii_rx_dv
                if (gmii_rx_dv) begin
                    data_reg <= gmii_rxd;  // Capture the first byte
                    state    <= RECEIVING;
                end
            end
            RECEIVING: begin
                // Only transfer when downstream is ready
                if (m_axis_tready) begin
                    if (gmii_rx_dv) begin
                        // Still receiving: update data_reg with current gmii_rxd
                        data_reg <= gmii_rxd;
                        state    <= RECEIVING;
                    end else begin
                        // gmii_rx_dv dropped: end of frame detected
                        state <= FINISHED;
                    end
                end
                // If m_axis_tready is low, hold state and data_reg
            end
            FINISHED: begin
                // Wait for handshake completion before returning to IDLE
                if (m_axis_tready) begin
                    state <= IDLE;
                end
            end
            default: state <= IDLE;
        endcase
    end

    // Output assignments:
    // m_axis_tdata always reflects the current data to be sent.
    assign m_axis_tdata = data_reg;

    // m_axis_tvalid is asserted only when data is available and the downstream is ready.
    // According to the spec, tvalid is de-asserted if m_axis_tready is low.
    assign m_axis_tvalid = (((state == RECEIVING) || (state == FINISHED)) && m_axis_tready);

    // m_axis_tlast is asserted only in the FINISHED state to indicate end-of-frame.
    assign m_axis_tlast = (state == FINISHED);

endmodule

output.rtl/gray_to_binary.sv:
module gray_to_binary #(
    parameter WIDTH      = 4,  // Specify the width of the Gray code input
    parameter DEBUG_MODE = 0   // Debug mode: 0 = Disabled, 1 = Enabled
) (
    input  logic [WIDTH-1:0] gray_in,     
    output logic [WIDTH-1:0] binary_out, 
    output logic [WIDTH-1:0] debug_mask,  
    output logic             parity,   
    output logic             valid        
);

  // Internal signals for processing stages
  logic [WIDTH-1:0] intermediate_stage_1; 
  logic [WIDTH-1:0] intermediate_stage_2;  
  logic [WIDTH-1:0] masked_output;
  logic [WIDTH-1:0] final_binary;  
  logic             valid_stage_1;  
  logic             valid_stage_2;  

  always @* begin

    // Stage 1: Intermediate Binary Computation
    // The MSB of the binary output is directly the MSB of the Gray code input.
    intermediate_stage_1[WIDTH-1] = gray_in[WIDTH-1];
    for (int i = WIDTH - 2; i >= 0; i--) begin
      intermediate_stage_1[i] = intermediate_stage_1[i+1] ^ gray_in[i];
    end
    valid_stage_1 = 1'b1;  

    // Stage 2: Debugging and Masking
    if (DEBUG_MODE) begin
         // When debug mode is enabled, generate a debug mask by inverting the computed binary output.
         debug_mask = ~intermediate_stage_1;
         intermediate_stage_2 = intermediate_stage_1; // Preserve the computed result.
         masked_output = intermediate_stage_1;       // No modification to the binary output.
    end else begin
         // Debug mode disabled: pass the binary output directly and clear the debug mask.
         debug_mask = {WIDTH{1'b0}};
         intermediate_stage_2 = intermediate_stage_1;
         masked_output = intermediate_stage_1;
    end
    valid_stage_2 = 1'b1;

    // Stage 3: Final Outputs
    final_binary = masked_output;
    binary_out = final_binary;
    // Compute parity by XOR-reducing the final binary output.
    parity = ^final_binary;
    valid = 1'b1;

  end

endmodule

