output.rtl/microcode_sequencer.sv:
module decodes a 5‐bit instruction and generates a 4‐bit control store address.
// The control store address is computed using combinational logic based on predefined mappings.
// Other signals are passed through or assigned default values.

module microcode_sequencer (
    input  logic         clk,         // 1-bit positive edge-triggered clock
    input  logic         c_n_in,      // Carry-in for ripple-carry adder
    input  logic         c_inc_in,    // Carry-in for PC incrementer
    input  logic         r_en,        // ACTIVE LOW auxiliary register enable
    input  logic         cc,          // ACTIVE LOW condition code input
    input  logic         ien,         // ACTIVE LOW instruction enable
    input  logic [3:0]   d_in,        // 4-bit data input bus
    input  logic [4:0]   instr_in,    // 5-bit opcode representing the instruction
    input  logic         oen,         // ACTIVE LOW output enable for data output path

    output logic [3:0]   d_out,       // 4-bit control store address output
    output logic         c_n_out,     // Carry-out from ripple-carry adder
    output logic         c_inc_out,   // Carry-out from PC incrementer
    output logic         full,        // ACTIVE HIGH: stack full flag
    output logic         empty        // ACTIVE HIGH: stack empty flag
);

  // Combinational decoder: maps the 5-bit instruction to a 4-bit control store address.
  // Predefined mappings (example):
  //   5'b00000 - PRST (Program Reset)         -> 4'b0000
  //   5'b00001 - Fetch PC                     -> 4'b0001
  //   5'b00010 - Fetch R                      -> 4'b0010
  //   5'b00011 - Fetch D                      -> 4'b0011
  //   5'b00100 - Fetch R + D                  -> 4'b0100
  //   5'b01011 - Push PC                      -> 4'b0101
  //   5'b01110 - Pop PC                       -> 4'b0110
  always_comb begin
    unique case (instr_in)
      5'b00000: d_out = 4'b0000; // PRST
      5'b00001: d_out = 4'b0001; // Fetch PC
      5'b00010: d_out = 4'b0010; // Fetch R
      5'b00011: d_out = 4'b0011; // Fetch D
      5'b00100: d_out = 4'b0100; // Fetch R + D
      5'b01011: d_out = 4'b0101; // Push PC
      5'b01110: d_out = 4'b0110; // Pop PC
      default:  d_out = 4'b0000; // Default mapping
    endcase
  end

  // For this design, the remaining signals are passed through or assigned default values.
  assign c_n_out = c_n_in;
  assign c_inc_out = c_inc_in;
  assign full = 1'b0;      // Default: stack is not full
  assign empty = 1'b0;     // Default: stack is not empty

endmodule

input.rtl/signed_sequential_booth_multiplier.s:
module signed_sequential_booth_multiplier #(parameter WIDTH = 8) (
    input  wire signed [WIDTH-1:0] A,
    input  wire signed [WIDTH-1:0] B,
    input  wire clk,
    input  wire rst,
    input  wire start,
    output reg  signed [2*WIDTH-1:0] result,
    output reg done
);

    // FSM states
    typedef enum logic [2:0] {
        IDLE     = 3'b000,
        ENCODE   = 3'b001, 
        PARTIAL  = 3'b010, 
        ADDITION = 3'b011, 
        DONE     = 3'b100
    } state_t;

    state_t state, next_state;

    // Registers for control and data signals
    reg signed [2*WIDTH-1:0] partial_products [0:WIDTH/2-1];
    reg signed [2*WIDTH-1:0] multiplicand;
    reg signed [WIDTH:0] booth_bits; 
    reg signed [2*WIDTH-1:0] accumulator;  
    reg [2:0] encoding_bits [0:WIDTH/2-1];
    reg [$clog2(WIDTH/2):0] addition_counter; // Counter for addition cycles
    integer i;

    // State machine: Sequential process for state transitions
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    // State machine: Combinational process for next-state logic
    always @(*) begin
        case (state)
            IDLE: begin
                if (start) begin
                    next_state = ENCODE;
                end else begin
                    next_state = IDLE;
                end
            end

            ENCODE: begin
                next_state = PARTIAL;
            end

            PARTIAL: begin
                next_state = ADDITION;
            end

            ADDITION: begin
                next_state = DONE;
            end

            DONE: begin
                if (!start) begin
                    next_state = IDLE;
                end else begin
                    next_state = DONE;
                end
            end

            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // Signal assignments: Perform operations based on current state
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            done <= 0;
            result <= 0;
            accumulator <= 0;
            addition_counter <= 0;
            multiplicand <= 0;
            booth_bits <= 0;
            for (i = 0; i < WIDTH/2; i = i + 1) begin
                encoding_bits[i] <= 0;
                partial_products[i] <= 0;
            end
        end else begin
            case (state)
                IDLE: begin
                    // Prepare for new computation
                    done <= 0;
                    result <= 0;
                    if (start) begin
                        multiplicand <= {{(WIDTH){A[WIDTH-1]}}, A}; // Sign-extend A
                        booth_bits <= {B, 1'b0};
                        accumulator <= 0;
                        for (i = 0; i < WIDTH/2; i = i + 1) begin
                            partial_products[i] <= 0;
                        end
                    end
                end

                ENCODE: begin
                    // Extract 3-bit Booth segments
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                        encoding_bits[i] <= booth_bits[2*i +: 3];
                    end
                end

                PARTIAL: begin
                    // Generate partial products based on Booth encoding
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                        case (encoding_bits[i])
                            3'b001, 3'b010: partial_products[i] <= (multiplicand << (2 * i));
                            3'b011:         partial_products[i] <= ((multiplicand << 1) << (2 * i));
                            3'b100:         partial_products[i] <= -((multiplicand << 1) << (2 * i));
                            3'b101, 3'b110: partial_products[i] <= -(multiplicand << (2 * i));
                            default:        partial_products[i] <= 0;
                        endcase
                    end
                end

                ADDITION: begin
                    accumulator <= 0;
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                      accumulator <= accumulator + partial_products[i];  
                    end
                end

                DONE: begin
                    // Output the result
                    result <= accumulator;
                    done <= 1;
                end
            endcase
        end
    end
endmodule

module pipelined_modified_booth_multiplier (
    input clk,
    input rst,
    input start,
    input signed [15:0] X,
    input signed [15:0] Y,
    output reg signed  [31:0] result,
    output reg done
);

    reg signed [31:0] partial_products [0:7];
    reg signed [15:0] X_reg, Y_reg;
    reg [4:0] valid_reg; // Extended valid register for more granular state control

    integer i;

    // Registers for pipelining the addition stages
    reg signed [31:0] s1, s2, s3, s4;
    reg signed [31:0] temp_products1, temp_products2;

    always @(posedge clk or posedge rst) 
    begin
        if (rst) 
        begin
            X_reg <= 16'd0;
            Y_reg <= 16'd0;
            valid_reg <= 5'd0;
            done <= 0;
            for (i = 0; i < 8; i = i + 1) 
            begin
                partial_products[i] <= 32'd0;
            end
            s1 <= 0; s2 <= 0; s3 <= 0; s4 <= 0;
            temp_products1 <= 0; temp_products2 <= 0;
            result <= 32'd0;
            done <= 1'b0;
        end 
        else 
        begin
            if (start && !valid_reg[0]) begin
                X_reg <= X;
                Y_reg <= Y;
                valid_reg[0] <= 1;  // Initiate state 1
            end
            else
              valid_reg[0] <= 0;  // Initiate state 1 

            // Process Booth multiplication
            if (valid_reg[0]) begin
                for (i = 0; i < 8; i = i + 1) begin
                    case ({Y_reg[2*i+1], Y_reg[2*i], (i == 0) ? 1'b0 : Y_reg[2*i-1]})
                        3'b000, 3'b111: partial_products[i] <= 32'd0;
                        3'b001, 3'b010: partial_products[i] <= {{16{X_reg[15]}}, X_reg} >> (2*i);
                        3'b011: partial_products[i] <= {{16{X_reg[15]}}, X_reg} >> (2*i + 1);
                        3'b100: partial_products[i] <= -({{16{X_reg[15]}}, X_reg} >> (2*i + 1));
                        3'b101, 3'b110: partial_products[i] <= -({{16{X_reg[15]}}, X_reg} >> (2*i));
                        default: partial_products[i] <= 32'd0;
                    endcase
                end
                valid_reg[1] <= 1; // State 1 done, mark State 2 as ready
                valid_reg[0] <= 0; // Reset state 1 active flag
            end 
            else
              valid_reg[1] <= 0; // State 1 done, mark State 2 as ready

            // State 3: Partial Summation
            if (valid_reg[1]) begin 
                s1 <= partial_products[0] + partial_products[1] + partial_products[2];
                s2 <= partial_products[3] + partial_products[4] + partial_products[5];

                valid_reg[2] <= 1; // State 3 done, mark State 4 as ready
                valid_reg[1] <= 0; // Clear state 2 active flag
            end 
            else
              valid_reg[2] <= 0; // State 3 done, mark State 4 as ready 

            // State 4: Sum of Sums
            if (valid_reg[2]) begin 
                s3 <= s1 + s2;
                s4 <= partial_products[6] + partial_products[7];

                valid_reg[3] <= 1; // State 4 done, mark State 5 as ready
                valid_reg[2] <= 0; // Clear state 3 active flag
            end 
            else
              valid_reg[3] <= 0; // State 4 done, mark State 5 as ready


            // State 5: Final Result
            if (valid_reg[3]) begin
                result <= s3 + s4;
                done <= 1;  // Output done signal
                valid_reg[3] <= 0; // Reset state 5 active flag after result computation
            end 
            else
            begin
              result <= 0;
              done <= 1'b0; 
            end 

        end
    end

endmodule

