module moving_average(
    input wire clk,
    input wire reset,
    input  wire [11 : 0] data_in,
    output wire [11 : 0] data_out
);

reg [11 : 0] memory [7 : 0];
reg [14 : 0] sum;
reg [2  : 0] write_address;
wire [2 : 0] next_address;
reg [11 : 0] read_data;

assign next_address=write_address + 1'b1;
assign data_out=sum[14 : 3];

    // write current input to memory
    integer i;
    always @(posedge clk ) begin
        if (reset == 1'b1) begin
            for (i = 0 ;i < 8 ; i = i + 1 ) begin
                memory[i]<='h0;
            end
        end else begin
            memory[write_address]<=data_in;
        end
    end

    // read the oldest element written to memory
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            read_data<='h0;
        end else begin
            read_data<=memory[next_address];
        end
    end

    // increase the write address to move onto the next data
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            write_address<='h0;
        end else begin
            write_address<=write_address + 1'b1;
        end
    end

    // calculate sum by adding the latest data to the sum and substracting the oldest data
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            sum<='h0;
        end else begin
            sum<=sum+data_in-read_data;
        end
    end

endmodule

output.rtl/moving_average.v:
module moving_average(
    input wire clk,
    input wire reset,
    input wire enable,
    input  wire [11:0] data_in,
    output wire [11:0] data_out
);

    reg [11:0] memory [7:0];
    reg [14:0] sum;
    reg [2:0] write_address;
    wire [2:0] next_address;
    reg [11:0] read_data;

    assign next_address = write_address + 1'b1;
    assign data_out = sum[14:3];

    // Write current input to memory only when enable is high.
    integer i;
    always @(posedge clk) begin
        if (reset == 1'b1) begin
            for (i = 0; i < 8; i = i + 1) begin
                memory[i] <= 'h0;
            end
        end else if (enable == 1'b1) begin
            memory[write_address] <= data_in;
        end
    end

    // Read the oldest element from memory only when enable is high.
    always @(posedge clk) begin
        if (reset == 1'b1) begin
            read_data <= 'h0;
        end else if (enable == 1'b1) begin
            read_data <= memory[next_address];
        end
    end

    // Increment the write address only when enable is high.
    always @(posedge clk) begin
        if (reset == 1'b1) begin
            write_address <= 'h0;
        end else if (enable == 1'b1) begin
            write_address <= write_address + 1'b1;
        end
    end

    // Update the sum only when enable is high.
    always @(posedge clk) begin
        if (reset == 1'b1) begin
            sum <= 'h0;
        end else if (enable == 1'b1) begin
            sum <= sum + data_in - read_data;
        end
    end

endmodule

output.rtl/mux_synch.sv:
module mux_synch (
    input  [7:0] data_in,   // asynchronous data input
    input        req,       // indicates that data is available at data_in
    input        dst_clk,   // destination clock (synchronization occurs on rising edge)
    input        src_clk,   // source clock (not used in dst_clk domain operations)
    input        nrst,      // active-low asynchronous reset
    output reg [7:0] data_out // synchronized version of data_in in the destination domain
);

    // Two-flop synchronizer for the req signal from the source domain.
    reg req_sync0, req_sync1;
    always_ff @(posedge dst_clk or negedge nrst) begin
        if (!nrst) begin
            req_sync0 <= 1'b0;
            req_sync1 <= 1'b0;
        end else begin
            req_sync0 <= req;
            req_sync1 <= req_sync0;
        end
    end

    // Pipeline registers to capture and delay the data_in signal.
    // The multiplexer selects between the new data_in (when req_sync1 is high)
    // and the previous value (when no new data is available).
    // This three-stage pipeline ensures that the input data remains stable for at least three dst_clk cycles.
    reg [7:0] data_pipe0, data_pipe1, data_pipe2;
    always_ff @(posedge dst_clk or negedge nrst) begin
        if (!nrst) begin
            data_pipe0 <= 8'b0;
            data_pipe1 <= 8'b0;
            data_pipe2 <= 8'b0;
        end else begin
            // If a synchronized request is detected, load the new data_in.
            data_pipe0 <= (req_sync1) ? data_in : data_pipe0;
            data_pipe1 <= data_pipe0;
            data_pipe2 <= data_pipe1;
        end
    end

    // Drive the output from the last stage of the pipeline.
    always_comb begin
        data_out = data_pipe2;
    end

endmodule

module nff (
    input  d_in,       // asynchronous signal to be synchronized
    input  dst_clk,    // destination clock
    input  rst,        // active-low asynchronous reset
    output reg syncd   // synchronized output (2-clock-cycle delayed version of d_in)
);

    // Two-flop synchronizer for d_in to mitigate metastability.
    reg d_in_sync;
    always_ff @(posedge dst_clk or negedge rst) begin
        if (!rst) begin
            d_in_sync <= 1'b0;
            syncd     <= 1'b0;
        end else begin
            d_in_sync <= d_in;
            syncd     <= d_in_sync;
        end
    end

endmodule

output.rtl/nbit_swizzling.sv:
module nbit_swizzling #(parameter DATA_WIDTH = 64) (
    input  logic [DATA_WIDTH-1:0] data_in,
    input  logic [1:0]            sel,
    output logic [DATA_WIDTH-1:0] data_out
);

    // Function to reverse the bits of a vector.
    // The function works for any input width.
    function automatic [N-1:0] reverse_segment (input [N-1:0] data);
      integer i;
      begin
        for(i = 0; i < $bits(data); i = i + 1) begin
          reverse_segment[i] = data[$bits(data)-1-i];
        end
      end
    endfunction

    // Combinational logic for selective bit reversal.
    always_comb begin
      case(sel)
        2'd0: begin
                 // Reverse the entire input.
                 data_out = reverse_segment(data_in);
               end
        2'd1: begin
                 // Divide into two halves and reverse each half individually.
                 integer half_width = DATA_WIDTH / 2;
                 logic [half_width-1:0] rev_upper, rev_lower;
                 rev_upper = reverse_segment(data_in[DATA_WIDTH-1:DATA_WIDTH/2]);
                 rev_lower = reverse_segment(data_in[DATA_WIDTH/2-1:0]);
                 data_out = {rev_upper, rev_lower};
               end
        2'd2: begin
                 // Divide into four equal sections and reverse each section.
                 integer quarter_width = DATA_WIDTH / 4;
                 logic [quarter_width-1:0] seg0, seg1, seg2, seg3;
                 seg0   = reverse_segment(data_in[DATA_WIDTH-1:DATA_WIDTH - quarter_width]);
                 seg1   = reverse_segment(data_in[DATA_WIDTH - quarter_width - 1: DATA_WIDTH - 2*quarter_width]);
                 seg2   = reverse_segment(data_in[DATA_WIDTH - 2*quarter_width - 1: DATA_WIDTH - 3*quarter_width]);
                 seg3   = reverse_segment(data_in[DATA_WIDTH - 3*quarter_width - 1: 0]);
                 data_out = {seg0, seg1, seg2, seg3};
               end
        2'd3: begin
                 // Divide into eight equal sections and reverse each section.
                 integer eighth_width = DATA_WIDTH / 8;
                 logic [eighth_width-1:0] seg0, seg1, seg2, seg3, seg4, seg5, seg6, seg7;
                 seg0   = reverse_segment(data_in[DATA_WIDTH-1: DATA_WIDTH - eighth_width]);
                 seg1   = reverse_segment(data_in[DATA_WIDTH - eighth_width - 1: DATA_WIDTH - 2*eighth_width]);
                 seg2   = reverse_segment(data_in[DATA_WIDTH - 2*eighth_width - 1: DATA_WIDTH - 3*eighth_width]);
                 seg3   = reverse_segment(data_in[DATA_WIDTH - 3*eighth_width - 1: DATA_WIDTH - 4*eighth_width]);
                 seg4   = reverse_segment(data_in[DATA_WIDTH - 4*eighth_width - 1: DATA_WIDTH - 5*eighth_width]);
                 seg5   = reverse_segment(data_in[DATA_WIDTH - 5*eighth_width - 1: DATA_WIDTH - 6*eighth_width]);
                 seg6   = reverse_segment(data_in[DATA_WIDTH - 6*eighth_width - 1: DATA_WIDTH - 7*eighth_width]);
                 seg7   = reverse_segment(data_in[DATA_WIDTH - 7*eighth_width - 1: 0]);
                 data_out = {seg0, seg1, seg2, seg3, seg4, seg5, seg6, seg7};
               end
        default: begin
                    // Default: pass the input directly.
                    data_out = data_in;
                  end
      endcase
    end

endmodule

