output.rtl/nbit_swizzling.sv:
module nbit_swizzling #(parameter DATA_WIDTH = 64)(
    input  [DATA_WIDTH-1:0] data_in,
    input  [1:0]             sel,
    output reg [DATA_WIDTH:0] data_out,
    output reg [DATA_WIDTH + PARITY_BITS - 1:0] ecc_out
);

    // Calculate number of parity bits
    localparam int PARITY_BITS = $clog2(DATA_WIDTH + $clog2(DATA_WIDTH) + 1);
    localparam int TOTAL_BITS  = DATA_WIDTH + PARITY_BITS;

    // Function to check if a number is a power of two (1-indexed check)
    function automatic bit is_power_of_two(input int x);
        is_power_of_two = (x != 0) && ((x & (x-1)) == 0);
    endfunction

    integer i;
    wire parity_bit;

    // Calculate parity for data_in (used in swizzling)
    assign parity_bit = ^data_in;

    // Swizzling logic for data_out based on sel
    always @(*) begin
        case(sel)
            2'b00: begin
                for (i = 0; i < DATA_WIDTH; i = i + 1) begin
                    data_out[i] = data_in[DATA_WIDTH-1-i];
                end
                data_out[DATA_WIDTH] = parity_bit;
            end

            2'b01: begin
                for (i = 0; i < DATA_WIDTH/2; i = i + 1) begin
                    data_out[i]                = data_in[DATA_WIDTH/2-1-i];
                    data_out[DATA_WIDTH/2 + i] = data_in[DATA_WIDTH-1-i];
                end
                data_out[DATA_WIDTH] = parity_bit;
            end

            2'b10: begin
                for (i = 0; i < DATA_WIDTH/4; i = i + 1) begin
                    data_out[i]                  = data_in[DATA_WIDTH/4-1-i];
                    data_out[DATA_WIDTH/4 + i]   = data_in[DATA_WIDTH/2-1-i];
                    data_out[DATA_WIDTH/2 + i]   = data_in[3*DATA_WIDTH/4-1-i];
                    data_out[3*DATA_WIDTH/4 + i] = data_in[DATA_WIDTH-1-i];
                end
                data_out[DATA_WIDTH] = parity_bit;
            end

            2'b11: begin
                for (i = 0; i < DATA_WIDTH/8; i = i + 1) begin
                    data_out[i]                  = data_in[DATA_WIDTH/8-1-i];
                    data_out[DATA_WIDTH/8 + i]   = data_in[DATA_WIDTH/4-1-i];
                    data_out[DATA_WIDTH/4 + i]   = data_in[3*DATA_WIDTH/8-1-i];
                    data_out[3*DATA_WIDTH/8 + i] = data_in[DATA_WIDTH/2-1-i];
                    data_out[DATA_WIDTH/2 + i]   = data_in[5*DATA_WIDTH/8-1-i];
                    data_out[5*DATA_WIDTH/8 + i] = data_in[3*DATA_WIDTH/4-1-i];
                    data_out[3*DATA_WIDTH/4 + i] = data_in[7*DATA_WIDTH/8-1-i];
                    data_out[7*DATA_WIDTH/8 + i] = data_in[DATA_WIDTH-1-i];
                end
                data_out[DATA_WIDTH] = parity_bit;
            end
            default: begin
                data_out = data_in;
                data_out[DATA_WIDTH] = parity_bit;
            end
        endcase
    end

    // Hamming ECC Generation for ecc_out
    // The encoded output (ecc_out) is formed by inserting parity bits at positions
    // that are powers of two and filling the remaining positions with bits from data_in.
    always @(*) begin
        integer j, k, data_count;
        reg [TOTAL_BITS-1:0] temp;
        data_count = 0;

        // Place data bits into non-parity positions
        for (j = 0; j < TOTAL_BITS; j = j + 1) begin
            if (is_power_of_two(j+1)) begin
                // Positions that are powers of two will hold parity bits (initialized to 0)
                temp[j] = 1'b0;
            end else begin
                temp[j] = data_in[data_count];
                data_count = data_count + 1;
            end
        end

        // Calculate and insert parity bits
        // For each parity position (1-indexed positions that are powers of two)
        for (k = 0; k < PARITY_BITS; k = k + 1) begin
            bit parity = 1'b0;
            int p = (1 << k); // p is the parity position (1-indexed)
            // p_index in 0-indexed numbering is p - 1
            for (j = 0; j < TOTAL_BITS; j = j + 1) begin
                // Include bit at position j if its (j+1) has the kth bit set,
                // but skip the parity bit position itself.
                if (((j+1) & p) != 0 && (j+1 != p)) begin
                    parity = parity ^ temp[j];
                end
            end
            temp[p - 1] = parity;
        end

        ecc_out = temp;
    end

endmodule

output.rtl/neuromorphic_array.sv:
module neuromorphic_array #(
    parameter NEURONS = 8,       // Number of neurons
    parameter INPUTS  = 8,        // Number of inputs
    parameter OUTPUTS = 8         // Number of outputs
) (
    input  logic [7:0] ui_in,       // Control input (ui_in[0] used for update)
    input  logic [7:0] uio_in,      // Input data
    output logic [7:0] uo_out,     // Output data from the last neuron
    input  logic clk,              // Clock signal
    input  logic rst_n             // Active-low reset
);
    // Internal wires for neuron outputs
    logic [7:0] neuron_outputs [0:NEURONS-1];

    // Instantiate the neurons in a generate loop
    genvar i;
    generate
        for (i = 0; i < NEURONS; i = i + 1) begin : neuron_inst
            if (i == 0) begin
                // First neuron: input is uio_in
                single_neuron_dut neuron (
                    .clk(clk),
                    .rst_n(rst_n),
                    .control(ui_in[0]),
                    .seq_in(uio_in),
                    .seq_out(neuron_outputs[i])
                );
            end else begin
                // Subsequent neurons: input is the output of the previous neuron
                single_neuron_dut neuron (
                    .clk(clk),
                    .rst_n(rst_n),
                    .control(ui_in[0]),
                    .seq_in(neuron_outputs[i-1]),
                    .seq_out(neuron_outputs[i])
                );
            end
        end
    endgenerate

    // Final output is taken from the last neuron in the array
    assign uo_out = neuron_outputs[NEURONS-1];

endmodule

module single_neuron_dut (
    input  logic clk,
    input  logic rst_n,
    input  logic control,        // Control signal: high enables state update
    input  logic [7:0] seq_in,   // Input data for updating state
    output logic [7:0] seq_out   // Output of the neuron (current state)
);
    // Internal state register
    logic [7:0] state;

    // Sequential process: on reset, clear state; otherwise update based on control signal
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= 8'b0;
        end else begin
            if (control)
                state <= seq_in;
            else
                state <= state;
        end
    end

    // Assign the current state to the output
    assign seq_out = state;

endmodule

input.rtl/one_hot_gen.sv:
module one_hot_gen #(
    parameter NS_A = 'd8,
    parameter NS_B = 'd4
) (
    input  logic                 clk,
    input  logic                 rst_async_n,
    input  logic [1:0]           i_config,
    input  logic                 i_start,
    input  logic                 o_ready,
    output logic [NS_A+NS_B-1:0] o_address_one_hot
);

typedef enum logic [2:0] {IDLE = 2'b00, REGION_A = 2'b01, REGION_B = 2'b10} state_t;

// ----------------------------------------
// - Wires/Registers creation
// ----------------------------------------
state_t state_ff, state_nx;
logic [NS_A-1:0] region_A_ff, region_A_nx;
logic [NS_B-1:0] region_B_ff, region_B_nx;
logic A_to_B, B_to_A, only_A, only_B;

// Input register
logic [2:0] config_ff;

// ----------------------------------------
// - Wire connections
// ----------------------------------------

// Region change flags
assign A_to_B = ( config_ff[1] & ~config_ff[0]);
assign B_to_A = ( config_ff[1] &  config_ff[0]);
assign only_A = (~config_ff[0] & ~config_ff[0]);
assign only_B = (~config_ff[0] &  config_ff[0]);

// Output assignment (Region A concatenated with Region B)
assign o_address_one_hot = {region_A_ff, region_B_ff};

// ----------------------------------------
// - Registers
// ----------------------------------------

always_ff @(posedge clk or negedge rst_async_n) begin : input_register
    if(~rst_async_n) begin
        config_ff <= 0;
    end else begin
        if(i_start && state_ff == IDLE) begin
            config_ff <= i_config;
        end
    end
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        o_ready <= 1;
        state_ff <= IDLE;
        region_A_ff <= {NS_A{1'b0}};
        region_B_ff <= {NS_B{1'b0}};
    end else begin
        o_ready <= (state_nx == IDLE);
        state_ff <= state_nx;
        region_A_ff <= region_A_nx;
        region_B_ff <= region_B_nx;
    end
end

// ----------------------------------------
// - One-hot address generation
// ----------------------------------------

always_comb begin : drive_regions
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                region_A_nx[NS_A] = (~i_config[0]);
                region_B_nx[NS_B] = (i_config[0]);
            end else begin
                region_A_nx[NS_A] = 1'b0;
                region_B_nx[NS_B] = 1'b0;
            end

            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_A: begin
            region_A_nx = region_A_ff >> 1;

            if(region_A_ff[0]) begin
                region_B_nx[NS_B] = A_to_B;
            end else begin
                region_B_nx[NS_B] = 1'b0;
            end
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                region_A_nx[NS_A] = B_to_A;
            end else begin
                region_A_nx[NS_A] = 1'b0;
            end
            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};

            region_B_nx = region_B_ff >> 1;
        end
        default: begin
            region_A_nx = {NS_A{1'b0}};
            region_B_nx = {NS_B{1'b0}};
        end
    endcase
end

// ----------------------------------------
// - FSM update
// ----------------------------------------

always_comb begin : update_state
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                if(i_config[0]) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = REGION_A;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        REGION_A: begin
            if(region_A_ff[0]) begin
                if(A_to_B) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_A;
            end
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                if(B_to_A) begin
                    state_nx = REGION_A;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_B;
            end
        end
        default: begin
            state_nx = IDLE;
        end
    endcase
end

endmodule : one_hot_gen

