module dual_port_memory (
    input logic clk,
    input logic we,
    input logic [7:0] write_addr,
    input logic [7:0] din,
    input logic [7:0] read_addr,
    output logic [7:0] dout
);

    logic [7:0] mem [255:0];

    always_ff @(posedge clk) begin
        if (we) begin
            mem[write_addr] <= din;
        end
    end

    assign dout = mem[read_addr];
endmodule

output.rtl/ping_pong_buffer.sv:
module ping_pong_buffer (
    input logic clk,
    input logic rst_n,
    input logic write_enable,
    input logic read_enable,
    input logic [7:0] data_in,
    output logic [7:0] data_out,
    output logic buffer_full,
    output logic buffer_empty,
    output reg buffer_select
);

    localparam DEPTH = 256; 
    localparam ADDR_WIDTH = 8; 

    // Pointer registers for each memory bank
    logic [ADDR_WIDTH-1:0] wr_ptr0, rd_ptr0;
    logic [ADDR_WIDTH-1:0] wr_ptr1, rd_ptr1;

    // Memory interface signals
    logic we0, we1;
    logic [ADDR_WIDTH-1:0] write_addr0, write_addr1;
    logic [7:0] din0, din1;
    logic [ADDR_WIDTH-1:0] read_addr0, read_addr1;
    logic [7:0] mem0_dout, mem1_dout;

    // Instantiate dual_port_memory modules
    dual_port_memory memory0 (
        .clk(clk),
        .we(we0),
        .write_addr(write_addr0),
        .din(din0),
        .read_addr(read_addr0),
        .dout(mem0_dout)
    );

    dual_port_memory memory1 (
        .clk(clk),
        .we(we1),
        .write_addr(write_addr1),
        .din(din1),
        .read_addr(read_addr1),
        .dout(mem1_dout)
    );

    // Output assignment: data_out comes from the inactive bank (the one not currently being written)
    assign data_out = (buffer_select == 0) ? mem1_dout : mem0_dout;

    // Main sequential block for pointer management and control logic
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_ptr0 <= 0;
            rd_ptr0 <= 0;
            wr_ptr1 <= 0;
            rd_ptr1 <= 0;
            buffer_select <= 0;
            buffer_full <= 0;
            buffer_empty <= 1;
        end else begin
            if (buffer_select == 0) begin
                // Active bank is 0 (writing), inactive bank is 1 (reading)
                // Write operation: only write if active bank is not full
                if (write_enable && (wr_ptr0 != (rd_ptr0 + 1) % DEPTH)) begin
                    wr_ptr0 <= wr_ptr0 + 1;
                end

                // Read operation from inactive bank if not empty
                if (read_enable && (rd_ptr1 != wr_ptr1)) begin
                    rd_ptr1 <= rd_ptr1 + 1;
                end

                // Update buffer status for active bank 0
                buffer_full <= (wr_ptr0 == (rd_ptr0 + 1) % DEPTH);
                buffer_empty <= (rd_ptr1 == wr_ptr1);

                // Toggle bank selection when either bank reaches end of buffer
                if (wr_ptr0 == DEPTH - 1 || rd_ptr1 == DEPTH - 1) begin
                    buffer_select <= 1;
                end
            end else begin
                // Active bank is 1 (writing), inactive bank is 0 (reading)
                if (write_enable && (wr_ptr1 != (rd_ptr1 + 1) % DEPTH)) begin
                    wr_ptr1 <= wr_ptr1 + 1;
                end

                if (read_enable && (rd_ptr0 != wr_ptr0)) begin
                    rd_ptr0 <= rd_ptr0 + 1;
                end

                buffer_full <= (wr_ptr1 == (rd_ptr1 + 1) % DEPTH);
                buffer_empty <= (rd_ptr0 == wr_ptr0);

                if (wr_ptr1 == DEPTH - 1 || rd_ptr0 == DEPTH - 1) begin
                    buffer_select <= 0;
                end
            end
        end
    end

    // Drive memory interface signals based on current bank selection
    always_comb begin
        if (buffer_select == 0) begin
            // Active bank: memory0 for writing, memory1 for reading
            we0 = write_enable && (wr_ptr0 != (rd_ptr0 + 1) % DEPTH);
            write_addr0 = wr_ptr0;
            din0 = data_in;
            read_addr1 = rd_ptr1;
            we1 = 1'b0;
        end else begin
            // Active bank: memory1 for writing, memory0 for reading
            we1 = write_enable && (wr_ptr1 != (rd_ptr1 + 1) % DEPTH);
            write_addr1 = wr_ptr1;
            din1 = data_in;
            read_addr0 = rd_ptr0;
            we0 = 1'b0;
        end
    end

endmodule

output.rtl/pipeline_mac.sv:
module pipeline_mac #(
    parameter DWIDTH = 16,  // Bit width for multiplicand and multiplier
    parameter N      = 4    // Number of data points to accumulate over
) (
    input logic clk,                                // Clock signal
    input logic rstn,                               // Active low reset signal
    input logic [DWIDTH-1:0] multiplicand,          // Input multiplicand
    input logic [DWIDTH-1:0] multiplier,            // Input multiplier
    input logic valid_i,                            // Input valid signal
    output logic [DWIDTH_ACCUMULATOR-1:0] result,   // Accumulated result output
    output logic valid_out                         // Output valid signal, indicates when result is ready
);
  // ----------------------------------------
  // - Local parameter definition
  // ----------------------------------------
  localparam DWIDTH_ACCUMULATOR = 2*DWIDTH + $clog2(N);

  // ----------------------------------------
  // - Interface Definitions
  // ----------------------------------------
  // Already defined above.

  // ----------------------------------------
  // - Internal signals
  // ----------------------------------------
  logic [DWIDTH_ACCUMULATOR-1:0] mult_result_reg;    // Register to store intermediate multiplication result
  logic [DWIDTH_ACCUMULATOR-1:0] accumulation_reg;   // Register to store accumulated result
  logic [$clog2(N):0] counter_reg;                   // Register to hold the value of the counter
  logic valid_out_s0, valid_out_s1, valid_out_s2;      // Intermediate Signals for valid output pipeline

  // ----------------------------------------
  // - Procedural blocks
  // ----------------------------------------

  // Stage 1 of the pipeline: Perform multiplication
  always @(posedge clk or negedge rstn) begin
     if (!rstn)
         mult_result_reg <= '0;
     else if (valid_i)
         mult_result_reg <= multiplicand * multiplier;
     // else: hold state
  end

  // Stage 2 of the pipeline: Accumulation logic
  always @(posedge clk or negedge rstn) begin
     if (!rstn)
         accumulation_reg <= '0;
     else if (valid_out_s1)
         accumulation_reg <= '0; // Reset accumulator after N valid inputs
     else if (valid_i)
         accumulation_reg <= accumulation_reg + mult_result_reg;
     // else: hold state
  end

  // N-bit counter to track the number of accumulations
  always @(posedge clk or negedge rstn) begin
     if (!rstn)
         counter_reg <= '0;
     else if (valid_out_s1)
         counter_reg <= '0; // Reset counter after output
     else if (valid_i)
         counter_reg <= counter_reg + 1;
     // else: hold state
  end

  // Register valid output for 2-stage pipeline
  always @(posedge clk or negedge rstn) begin
     if (!rstn) begin
         valid_out_s0 <= '0;
         valid_out_s1 <= '0;
         valid_out_s2 <= '0;
     end else begin
         valid_out_s0 <= (counter_reg == N-1); // Assert when N-1 valid inputs have been processed
         valid_out_s1 <= valid_out_s0;
         valid_out_s2 <= valid_out_s1;
     end
  end

  // ----------------------------------------
  // - Combinational Assignments
  // ----------------------------------------
  // The following assignments generate the final output signals.
  assign result = accumulation_reg;
  assign valid_out = valid_out_s1 & ~valid_out_s2; // Pulse valid_out when rising edge of valid_out_s1

endmodule

output.rtl/piso_8bit.sv:
module piso_8bit (
    input  logic clk,
    input  logic rst,
    output logic serial_out
);

  // Internal 8-bit register holding the current pattern
  logic [7:0] tmp;
  // 3-bit counter to track the number of bits shifted out (0 to 7)
  logic [2:0] bit_counter;

  always_ff @(posedge clk or negedge rst) begin
    if (!rst) begin
      // Asynchronous active LOW reset: initialize tmp to 8'b0000_0001 and clear counter/output
      tmp         <= 8'b0000_0001;
      bit_counter <= 3'b000;
      serial_out  <= 1'b0;
    end else begin
      if (bit_counter < 3'b111) begin
        // Output the MSB of tmp and increment the counter
        serial_out  <= tmp[7];
        bit_counter <= bit_counter + 1;
      end else begin
        // After 8 bits have been shifted, output the MSB of tmp,
        // increment tmp by 1 (modulo 256), and reset the counter.
        serial_out  <= tmp[7];
        tmp         <= tmp + 1;  // 1111_1111 + 1 wraps to 0000_0000 automatically
        bit_counter <= 3'b000;
      end
    end
  end

endmodule

output.rtl/pkt_detector.sv:
module pkt_detector #(
    parameter PKT_CNT_WIDTH = 4
) (
    input  logic                       reset,
    input  logic                       clk,
    input  logic [7:0]                 data_in,
    input  logic                       data_k_flag,
    output logic [PKT_CNT_WIDTH - 1:0] pkt_count,
    output logic [159:0]               pkt_data,
    output logic                       mem_read_detected,
    output logic                       mem_write_detected,
    output logic                       io_read_detected,
    output logic                       io_write_detected,
    output logic                       cfg_read0_detected,
    output logic                       cfg_write0_detected,
    output logic                       cfg_read1_detected,
    output logic                       cfg_write1_detected,
    output logic                       completion_detected,
    output logic                       completion_data_detected,
    output logic                       error_detected
);

    localparam [7:0] START_SYMBOL = 8'hFB;
    localparam [7:0] END_SYMBOL   = 8'hFD;
    localparam       PKT_BYTES    = 20;

    typedef enum logic [1:0] {
        S_IDLE     = 2'b00,
        S_ACTIVE   = 2'b01,
        S_WAIT_END = 2'b10,
        S_ERROR    = 2'b11
    } state_t;

    state_t curr_state, nxt_state;

    logic [7:0]    byte_cnt;
    logic [159:0]  pkt_reg;

    // State Register
    always_ff @(posedge clk or negedge reset) begin
        if (!reset)
            curr_state <= S_IDLE;
        else
            curr_state <= nxt_state;
    end

    // Next State Logic
    always_comb begin
        case (curr_state)
            S_IDLE: 
                if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1))
                    nxt_state = S_ACTIVE;
                else
                    nxt_state = S_IDLE;

            S_ACTIVE: 
                if (byte_cnt == PKT_BYTES)
                    nxt_state = S_WAIT_END;
                else
                    nxt_state = S_ACTIVE;

            S_WAIT_END: 
                if (pkt_reg[159:152] == END_SYMBOL)
                    nxt_state = S_IDLE;
                else
                    nxt_state = S_ERROR;

            S_ERROR: 
                if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1))
                    nxt_state = S_ACTIVE;
                else
                    nxt_state = S_ERROR;

            default: nxt_state = S_IDLE;
        endcase
    end

    // Sequential logic: update registers, accumulate packet data, update counters and flags
    always_ff @(posedge clk or negedge reset) begin
        if (!reset) begin
            byte_cnt            <= 0;
            pkt_reg             <= 0;
            pkt_count           <= 0;
            pkt_data            <= 0;
            mem_read_detected   <= 0;
            mem_write_detected  <= 0;
            io_read_detected    <= 0;
            io_write_detected   <= 0;
            cfg_read0_detected  <= 0;
            cfg_write0_detected <= 0;
            cfg_read1_detected  <= 0;
            cfg_write1_detected <= 0;
            completion_detected <= 0;
            completion_data_detected <= 0;
            error_detected      <= 0;
        end
        else begin
            case (curr_state)
                S_IDLE: begin
                    // Wait for start symbol; reset accumulation registers
                    byte_cnt    <= 0;
                    pkt_reg     <= 0;
                end

                S_ACTIVE: begin
                    if (data_k_flag) begin
                        // Shift in new byte into packet register
                        pkt_reg <= {pkt_reg[151:0], data_in};
                        // Increment byte counter; reset when reaching PKT_BYTES
                        if (byte_cnt == PKT_BYTES - 1)
                            byte_cnt <= 0;
                        else
                            byte_cnt <= byte_cnt + 1;
                    end
                end

                S_WAIT_END: begin
                    if (pkt_reg[159:152] == END_SYMBOL) begin
                        // Valid packet: update packet counter and data
                        pkt_count  <= pkt_count + 1;
                        pkt_data   <= pkt_reg;
                        // Decode the packet header (first byte) to set detection flags
                        case (pkt_reg[31:24])
                            8'h01: mem_read_detected   <= 1;
                            8'h02: mem_write_detected  <= 1;
                            8'h03: io_read_detected    <= 1;
                            8'h04: io_write_detected   <= 1;
                            8'h05: cfg_read0_detected  <= 1;
                            8'h06: cfg_write0_detected <= 1;
                            8'h07: cfg_read1_detected  <= 1;
                            8'h08: cfg_write1_detected <= 1;
                            8'h09: completion_detected <= 1;
                            8'h0A: completion_data_detected <= 1;
                            default: begin
                                // No specific flag set for unrecognized header
                            end
                        endcase
                    end
                    else begin
                        // Invalid packet sequence detected
                        error_detected <= 1;
                    end
                    // Reset accumulation registers for next packet
                    pkt_reg    <= 0;
                    byte_cnt   <= 0;
                end

                S_ERROR: begin
                    // Remain in error state until recovery; assert error flag
                    error_detected <= 1;
                    // Clear detection flags and reset accumulation registers
                    mem_read_detected   <= 0;
                    mem_write_detected  <= 0;
                    io_read_detected    <= 0;
                    io_write_detected   <= 0;
                    cfg_read0_detected  <= 0;
                    cfg_write0_detected <= 0;
                    cfg_read1_detected  <= 0;
                    cfg_write1_detected <= 0;
                    completion_detected <= 0;
                    completion_data_detected <= 0;
                    pkt_reg    <= 0;
                    byte_cnt   <= 0;
                end

                default: begin
                    // Default case: do nothing
                end
            endcase
        end
    end

endmodule

output.rtl/cvdp_prbs_gen.sv:
module implements a configurable PRBS generator/checker.
// In generator mode (CHECK_MODE==0), it updates an internal LFSR (of width POLY_LENGTH)
// using the feedback computed as the XOR of the bit at position POLY_TAP and the MSB (bit POLY_LENGTH-1).
// The generated PRBS pattern is output on the lower WIDTH bits of data_out.
//
// In checker mode (CHECK_MODE==1), the module performs WIDTH iterative LFSR updates
// starting from the current state of the PRBS register. For each iteration i (0 <= i < WIDTH):
//   - It computes the expected feedback bit using the current state.
//   - It compares the expected bit with the corresponding bit of data_in.
//   - It updates the internal register with the feedback.
// The error for each bit is the XOR of the expected bit and the corresponding data_in bit.
// The resulting error vector is assigned to data_out (a nonzero value indicates a mismatch).
//
// On reset (rst asserted), the PRBS register is initialized to all ones and data_out is set to all ones.
//
module cvdp_prbs_gen #
(
  parameter int CHECK_MODE = 0,       // 0: Generator mode; 1: Checker mode
  parameter int POLY_LENGTH = 31,      // Length of the LFSR (number of stages)
  parameter int POLY_TAP    = 3,       // Tap position (must be less than POLY_LENGTH)
  parameter int WIDTH        = 16      // Width of data_in and data_out buses
)
(
  input  logic         clk,
  input  logic         rst,
  input  logic [WIDTH-1:0] data_in,  // In generator mode, expected to be 0
  output logic [WIDTH-1:0] data_out  // In generator mode: generated PRBS pattern; in checker mode: error bits
);

  // Internal PRBS register (LFSR) of width POLY_LENGTH.
  logic [POLY_LENGTH-1:0] prbs_reg;

  always_ff @(posedge clk) begin
    if (rst) begin
      // On reset, initialize the PRBS register to all ones.
      prbs_reg <= '1;
      data_out <= '1;
    end
    else begin
      if (CHECK_MODE == 0) begin
        // ------------------------------
        // Generator Mode
        // ------------------------------
        //
        // Compute the feedback bit as the XOR of the tap bit and the MSB.
        // Note: MSB is at index POLY_LENGTH-1 (assuming bit 0 is LSB).
        bit fb = prbs_reg[POLY_TAP] ^ prbs_reg[POLY_LENGTH-1];

        // Update the PRBS register by shifting right and inserting fb at MSB.
        prbs_reg <= { fb, prbs_reg[POLY_LENGTH-1:1] };

        // Output the lower WIDTH bits of the PRBS register.
        data_out <= prbs_reg[WIDTH-1:0];

      end else begin
        // ------------------------------
        // Checker Mode
        // ------------------------------
        //
        // In checker mode, we perform WIDTH iterative updates of the LFSR.
        // For each iteration i (0 <= i < WIDTH):
        //   - Compute the expected feedback bit from the current state.
        //   - Compare it with data_in[i] (XOR yields 1 if there is a mismatch).
        //   - Update the internal register.
        // Finally, assign the collected error bits to data_out.
        //
        // Note: This design updates the LFSR WIDTH times per clock cycle.
        // It is assumed that POLY_LENGTH >= WIDTH.

        logic [POLY_LENGTH-1:0] temp_reg;
        logic [WIDTH-1:0]       error;
        integer i;

        // Start with the current state of the PRBS register.
        temp_reg = prbs_reg;

        // Iterate over each bit position of the data bus.
        for (i = 0; i < WIDTH; i++) begin
          // Compute feedback from the current state.
          bit fb = temp_reg[POLY_TAP] ^ temp_reg[POLY_LENGTH-1];
          // Compare the expected feedback bit with the corresponding bit of data_in.
          error[i] = data_in[i] ^ fb;
          // Update the temporary register for the next iteration.
          temp_reg = { fb, temp_reg[POLY_LENGTH-1:1] };
        end

        // Update the main PRBS register with the final state.
        prbs_reg <= temp_reg;
        // Output the error bits.
        data_out <= error;
      end
    end
  end

endmodule

