output.rtl/sdram_controller.sv:
module sdram_controller (
    input  logic         clk,
    input  logic         reset,
    input  logic [23:0]  addr,
    input  logic [15:0]  data_in,
    output logic [15:0]  data_out,
    input  logic         read,
    input  logic         write,
    output logic         sdram_clk,
    output logic         sdram_cke,
    output logic         sdram_cs,
    output logic         sdram_ras,
    output logic         sdram_cas,
    output logic         sdram_we,
    output logic [23:0]  sdram_addr,
    output logic [1:0]   sdram_ba,
    input  logic [15:0]  sdram_dq,
    output logic [15:0]  dq_out
);

   // FSM state encoding
   typedef enum logic [2:0] {
      INIT     = 3'd0,
      IDLE     = 3'd1,
      ACTIVATE = 3'd2,
      READ     = 3'd3,
      WRITE    = 3'd4,
      REFRESH  = 3'd5
   } state_t;

   state_t state, next_state;

   // Counters for initialization and idle auto-refresh
   logic [3:0] init_counter;
   logic [9:0] idle_counter;

   // State transition logic
   always_ff @(posedge clk or posedge reset) begin
      if (reset) begin
         state      <= INIT;
         init_counter <= 4'd0;
         idle_counter <= 10'd0;
      end
      else begin
         case (state)
           INIT: begin
              init_counter <= init_counter + 1;
              if (init_counter >= 10) begin
                 state      <= IDLE;
                 idle_counter <= 10'd0;
              end
           end
           IDLE: begin
              if (read || write) begin
                 state      <= ACTIVATE;
                 idle_counter <= 10'd0;
              end
              else if (idle_counter >= 1024) begin
                 state      <= REFRESH;
                 idle_counter <= 10'd0;
              end
              else begin
                 idle_counter <= idle_counter + 1;
              end
           end
           ACTIVATE: begin
              // After activation, choose READ or WRITE based on control signals
              state <= (read) ? READ : WRITE;
           end
           READ: begin
              state <= IDLE;
           end
           WRITE: begin
              state <= IDLE;
           end
           REFRESH: begin
              state <= IDLE;
           end
           default: state <= IDLE;
         endcase
      end
   end

   // Output logic based on current state
   always_ff @(posedge clk or posedge reset) begin
      if (reset) begin
         sdram_clk    <= 1'b0;
         sdram_cke    <= 1'b0;
         sdram_cs     <= 1'b0;
         sdram_ras    <= 1'b0;
         sdram_cas    <= 1'b0;
         sdram_we     <= 1'b0;
         sdram_addr   <= 24'd0;
         sdram_ba     <= 2'd0;
         dq_out       <= 16'd0;
         data_out     <= 16'd0;
      end
      else begin
         case (state)
           // Initialization: simple delay sequence
           INIT: begin
              sdram_clk    <= clk;
              sdram_cke    <= 1'b0;
              sdram_cs     <= 1'b0;
              sdram_ras    <= 1'b0;
              sdram_cas    <= 1'b0;
              sdram_we     <= 1'b0;
              sdram_addr   <= 24'd0;
              sdram_ba     <= 2'd0;
              dq_out       <= 16'd0;
              data_out     <= 16'd0;
           end
           // Idle state: no active command
           IDLE: begin
              sdram_clk    <= clk;
              sdram_cke    <= 1'b0;
              sdram_cs     <= 1'b0;
              sdram_ras    <= 1'b0;
              sdram_cas    <= 1'b0;
              sdram_we     <= 1'b0;
              sdram_addr   <= 24'd0;
              sdram_ba     <= 2'd0;
              dq_out       <= 16'd0;
              data_out     <= 16'd0;
           end
           // ACTIVATE: Issue Activate command (CS, RAS, CAS asserted)
           ACTIVATE: begin
              sdram_clk    <= clk;
              sdram_cke    <= 1'b1;
              sdram_cs     <= 1'b1;
              sdram_ras    <= 1'b1;
              sdram_cas    <= 1'b1;
              sdram_we     <= 1'b0;
              sdram_addr   <= 24'd0;
              sdram_ba     <= 2'd0;
              dq_out       <= 16'd0;
              data_out     <= 16'd0;
           end
           // READ: Issue Read command and capture data from SDRAM
           READ: begin
              sdram_clk    <= clk;
              sdram_cke    <= 1'b1;
              sdram_cs     <= 1'b1;
              sdram_ras    <= 1'b0;
              sdram_cas    <= 1'b1;
              sdram_we     <= 1'b0;
              sdram_addr   <= addr;
              sdram_ba     <= 2'd0;  // Assuming bank 0
              data_out     <= sdram_dq;
              dq_out       <= 16'd0; // Not driving during read
           end
           // WRITE: Issue Write command and drive data bus with data_in
           WRITE: begin
              sdram_clk    <= clk;
              sdram_cke    <= 1'b1;
              sdram_cs     <= 1'b1;
              sdram_ras    <= 1'b0;
              sdram_cas    <= 1'b1;
              sdram_we     <= 1'b1;
              sdram_addr   <= addr;
              sdram_ba     <= 2'd0;
              dq_out       <= data_in;
              data_out     <= 16'd0; // Not used in write mode
           end
           // REFRESH: Issue Auto-Refresh command
           REFRESH: begin
              sdram_clk    <= clk;
              sdram_cke    <= 1'b1;
              sdram_cs     <= 1'b1;
              sdram_ras    <= 1'b1;
              sdram_cas    <= 1'b1;
              sdram_we     <= 1'b0;
              sdram_addr   <= 24'd0;
              sdram_ba     <= 2'd0;
              dq_out       <= 16'd0;
              data_out     <= 16'd0;
           end
           default: begin
              sdram_clk    <= clk;
              sdram_cke    <= 1'b0;
              sdram_cs     <= 1'b0;
              sdram_ras    <= 1'b0;
              sdram_cas    <= 1'b0;
              sdram_we     <= 1'b0;
              sdram_addr   <= 24'd0;
              sdram_ba     <= 2'd0;
              dq_out       <= 16'd0;
              data_out     <= 16'd0;
           end
         endcase
      end
   end

endmodule

output.rtl/secure_read_write_bus_interface.v:
module secure_read_write_bus_interface(
    input  wire [p_addr_width-1:0] i_addr,
    input  wire [p_data_width-1:0] i_data_in,
    input  wire [7:0]              i_key_in,
    input  wire                    i_read_write_enable,
    input  wire                    i_capture_pulse,
    input  wire                    i_reset_bar,
    output reg  [p_data_width-1:0] o_data_out,
    output reg                     o_error
);

    // Parameter definitions
    parameter p_configurable_key = 8'hAA;
    parameter p_data_width       = 8;
    parameter p_addr_width       = 8;

    // Calculate memory depth from address width
    localparam integer MEM_DEPTH = (1 << p_addr_width);

    // Internal memory array
    reg [p_data_width-1:0] mem [0:MEM_DEPTH-1];

    // Synchronous operation on rising edge of i_capture_pulse with asynchronous reset
    integer j;
    always @(posedge i_capture_pulse or negedge i_reset_bar) begin
        if (!i_reset_bar) begin
            // Asynchronous reset: clear memory and outputs
            for (j = 0; j < MEM_DEPTH; j = j + 1) begin
                mem[j] <= 0;
            end
            o_data_out <= 0;
            o_error    <= 0;
        end else begin
            // Check authorization key
            if (i_key_in == p_configurable_key) begin
                if (i_read_write_enable) begin
                    // Read operation: output data from memory
                    o_data_out <= mem[i_addr];
                    o_error    <= 0;
                end else begin
                    // Write operation: store data into memory
                    mem[i_addr] <= i_data_in;
                    o_data_out <= 0;
                    o_error    <= 0;
                end
            end else begin
                // Unauthorized access: flag error and default outputs
                o_data_out <= 0;
                o_error    <= 1;
            end
        end
    end

endmodule

output.rtl/secure_read_write_register_bank.v:
module secure_read_write_register_bank #(
   parameter p_address_width = 8,
   parameter p_data_width    = 8,
   parameter p_unlock_code_0 = 8'hAB,
   parameter p_unlock_code_1 = 8'hCD
) (
   input  wire [p_address_width-1:0] i_addr,          // target address
   input  wire [p_data_width-1:0]    i_data_in,       // data input for write
   input  wire                       i_read_write_enable, // 0: write, 1: read
   input  wire                       i_capture_pulse,     // capture pulse (clock)
   input  wire                       i_rst_n,             // asynchronous active low reset
   output reg  [p_data_width-1:0]    o_data_out          // data output
);

   // Unlock state machine states:
   // 0: WAIT_FOR_UNLOCK0 (waiting for correct code at address 0)
   // 1: WAIT_FOR_UNLOCK1 (waiting for correct code at address 1)
   // 2: UNLOCKED
   reg [1:0] unlock_state;

   // Register to hold read data for output
   reg [p_data_width-1:0] read_data_reg;

   // Memory array for the register bank
   // Size is 2^(p_address_width) registers.
   reg [p_data_width-1:0] mem [(1<<p_address_width)-1:0];

   // Synchronous process triggered on the rising edge of i_capture_pulse or asynchronous reset.
   always @(posedge i_capture_pulse or negedge i_rst_n) begin
      if (!i_rst_n) begin
         // Reset: clear unlock state machine (and optionally clear memory)
         unlock_state <= 0;  // Set to WAIT_FOR_UNLOCK0
         // Optional: clear memory registers if desired.
      end
      else begin
         if (!i_read_write_enable) begin
            // Write operation
            if (unlock_state != 2) begin
               // Unlock sequence not complete: only addresses 0 and 1 are allowed.
               if ((i_addr == 0) || (i_addr == 1)) begin
                  // Check for correct unlock sequence based on current state.
                  if ((unlock_state == 0) && (i_addr == 0) && (i_data_in == p_unlock_code_0)) begin
                     // First unlock code received at address 0: transition to WAIT_FOR_UNLOCK1.
                     unlock_state <= 1;
                     mem[0] <= i_data_in;  // Store the unlock code.
                  end
                  else if ((unlock_state == 1) && (i_addr == 1) && (i_data_in == p_unlock_code_1)) begin
                     // Second unlock code received at address 1: unlock complete.
                     unlock_state <= 2;
                     mem[1] <= i_data_in;  // Store the trigger code.
                  end
                  else begin
                     // Incorrect code written to address 0 or 1: reset unlock sequence.
                     unlock_state <= 0;
                  end
               end
               // If i_addr is not 0 or 1, no write is performed.
            end
            else begin
               // Unlock sequence complete: allow writes to any address.
               mem[i_addr] <= i_data_in;
            end
         end
         else begin
            // Read operation
            if ((unlock_state == 2) && (i_addr != 0) && (i_addr != 1)) begin
               // Read allowed only for addresses other than 0 and 1.
               read_data_reg <= mem[i_addr];
            end
            else begin
               // Either not unlocked or attempting to read from address 0 or 1: output 0.
               read_data_reg <= 0;
            end
         end
      end
   end

   // Drive the output with the read data register.
   assign o_data_out = read_data_reg;

endmodule

output.rtl/binary_to_one_hot_decoder_sequential:
module binary_to_one_hot_decoder_sequencial #(
  parameter BINARY_WIDTH = 5,
  parameter OUTPUT_WIDTH = 32
)(
  input  wire [BINARY_WIDTH-1:0] i_binary_in,
  input  wire                     i_clk,
  input  wire                     i_rstb,
  output reg  [OUTPUT_WIDTH-1:0]  o_one_hot_out
);

  // Combinational logic to generate one-hot vector.
  // Only the bit at index i_binary_in is set to 1.
  reg [OUTPUT_WIDTH-1:0] one_hot;
  always @(*) begin
    one_hot = {OUTPUT_WIDTH{1'b0}};
    // Set the bit corresponding to the binary input.
    one_hot[i_binary_in] = 1'b1;
  end

  // Sequential logic: sample input and update output on rising edge of clock.
  // Asynchronous reset: when i_rstb is low, o_one_hot_out is reset to 0.
  always @(posedge i_clk or negedge i_rstb) begin
    if (!i_rstb)
      o_one_hot_out <= {OUTPUT_WIDTH{1'b0}};
    else
      o_one_hot_out <= one_hot;
  end

endmodule

output.rtl/serial_in_parallel_out_8bit.sv:
module serial_in_parallel_out_8bit(
    input  logic clock,
    input  logic serial_in,
    output logic [7:0] parallel_out
);

    // On every positive edge of the clock, shift the register left by one bit.
    // The MSB is dropped and the serial_in bit is inserted at the LSB.
    always_ff @(posedge clock) begin
        parallel_out <= {parallel_out[6:0], serial_in};
    end

endmodule

