output.rtl/sorting_engine.sv:
module sorting_engine #(
  parameter int N    = 8,  // Number of elements (N > 0)
  parameter int WIDTH = 8   // Bit-width of each element (WIDTH > 0)
)(
  input  logic         clk,
  input  logic         rst,
  input  logic         start,
  input  logic [N*WIDTH-1:0] in_data,
  output logic         done,
  output logic [N*WIDTH-1:0] out_data
);

  // State encoding
  localparam IDLE    = 2'd0;
  localparam SORTING = 2'd1;
  localparam DONE    = 2'd2;

  // State registers and counters
  reg [1:0] state;
  reg [$clog2(N)-1:0] pass_cnt;  // Counts passes (we perform N passes)
  reg [$clog2(N)-1:0] inner_cnt; // Counts comparisons within a pass

  // Internal data array to hold the unsorted (and then sorted) values
  reg [WIDTH-1:0] data [0:N-1];

  // Register to latch the sorted array for output
  reg [N*WIDTH-1:0] sorted_reg;

  // State machine: IDLE, SORTING, DONE
  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      state       <= IDLE;
      pass_cnt    <= 0;
      inner_cnt   <= 0;
      done        <= 0;
      sorted_reg  <= 0;
      integer i;
      for (i = 0; i < N; i = i + 1) begin
        data[i] <= 0;
      end
    end
    else begin
      case (state)
        IDLE: begin
          // Clear done signal in IDLE
          done <= 0;
          if (start) begin
            // Load the input array from the bus.
            integer i;
            for (i = 0; i < N; i = i + 1) begin
              // Extract each element; element 0 is the least-significant bits.
              data[i] <= in_data[((i+1)*WIDTH)-1 -: WIDTH];
            end
            pass_cnt <= 0;
            inner_cnt <= 0;
            state <= SORTING;
          end
        end

        SORTING: begin
          // Each comparison and potential swap takes one clock cycle.
          if (inner_cnt < (N-1)) begin
            // Compare adjacent elements.
            if (data[inner_cnt] > data[inner_cnt+1]) begin
              logic [WIDTH-1:0] temp;
              temp = data[inner_cnt];
              data[inner_cnt] <= data[inner_cnt+1];
              data[inner_cnt+1] <= temp;
            end
            inner_cnt <= inner_cnt + 1;
          end
          else begin
            // End of one pass: reset inner counter and increment pass counter.
            inner_cnt <= 0;
            pass_cnt <= pass_cnt + 1;
            if (pass_cnt == N) begin
              // After N passes (i.e. N*(N-1) comparisons), sorting is complete.
              state <= DONE;
            end
          end
        end

        DONE: begin
          // Latch the sorted array into sorted_reg.
          integer j;
          sorted_reg <= 0;
          for (j = 0; j < N; j = j + 1) begin
            // Pack each element into the output bus.
            // Element 0 goes to bits [WIDTH-1:0], element 1 to [2*WIDTH-1:WIDTH], etc.
            sorted_reg[((j+1)*WIDTH)-1 -: WIDTH] <= data[j];
          end
          state <= IDLE;
          // Assert done for one clock cycle.
          done <= 1;
        end
      endcase
    end
  end

  // Drive the output port with the sorted array.
  assign out_data = sorted_reg;

endmodule

input.rtl/sorting_engine.sv:
module sorting_engine #(
    parameter N = 8,             // Number of elements to sort
    parameter WIDTH = 8          // Bit-width of each element
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    // Internal registers to hold the array
    reg [WIDTH-1:0] array [0:N-1];

    // FSM states
    localparam IDLE    = 2'd0;
    localparam SORTING = 2'd1;
    localparam DONE    = 2'd2;

    reg [1:0]  state, next_state;

    // Variables for bubble sort indexing
    reg [$clog2(N)-1:0] i;  // Outer loop index
    reg [$clog2(N)-1:0] j;  // Inner loop index

    // Wires for comparison and swap
    wire [WIDTH-1:0] val_j;
    wire [WIDTH-1:0] val_j1;

    assign val_j  = array[j];
    assign val_j1 = array[j+1];

    // FSM: Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = SORTING;
            end
            SORTING: begin
                // Transition to DONE once all passes are complete
                if (i == (N-1) && j == (N-2))
                    next_state = DONE;
            end
            DONE: begin
                next_state = IDLE;
            end
            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // FSM: Output and counter updates
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            i <= 0;
            j <= 0;
            done <= 0;
        end else begin
            state <= next_state;

            case (state)
                IDLE: begin
                    done <= 0;
                    if (start) begin
                        // Load the array from in_data
                        for (int k = 0; k < N; k = k + 1) begin
                            array[k] <= in_data[(k+1)*WIDTH-1 -: WIDTH];
                        end
                        i <= 0;
                        j <= 0;
                    end
                end

                SORTING: begin
                    // Perform a single comparison and swap if needed
                    if (val_j > val_j1) begin
                        array[j]   <= val_j1;
                        array[j+1] <= val_j;
                    end

                    // Update j
                    if (j == N-2) begin
                        // One pass completed, increment i
                        j <= 0;
                        i <= i + 1;
                    end else begin
                        j <= j + 1;
                    end
                end

                DONE: begin
                    // Sorting complete
                    done <= 1;
                    // Output the sorted data
                    for (int m = 0; m < N; m = m + 1) begin
                        out_data[(m+1)*WIDTH-1 -: WIDTH] <= array[m];
                    end
                end
                default: begin
                end
            endcase
        end
    end

endmodule

