module sprite_controller_fsm#(
   parameter MEM_ADDR_WIDTH = 16,
   parameter PIXEL_WIDTH    = 24,
   parameter SPRITE_WIDTH   = 16,
   parameter SPRITE_HEIGHT  = 16,
   parameter WAIT_WIDTH     = 4,
   parameter N_ROM          = 256
)(
   input  logic                 clk,
   input  logic                 rst_n,
   input  logic [WAIT_WIDTH-1:0] i_wait,
   output logic                 rw,                             
   output logic [MEM_ADDR_WIDTH-1:0] write_addr,
   output logic [PIXEL_WIDTH-1:0] write_data,   
   output logic [SPRITE_WIDTH-1:0] x_pos,       
   output logic [SPRITE_HEIGHT-1:0] y_pos,      
   input  logic [PIXEL_WIDTH-1:0] pixel_out,    
   output logic                 done                            
);

   // FSM state declaration
   typedef enum logic [2:0] {
       IDLE,
       INIT_WRITE,
       WRITE,
       INIT_READ,
       READ,
       WAIT,
       DONE
   } state_t;

   state_t current_state, next_state;

   // Internal registers
   logic [MEM_ADDR_WIDTH-1:0] addr_counter; 
   logic [PIXEL_WIDTH-1:0]    data_counter;    
   logic [WAIT_WIDTH-1:0]     wait_counter;     

   // Combinational block: next state logic and output assignments
   always_comb begin
      // Default assignments for outputs
      rw          = 1'b0;
      write_addr  = addr_counter;
      write_data  = data_counter;
      x_pos       = addr_counter % SPRITE_WIDTH;
      y_pos       = addr_counter / SPRITE_WIDTH;
      done        = 1'b0;

      case (current_state)
         IDLE: begin
            next_state = INIT_WRITE;
         end
         INIT_WRITE: begin
            next_state = WRITE;
         end
         WRITE: begin
            rw = 1'b1;
            next_state = (addr_counter == (N_ROM - 1)) ? INIT_READ : WRITE;
         end
         INIT_READ: begin
            rw = 1'b0;
            next_state = READ;
         end
         READ: begin
            rw = 1'b0;
            next_state = (addr_counter == (N_ROM - 1)) ? WAIT : READ;
         end
         WAIT: begin
            rw = 1'b0;
            next_state = (wait_counter == i_wait) ? DONE : WAIT;
         end
         DONE: begin
            done = 1'b1;
            next_state = IDLE;
         end
         default: next_state = IDLE;
      endcase
   end

   // Sequential block: state update and register updates
   always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         current_state <= IDLE;
         addr_counter  <= {MEM_ADDR_WIDTH{1'b0}};
         data_counter  <= {PIXEL_WIDTH{1'b0}};
         wait_counter  <= {WAIT_WIDTH{1'b0}};
      end else begin
         current_state <= next_state;
         case (current_state)
            IDLE: begin
               addr_counter  <= {MEM_ADDR_WIDTH{1'b0}};
               data_counter  <= {PIXEL_WIDTH{1'b0}};
               wait_counter  <= {WAIT_WIDTH{1'b0}};
            end
            INIT_WRITE: begin
               addr_counter  <= {MEM_ADDR_WIDTH{1'b0}};
               data_counter  <= 24'hFF0000;
            end
            WRITE: begin
               addr_counter  <= addr_counter + 1;
               data_counter  <= data_counter + 1;
            end
            INIT_READ: begin
               addr_counter  <= {MEM_ADDR_WIDTH{1'b0}};
            end
            READ: begin
               addr_counter  <= addr_counter + 1;
            end
            WAIT: begin
               wait_counter  <= wait_counter + 1;
            end
            DONE: begin
               // Optionally, counters could be reset here if desired.
            end
            default: begin
               // No action for undefined states.
            end
         endcase
      end
   end

endmodule

input.rtl/Bitstream.sv:
module Bitstream(input  logic clk,rst_n,
                 input  logic enb,
                 input  logic rempty_in,
                 input  logic rinc_in,
                 input  logic [7:0] i_byte,
                 output logic o_bit,
                 output logic rempty_out,
                 output logic rinc_out);

    parameter IDLE  = 3'b000;
    parameter WaitR = 3'b001;
    parameter Ready = 3'b010;
    logic [1:0] curr_state,next_state;

    logic [0:7] byte_buf;
    logic [3:0] bp;
    logic rde;

    //FSM block

    always_ff @(posedge clk) begin
        if(!rst_n) curr_state <= IDLE;
        else curr_state <= next_state;
    end

    always_comb begin
        case(curr_state)
            IDLE: next_state = Ready;
            IDLE:begin
                if(enb)begin
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
                else begin
                    next_state = IDLE;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
            end
            WaitR:begin
                if(rempty_in)begin
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
                else begin
                    next_state = Ready;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b1;
                end
            end
            Ready:begin
                if(rde)begin
                    if(rempty_in)begin
                        next_state = WaitR;
                        rempty_out = 1'b1;
                        rinc_out   = 1'b0;
                    end
                    else begin
                        next_state = Ready;
                        rempty_out = 1'b1;
                        rinc_out   = 1'b1;
                    end
                end
                else begin
                    next_state = Ready;
                    rempty_out = 1'b0;
                    rinc_out   = 1'b0;
                end
            end
            default:begin
                next_state = IDLE;
                rempty_out = 1'b1;
                rinc_out   = 1'b0;
            end
        endcase
    end

    always @(posedge clk) begin
        if(rinc_out) 
           byte_buf <= i_byte[7:1];
    end

    always @(posedge clk) begin
        if(rinc_out) 
            bp <= 4'b0;
        else 
            if(rinc_in & ~rempty_out) 
               bp <= bp + 1'b1;
    end

    //Other comb logic

    assign rde = bp[3];
    assign o_bit = byte_buf[bp];

endmodule

output.rtl/Bitstream.sv:
module addressing the following lint issues:
   - Corrected state register width (from [1:0] to [2:0]) to match 3‐bit parameters.
   - Changed byte buffer declaration to [7:0] (natural order) and removed truncated assignments.
   - Removed overlapping case conditions in the FSM.
   - Eliminated unused signal “bp” by introducing a proper 3‐bit counter “bit_cnt” for 8 bits.
   - Ensured that all signals are assigned in sequential blocks to avoid latch inference.
*/

module Bitstream(
    input  logic         clk,
    input  logic         rst_n,
    input  logic         enb,
    input  logic         rempty_in,
    input  logic         rinc_in,
    input  logic [7:0]   i_byte,
    output logic         o_bit,
    output logic         rempty_out,
    output logic         rinc_out
);

    // Define FSM states with consistent 3-bit width
    parameter IDLE  = 3'b000;
    parameter WaitR = 3'b001;
    parameter Ready = 3'b010;

    // State registers now 3 bits wide to match parameters
    logic [2:0] curr_state, next_state;

    // Buffer to hold the byte. Use natural bit order [7:0]
    logic [7:0] byte_buf;

    // Counter to track bit extraction (0 to 7 for 8 bits)
    logic [2:0] bit_cnt;

    // FSM sequential block
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            curr_state <= IDLE;
        else
            curr_state <= next_state;
    end

    // FSM combinational next state logic
    always_comb begin
        // Default assignments
        next_state   = curr_state;
        rempty_out   = 1'b1;
        rinc_out     = 1'b0;

        case (curr_state)
            IDLE: begin
                if (enb) begin
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
                else begin
                    next_state = IDLE;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
            end
            WaitR: begin
                if (rempty_in) begin
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
                else begin
                    next_state = Ready;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b1;
                end
            end
            Ready: begin
                if (bit_cnt == 7) begin
                    // Last bit transmitted, move to WaitR for new byte
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
                else begin
                    next_state = Ready;
                    rempty_out = 1'b0;
                    rinc_out   = 1'b1;
                end
            end
            default: begin
                next_state = IDLE;
                rempty_out = 1'b1;
                rinc_out   = 1'b0;
            end
        endcase
    end

    // Sequential logic for byte buffering and shifting
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            byte_buf <= 8'b0;
            bit_cnt  <= 3'b0;
        end
        else if (rinc_out) begin
            // Load new byte and reset bit counter
            byte_buf <= i_byte;
            bit_cnt  <= 3'b0;
        end
        else if (rinc_in & ~rempty_out) begin
            // Shift out the next bit
            byte_buf <= byte_buf >> 1;
            bit_cnt  <= bit_cnt + 1;
        end
    end

    // Output the least significant bit of byte_buf
    assign o_bit = byte_buf[0];

endmodule

input.rtl/square_root.sv:
module square_root #(parameter WIDTH = 16) (
    input  wire [WIDTH-1:0] num,       
    output reg  [WIDTH/2-1:0] root     
);
    reg [WIDTH-1:0] remainder,square;         
    reg [WIDTH/2-1:0] test_bit, temp_square;        
    integer i,j;

    always @(*) 
    begin
        remainder = num;               
        root = 0;                      
        temp_square = 0;


        for (i = WIDTH/2-1; i >= 0; i = i - 1) 
        begin
            test_bit = 1'b1 << i;      
            temp_square = (root | test_bit);        
            square = 0; 
            for (j = 0; j < WIDTH; j = j + 1) 
            begin
              if (temp_square[j]) 
              begin 
                  square = square + (temp_square << j); 
              end 
            end

            if (square <= remainder) 
            begin
                root = root | test_bit; 
            end
        end
    end
endmodule

output.rtl/square_root_seq.sv:
module square_root_seq #(parameter WIDTH = 16)(
    input  wire clk,
    input  wire rst,
    input  wire start,
    input  wire [WIDTH-1:0] num,
    output reg [WIDTH/2-1:0] final_root,
    output reg done
);

    // State machine states
    localparam IDLE   = 1'b0;
    localparam COMPUTE = 1'b1;

    reg state, next_state;

    // Registers for the subtraction-based iterative algorithm
    reg [WIDTH-1:0] remainder; // Holds the remaining value after subtractions
    reg [WIDTH-1:0] odd;       // Current odd number to subtract (initialized to 1)
    reg [WIDTH/2-1:0] root;    // Count of subtractions (the computed square root)

    // Next state logic (combinational)
    always @(*) begin
        next_state = state; // Default: hold current state
        case (state)
            IDLE: begin
                if (start)
                    next_state = COMPUTE;
                else
                    next_state = IDLE;
            end
            COMPUTE: begin
                if (remainder >= odd)
                    next_state = COMPUTE;
                else
                    next_state = IDLE;
            end
            default: next_state = IDLE;
        endcase
    end

    // Sequential process: state and register updates
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state        <= IDLE;
            remainder    <= 0;
            odd          <= 0;
            root         <= 0;
            final_root   <= 0;
            done         <= 0;
        end else begin
            state <= next_state;

            // In the IDLE state, if start is asserted, initialize the registers.
            if (state == IDLE) begin
                if (start) begin
                    remainder <= num;  // Load input number into remainder
                    odd       <= 1;    // Initialize the first odd number
                    root      <= 0;    // Reset the square root counter
                end
                done <= 0;
            end
            // In the COMPUTE state, perform the subtraction-based iteration.
            else if (state == COMPUTE) begin
                if (remainder >= odd) begin
                    remainder <= remainder - odd; // Subtract the current odd number
                    root      <= root + 1;         // Increment the square root count
                    odd       <= odd + 2;          // Update to the next odd number
                    done      <= 0;                // Not yet complete
                end else begin
                    final_root <= root;            // Computation complete: assign result
                    done       <= 1;              // Assert done for one clock cycle
                end
            end
        end
    end

endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict (
  input  logic [31:0] fetch_rdata_i,  // Fetched 32-bit instruction
  input  logic [31:0] fetch_pc_i,     // Program counter of the fetched instruction
  input  logic        fetch_valid_i,  // High when the fetched instruction is valid
  output logic        predict_branch_taken_o, // High if branch/jump is predicted taken
  output logic [31:0] predict_branch_pc_o    // Predicted target address (PC + immediate)
);

  //-------------------------------------------------------------------------
  // Local parameters for opcodes
  //-------------------------------------------------------------------------
  localparam OPCODE_BRANCH = 7'h63; // Branch instructions (BXXX)
  localparam OPCODE_JAL    = 7'h6F; // Uncompressed JAL instruction
  localparam OPCODE_JALR   = 7'h67; // Uncompressed JALR instruction

  //-------------------------------------------------------------------------
  // Internal signals
  //-------------------------------------------------------------------------
  logic [31:0] instr;      // Alias for fetch_rdata_i
  logic [31:0] branch_imm; // Sign-extended immediate value
  logic        taken;      // Prediction flag (1 = taken, 0 = not-taken)

  //-------------------------------------------------------------------------
  // Main combinational logic
  //-------------------------------------------------------------------------
  always_comb begin
    // Default assignments
    predict_branch_taken_o = 1'b0;
    predict_branch_pc_o    = 32'd0;
    taken                  = 1'b0;
    branch_imm             = 32'd0;
    instr                  = fetch_rdata_i;

    if (fetch_valid_i) begin
      //-------------------------------------------------------------------------
      // Decode instruction type based on opcode (lower 7 bits)
      //-------------------------------------------------------------------------
      if (instr[6:0] == OPCODE_BRANCH) begin
        //-----------------------------------------------------------------------
        // Branch Instruction (BXXX)
        // Immediate extraction for uncompressed branch:
        //   imm_b_type = {19{instr[31]}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0}
        // Prediction: branch is taken if the sign bit (MSB of the immediate) is 1.
        //-----------------------------------------------------------------------
        branch_imm = {19{instr[31]}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0};
        taken      = branch_imm[31];

      end else if (instr[6:0] == OPCODE_JAL) begin
        //-----------------------------------------------------------------------
        // Jump Instruction (JAL or compressed jump equivalent)
        // Immediate extraction for uncompressed JAL:
        //   imm_j_type = {12{instr[31]}, instr[19:12], instr[20], instr[30:21], 1'b0}
        // Prediction: always taken.
        //-----------------------------------------------------------------------
        branch_imm = {12{instr[31]}, instr[19:12], instr[20], instr[30:21], 1'b0};
        taken      = 1'b1;

      end else if (instr[6:0] == OPCODE_JALR) begin
        //-----------------------------------------------------------------------
        // JALR Instruction
        // Immediate extraction for uncompressed JALR:
        //   imm_jalr_type = {20{instr[31]}, instr[31:20]}
        // Prediction: always taken.
        //-----------------------------------------------------------------------
        branch_imm = {20{instr[31]}, instr[31:20]};
        taken      = 1'b1;

      end else begin
        //-----------------------------------------------------------------------
        // For any other instruction, prediction is not taken.
        //-----------------------------------------------------------------------
        taken      = 1'b0;
        branch_imm = 32'd0;
      end

      //-------------------------------------------------------------------------
      // Output assignment: target PC = fetch_pc_i + branch_imm
      //-------------------------------------------------------------------------
      predict_branch_taken_o = taken;
      predict_branch_pc_o    = fetch_pc_i + branch_imm;
    end
    // If fetch_valid_i is low, outputs remain 0.
  end

endmodule

input.rtl/static_branch_predict.sv:
module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;


  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]}+reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0};

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal  : branch_imm = imm_jal_type;
      instr_jalr : branch_imm = imm_jalr_type;
      instr_b    : branch_imm = imm_b_type;
      instr_cj   : branch_imm = imm_cj_type;
      instr_cb   : branch_imm = imm_cb_type;
      default    : ;
    endcase
  end
  assign predict_branch_pc_o    = fetch_pc_i + branch_imm; 
  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);
  assign predict_branch_taken_o = fetch_valid_i & (instr_jal | instr_jalr | instr_cj | instr_b_taken);

endmodule

