output.rtl/sync_lifo.sv:
module sync_lifo #(
  parameter DATA_WIDTH = 8,
  parameter ADDR_WIDTH = 3
) (
  input  logic         clock,
  input  logic         reset,
  input  logic         write_en,
  input  logic         read_en,
  input  logic [DATA_WIDTH-1:0] data_in,
  output logic         empty,
  output logic         full,
  output logic [DATA_WIDTH-1:0] data_out
);

  // Calculate the depth of the LIFO based on ADDR_WIDTH.
  localparam int DEPTH = 2**ADDR_WIDTH;

  // Memory array to store data.
  reg [DATA_WIDTH-1:0] mem [0:DEPTH-1];

  // Pointer indicating the next free position (top of the stack).
  reg [ADDR_WIDTH-1:0] top_ptr;

  // Register to hold the data output.
  reg [DATA_WIDTH-1:0] data_out_reg;

  // Combinational assignments for empty and full flags.
  assign empty = (top_ptr == 0);
  assign full  = (top_ptr == DEPTH-1);

  // Synchronous process for LIFO operations.
  always_ff @(posedge clock) begin
    if (reset) begin
      // On reset, clear the pointer and output.
      top_ptr            <= 0;
      data_out_reg       <= '0;
      // Clear the memory array.
      integer i;
      for (i = 0; i < DEPTH; i = i + 1) begin
        mem[i] <= '0;
      end
    end
    else begin
      // Read operation: if read_en is asserted and LIFO is not empty,
      // pop the top element and update the pointer.
      if (read_en && !empty) begin
        data_out_reg <= mem[top_ptr - 1];
        top_ptr      <= top_ptr - 1;
      end

      // Write operation: if write_en is asserted and LIFO is not full,
      // push new data into the memory and update the pointer.
      if (write_en && !full) begin
        mem[top_ptr] <= data_in;
        top_ptr      <= top_ptr + 1;
      end
    end
  end

  // Drive the output data.
  always_comb begin
    data_out = data_out_reg;
  end

endmodule

output.rtl/sync_serial_communication_top.sv:
module.

module sync_serial_communication_top (
  input  logic         clk,
  input  logic         reset_n,  // Active LOW asynchronous reset
  input  logic [63:0]  data_in,  // Data input for TX
  input  logic [2:0]   sel,      // Controls the data width for TX (and RX)
  output logic [63:0]  data_out, // Data output from RX
  output logic         done      // Indicates valid result from RX (HIGH for one clk cycle)
);

  // Wires connecting the TX and RX blocks
  wire logic serial_out;
  wire logic serial_clk;
  wire logic rx_done;
  wire logic [63:0] rx_data_out;

  // Instantiate the transmitter block
  tx_block u_tx (
    .clk       (clk),
    .reset_n   (reset_n),
    .data_in   (data_in),
    .sel       (sel),
    .serial_out(serial_out),
    .done      (),  // TX done is not used at top-level
    .serial_clk(serial_clk)
  );

  // Instantiate the receiver block
  rx_block u_rx (
    .clk        (clk),
    .reset_n    (reset_n),
    .data_in    (serial_out),
    .sel        (sel),
    .serial_clk (serial_clk),
    .data_out   (rx_data_out),
    .done       (rx_done)
  );

  // Drive top-level outputs from the RX block outputs
  assign data_out = rx_data_out;
  assign done     = rx_done;

endmodule

module sync_serial_communication_tx_rx(
    input         clk,                    
    input         reset_n,                
    input  [2:0]  sel,              
    input  [63:0] data_in,         
    output [63:0] data_out,       
    output        done,
    output        parity,           // Transmitted parity bit from TX block
    output        parity_error      // Parity error detected in RX block
);

// Internal signals
wire tx_out;
wire tx_done;
wire serial_clk_in;

// Instantiate the TX block
tx_block uut_tx_block (
    .clk         (clk),                    
    .reset_n     (reset_n),                
    .data_in     (data_in),         
    .sel         (sel),              
    .serial_out  (tx_out),          
    .done        (tx_done),         
    .serial_clk  (serial_clk_in),   
    .parity      (parity)            // Connect TX parity output to top-level parity
);

// Instantiate the RX block
rx_block uut_rx_block (
    .clk         (clk),                    
    .reset_n     (reset_n),                
    .serial_clk  (serial_clk_in),   
    .data_in     (tx_out),          
    .parity_in   (parity),           // Connect TX parity output to RX parity_in
    .sel         (sel),              
    .done        (done),             
    .data_out    (data_out),        
    .parity_error(parity_error)      // Top-level parity error output
);

endmodule

module sync_serial_communication_tx_rx(
    input  clk,
    input  reset_n,
    input  [2:0] sel,
    input  [63:0] data_in,
    output [63:0] data_out,
    output done
);

  //-------------------------------------------------------------------------
  // Instantiate TX block (optimized)
  //-------------------------------------------------------------------------
  wire tx_out;
  wire tx_done;
  wire serial_clk_in;

  tx_block uut_tx_block (
      .clk(clk),
      .reset_n(reset_n),
      .data_in(data_in),
      .sel(sel),
      .serial_out(tx_out),
      .done(tx_done),
      .serial_clk(serial_clk_in)
  );

  //-------------------------------------------------------------------------
  // 3-stage pipeline between TX and RX blocks
  // (Increases overall latency by 3 cycles and reduces combinational load)
  //-------------------------------------------------------------------------
  reg tx_out_p1, tx_out_p2, tx_out_p3;
  reg serial_clk_p1, serial_clk_p2, serial_clk_p3;
  reg tx_done_p1, tx_done_p2, tx_done_p3;

  always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      tx_out_p1   <= 1'b0;
      tx_out_p2   <= 1'b0;
      tx_out_p3   <= 1'b0;
      serial_clk_p1 <= 1'b0;
      serial_clk_p2 <= 1'b0;
      serial_clk_p3 <= 1'b0;
      tx_done_p1  <= 1'b0;
      tx_done_p2  <= 1'b0;
      tx_done_p3  <= 1'b0;
    end else begin
      tx_out_p1   <= tx_out;
      tx_out_p2   <= tx_out_p1;
      tx_out_p3   <= tx_out_p2;
      serial_clk_p1 <= serial_clk_in;
      serial_clk_p2 <= serial_clk_p1;
      serial_clk_p3 <= serial_clk_p2;
      tx_done_p1  <= tx_done;
      tx_done_p2  <= tx_done_p1;
      tx_done_p3  <= tx_done_p2;
    end
  end

  //-------------------------------------------------------------------------
  // Instantiate RX block (optimized)
  //-------------------------------------------------------------------------
  rx_block uut_rx_block (
      .clk(clk),
      .serial_clk(serial_clk_p3),
      .reset_n(reset_n),
      .sel(sel),
      .data_in(tx_out_p3),
      .data_out(data_out),
      .done(done)
  );

endmodule

//------------------------------------------------------------------------------
// Optimized TX Block
//------------------------------------------------------------------------------
module tx_block(
    input  clk,
    input  reset_n,
    input  [63:0] data_in,
    input  [2:0] sel,
    output reg serial_out,
    output reg done,
    output serial_clk
);

  // Internal registers
  reg [63:0] data_reg;
  reg [6:0]  bit_count;
  reg [6:0]  reg_count;
  reg [6:0]  temp_reg_count;

  // Combined sequential logic: state update, data shifting, and output generation.
  always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      data_reg      <= 64'h0;
      bit_count     <= 7'h0;
      reg_count     <= 7'h0;
      temp_reg_count<= 7'h0;
      serial_out    <= 1'b0;
      done          <= 1'b0;
    end else begin
      if (done) begin
        // Select data width based on sel; reset bit_count when done.
        case (sel)
          3'b000: begin
            data_reg  <= 64'h0;
            bit_count <= 7'd0;
          end
          3'b001: begin
            data_reg  <= {56'h0, data_in[7:0]};
            bit_count <= 7'd7;
          end
          3'b010: begin
            data_reg  <= {48'h0, data_in[15:0]};
            bit_count <= 7'd15;
          end
          3'b011: begin
            data_reg  <= {32'h0, data_in[31:0]};
            bit_count <= 7'd31;
          end
          3'b100: begin
            data_reg  <= data_in;
            bit_count <= 7'd63;
          end
          default: begin
            data_reg  <= 64'h0;
            bit_count <= 7'h0;
          end
        endcase
      end else if (bit_count > 7'h0) begin
        // Shift out one bit per cycle.
        data_reg   <= data_reg >> 1;
        bit_count  <= bit_count - 1;
      end
      // Update reg_count and pipeline register for clock gating.
      reg_count     <= bit_count;
      temp_reg_count<= reg_count;
      // Drive serial_out with LSB of data_reg when active.
      serial_out    <= ((reg_count != 7'h0) || (bit_count != 7'h0)) ? data_reg[0] : 1'b0;
      // Assert done when all bits have been transmitted.
      done          <= (bit_count == 7'h0) ? 1'b1 : 1'b0;
    end
  end

  // Generate serial clock with minimal combinational logic.
  // The #1 delay is retained for simulation purposes.
  assign #1 serial_clk = clk && (temp_reg_count !== 7'd0);

endmodule

//------------------------------------------------------------------------------
// Optimized RX Block
//------------------------------------------------------------------------------
module rx_block(
    input  wire clk,
    input  wire reset_n,
    input  wire data_in,
    input  wire serial_clk,
    input  wire [2:0] sel,
    output reg done,
    output reg [63:0] data_out
);

  // Internal registers for serial data capture.
  reg [63:0] data_reg;
  reg [7:0]  bit_count;
  reg [7:0]  count;

  // Capture serial data on rising edge of serial_clk.
  always @(posedge serial_clk or negedge reset_n) begin
    if (!reset_n) begin
      data_reg  <= 64'h0;
      bit_count <= 8'd0;
    end else if (done) begin
      // Reset on completion.
      data_reg  <= 64'h0;
      bit_count <= 8'd0;
    end else begin
      // Shift in the new bit at the current index.
      data_reg[bit_count] <= data_in;
      bit_count <= bit_count + 1;
    end
  end

  // Monitor reception progress and update outputs on clk edge.
  always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      count    <= 8'd0;
      done     <= 1'b0;
      data_out <= 64'h0;
    end else if (bit_count != 0) begin
      if (count < bit_count) begin
        count <= count + 1;
        done  <= 1'b0;
      end else begin
        // Once all bits are received, latch the output.
        count  <= count;  // Hold count
        done   <= 1'b1;
        case (sel)
          3'b000: data_out <= 64'h0;
          3'b001: data_out <= {56'h0, data_reg};
          3'b010: data_out <= {48'h0, data_reg};
          3'b011: data_out <= {32'h0, data_reg};
          3'b100: data_out <= data_reg;
          default: data_out <= 64'h0;
        endcase
      end
    end else begin
      // No data received: reset counters.
      count <= 8'd0;
      done  <= 1'b0;
    end
  end

endmodule

output.rtl/thermostat.v:
module thermostat (
  input  wire         i_clk,
  input  wire         i_rst,
  input  wire [5:0]   i_temp_feedback,  // Bit mapping:
                            //   [5] = i_full_cold, [4] = i_medium_cold, [3] = i_low_cold,
                            //   [2] = i_low_hot,   [1] = i_medium_hot, [0] = i_full_hot
  input  wire         i_fan_on,
  input  wire         i_enable,
  input  wire         i_fault,
  input  wire         i_clr,
  output reg          o_heater_full,
  output reg          o_heater_medium,
  output reg          o_heater_low,
  output reg          o_aircon_full,
  output reg          o_aircon_medium,
  output reg          o_aircon_low,
  output reg          o_fan,
  output reg [2:0]    o_state
);

  // Define FSM states
  localparam AMBIENT  = 3'b011;
  localparam HEAT_LOW = 3'b000;
  localparam HEAT_MED = 3'b001;
  localparam HEAT_FULL= 3'b010;
  localparam COOL_LOW = 3'b100;
  localparam COOL_MED = 3'b101;
  localparam COOL_FULL= 3'b110;

  reg [2:0] state;

  always @(posedge i_clk or negedge i_rst) begin
    if (!i_rst) begin
      // Asynchronous reset: force FSM to AMBIENT and all outputs to 0
      state              <= AMBIENT;
      o_heater_full      <= 1'b0;
      o_heater_medium    <= 1'b0;
      o_heater_low       <= 1'b0;
      o_aircon_full      <= 1'b0;
      o_aircon_medium    <= 1'b0;
      o_aircon_low       <= 1'b0;
      o_fan              <= 1'b0;
      o_state            <= AMBIENT;
    end
    else begin
      // Check for fault condition (highest priority override)
      if (i_fault) begin
        // If fault is active, force all outputs to 0.
        // If clear is asserted, set state to AMBIENT on next clock.
        if (i_clr)
          state <= AMBIENT;
        o_heater_full      <= 1'b0;
        o_heater_medium    <= 1'b0;
        o_heater_low       <= 1'b0;
        o_aircon_full      <= 1'b0;
        o_aircon_medium    <= 1'b0;
        o_aircon_low       <= 1'b0;
        o_fan              <= 1'b0;
      end
      // Disable override: if thermostat is disabled, force outputs to 0 and FSM to AMBIENT.
      else if (!i_enable) begin
        state              <= AMBIENT;
        o_heater_full      <= 1'b0;
        o_heater_medium    <= 1'b0;
        o_heater_low       <= 1'b0;
        o_aircon_full      <= 1'b0;
        o_aircon_medium    <= 1'b0;
        o_aircon_low       <= 1'b0;
        o_fan              <= 1'b0;
      end
      // Normal operation: determine next state based on temperature feedback
      else begin
        // Temperature feedback evaluation:
        // Cold conditions (highest priority):
        if (i_temp_feedback[5]) begin
          state <= HEAT_FULL;
        end
        else if (i_temp_feedback[4]) begin
          state <= HEAT_MED;
        end
        else if (i_temp_feedback[3]) begin
          state <= HEAT_LOW;
        end
        // Hot conditions:
        else if (i_temp_feedback[0]) begin
          state <= COOL_FULL;
        end
        else if (i_temp_feedback[1]) begin
          state <= COOL_MED;
        end
        else if (i_temp_feedback[2]) begin
          state <= COOL_LOW;
        end
        // If none of the above, go to AMBIENT.
        else begin
          state <= AMBIENT;
        end

        // Set outputs based on the current state.
        case (state)
          HEAT_FULL: begin
            o_heater_full      <= 1'b1;
            o_heater_medium    <= 1'b0;
            o_heater_low       <= 1'b0;
            o_aircon_full      <= 1'b0;
            o_aircon_medium    <= 1'b0;
            o_aircon_low       <= 1'b0;
          end
          HEAT_MED: begin
            o_heater_full      <= 1'b0;
            o_heater_medium    <= 1'b1;
            o_heater_low       <= 1'b0;
            o_aircon_full      <= 1'b0;
            o_aircon_medium    <= 1'b0;
            o_aircon_low       <= 1'b0;
          end
          HEAT_LOW: begin
            o_heater_full      <= 1'b0;
            o_heater_medium    <= 1'b0;
            o_heater_low       <= 1'b1;
            o_aircon_full      <= 1'b0;
            o_aircon_medium    <= 1'b0;
            o_aircon_low       <= 1'b0;
          end
          COOL_FULL: begin
            o_heater_full      <= 1'b0;
            o_heater_medium    <= 1'b0;
            o_heater_low       <= 1'b0;
            o_aircon_full      <= 1'b1;
            o_aircon_medium    <= 1'b0;
            o_aircon_low       <= 1'b0;
          end
          COOL_MED: begin
            o_heater_full      <= 1'b0;
            o_heater_medium    <= 1'b0;
            o_heater_low       <= 1'b0;
            o_aircon_full      <= 1'b0;
            o_aircon_medium    <= 1'b1;
            o_aircon_low       <= 1'b0;
          end
          COOL_LOW: begin
            o_heater_full      <= 1'b0;
            o_heater_medium    <= 1'b0;
            o_heater_low       <= 1'b0;
            o_aircon_full      <= 1'b0;
            o_aircon_medium    <= 1'b0;
            o_aircon_low       <= 1'b1;
          end
          AMBIENT: begin
            o_heater_full      <= 1'b0;
            o_heater_medium    <= 1'b0;
            o_heater_low       <= 1'b0;
            o_aircon_full      <= 1'b0;
            o_aircon_medium    <= 1'b0;
            o_aircon_low       <= 1'b0;
          end
          default: begin
            o_heater_full      <= 1'b0;
            o_heater_medium    <= 1'b0;
            o_heater_low       <= 1'b0;
            o_aircon_full      <= 1'b0;
            o_aircon_medium    <= 1'b0;
            o_aircon_low       <= 1'b0;
          end
        endcase

        // Fan control: fan on if any heater/aircon output is active OR if manual override (i_fan_on) is asserted.
        if ((state == HEAT_FULL || state == HEAT_MED || state == HEAT_LOW ||
             state == COOL_FULL || state == COOL_MED || state == COOL_LOW) || i_fan_on)
          o_fan <= 1'b1;
        else
          o_fan <= 1'b0;
      end

      // Update the FSM output state.
      o_state <= state;
    end
  end

endmodule

output.rtl/ttc_counter_lite.sv:
module ttc_counter_lite (
    input  logic         clk,
    input  logic         reset,
    input  logic [3:0]   axi_addr,
    input  logic [31:0]  axi_wdata,
    input  logic         axi_write_en,
    input  logic         axi_read_en,
    output logic [31:0]  axi_rdata,
    output logic         interrupt
);

  // Internal registers
  logic [15:0] count;
  logic [15:0] match_value;
  logic [15:0] reload_value;
  logic [31:0] control;
  logic [31:0] status;
  logic        match_flag;

  // Control register bit positions:
  // Bit 0: Enable (timer enabled when high)
  // Bit 1: Interval Mode (when high, counter reloads on match)
  // Bit 2: Interrupt Enable (when high, interrupt is generated)
  localparam CTRL_ENABLE      = 0;
  localparam CTRL_INTERVAL    = 1;
  localparam CTRL_INTERRUPT   = 2;

  // AXI Read Logic (combinational)
  always_comb begin
    case (axi_addr)
      4'h0: axi_rdata = {16'b0, count};         // Count Register (lower 16 bits)
      4'h1: axi_rdata = {16'b0, match_value};    // Match Value Register (lower 16 bits)
      4'h2: axi_rdata = {16'b0, reload_value};   // Reload Value Register (lower 16 bits)
      4'h3: axi_rdata = control;                 // Control Register
      4'h4: axi_rdata = status;                  // Status Register
      default: axi_rdata = 32'b0;
    endcase
  end

  // Main Sequential Logic
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      // Reset all registers and flags
      count          <= 16'b0;
      match_value    <= 16'b0;
      reload_value   <= 16'b0;
      control        <= 32'b0;
      status         <= 32'b0;
      match_flag     <= 1'b0;
    end
    else begin
      // Process AXI write operations
      if (axi_write_en) begin
        case (axi_addr)
          4'h1: match_value <= axi_wdata[15:0];  // Write lower 16 bits to Match Value Register
          4'h2: reload_value <= axi_wdata[15:0]; // Write lower 16 bits to Reload Value Register
          4'h3: control <= {28'b0, axi_wdata[CTRL_INTERRUPT:0]}; // Only lower 3 bits are used
          4'h4: begin
                   // Writing to Status Register clears the interrupt flag.
                   status <= axi_wdata;
                   match_flag <= 1'b0;
                end
          default: ; // Write to Count Register is not allowed (read-only)
        endcase
      end

      // Timer Operation: Increment count if enabled
      if (control[CTRL_ENABLE]) begin
        if (count == match_value) begin
          // Match event detected
          if (control[CTRL_INTERVAL])
            count <= reload_value;  // Interval Mode: reload to reload_value
          else
            count <= match_value;   // Non-Interval Mode: hold at match_value
        end
        else begin
          count <= count + 1;
        end
      end

      // Update match_flag if not cleared by a status write
      if (! (axi_write_en && (axi_addr == 4'h4))) begin
        if (count == match_value)
          match_flag <= 1'b1;
        else
          match_flag <= 1'b0;
      end

      // Update Status Register: bit0 reflects the interrupt status
      status[0] <= match_flag;
    end
  end

  // Interrupt Generation: Assert interrupt if match_flag is set and interrupt enable is active
  assign interrupt = match_flag & control[CTRL_INTERRUPT];

endmodule

output.rtl/unpack_one_hot.v:
module implementing a flexible unpacking mechanism.
// The module expands a 256‐bit source register into a 512‐bit destination register
// according to a one‐hot selector, a sign control, and a size control.
//
// Cases:
//   • one_hot_selector = 3'b001:
//         Each 1‐bit from source_reg is expanded to an 8‐bit segment.
//         For sign==1, a 1 bit becomes 0x00 or 0xFF; for sign==0, it becomes 0x00 or 0x01.
//   • one_hot_selector = 3'b010:
//         Each 2‐bit segment from source_reg is expanded to an 8‐bit segment.
//         The 2 bits are sign‐ or zero‐extended to 8 bits.
//   • one_hot_selector = 3'b100:
//         If size==1:
//             Each 8‐bit segment from source_reg is expanded to a 16‐bit segment.
//         Else (size==0):
//             Each 4‐bit segment from source_reg is expanded to an 8‐bit segment.
//         In both cases, the extracted value is sign‐ or zero‐extended as indicated by “sign”.
//   • Default:
//         The entire source_reg is assigned to the lower 256 bits of destination_reg (upper 256 bits = 0).
//
module unpack_one_hot (
  input         sign,         // 1: sign-extend, 0: zero-extend
  input         size,         // For one_hot_selector==3'b100: 1 => 8-bit source chunks, 0 => 4-bit source chunks
  input  [2:0]  one_hot_selector, // One-hot selector controlling granularity
  input  [255:0] source_reg,    // Packed 256-bit input data
  output reg [511:0] destination_reg // Expanded 512-bit output data
);

  integer i;
  // Temporary registers for segment extraction.
  reg [7:0] seg;       // Used for 8-bit segments
  reg [15:0] seg16;    // Used for 16-bit segments

  always @(*) begin
    // Default initialization: clear destination register.
    destination_reg = 512'd0;

    case (one_hot_selector)
      3'b001: begin
        // Case 3'b001: Each 1-bit segment from source_reg becomes an 8-bit segment.
        // Number of segments = 512/8 = 64.
        for (i = 0; i < 64; i = i + 1) begin
          // Extract one bit from source_reg.
          // (Assumes source_reg is at least 64 bits; unused bits default to 0.)
          if (sign)
            seg = (source_reg[i]) ? 8'hFF : 8'h00;
          else
            seg = (source_reg[i]) ? 8'h01 : 8'h00;
          destination_reg[i*8 +: 8] = seg;
        end
      end

      3'b010: begin
        // Case 3'b010: Each 2-bit segment from source_reg becomes an 8-bit segment.
        // Number of segments = 64 (using 128 bits of source_reg).
        for (i = 0; i < 64; i = i + 1) begin
          // Extract 2 bits from source_reg.
          seg = source_reg[i*2 +: 2];
          if (sign)
            // Sign-extend the 2-bit value to 8 bits.
            seg = {{6{seg[1]}}, seg};
          else
            // Zero-extend the 2-bit value.
            seg = {{6'd0}, seg};
          destination_reg[i*8 +: 8] = seg;
        end
      end

      3'b100: begin
        // Case 3'b100: Behavior depends on the "size" signal.
        if (size == 1) begin
          // When size==1:
          // Each segment is 16 bits in the destination.
          // Number of segments = 512/16 = 32.
          // Each segment uses 8 bits from source_reg (total 256 bits used).
          for (i = 0; i < 32; i = i + 1) begin
            seg = source_reg[i*8 +: 8];
            if (sign)
              // Sign-extend the 8-bit value to 16 bits.
              seg16 = {{8{seg[7]}}, seg};
            else
              // Zero-extend the 8-bit value.
              seg16 = {8'd0, seg};
            destination_reg[i*16 +: 16] = seg16;
          end
        end
        else begin
          // When size==0:
          // Each segment is 8 bits in the destination.
          // Number of segments = 64 (using 256 bits of source_reg, 4 bits per segment).
          for (i = 0; i < 64; i = i + 1) begin
            seg = source_reg[i*4 +: 4];
            if (sign)
              // Sign-extend the 4-bit value to 8 bits.
              seg = {{7{seg[3]}}, seg};
            else
              // Zero-extend the 4-bit value.
              seg = {7'd0, seg};
            destination_reg[i*8 +: 8] = seg;
          end
        end
      end

      default: begin
        // Default case: assign source_reg directly to the lower 256 bits of destination_reg.
        destination_reg = {source_reg, 256'd0};
      end
    endcase
  end

endmodule

output.rtl/vending_machine.sv:
module vending_machine (
    input  logic         clk,
    input  logic         rst,
    input  logic         item_button,
    input  logic [2:0]   item_selected,
    input  logic [3:0]   coin_input,
    input  logic         cancel,
    output logic         dispense_item,
    output logic         return_change,
    output logic [4:0]   item_price,
    output logic [4:0]   change_amount,
    output logic [2:0]   dispense_item_id,
    output logic         error,
    output logic         return_money
);

  //-------------------------------------------------------------------------
  // FSM States
  //-------------------------------------------------------------------------
  typedef enum logic [2:0] {
    IDLE              = 3'b000,
    ITEM_SELECTION    = 3'b001,
    PAYMENT_VALIDATION= 3'b010,
    DISPENSING_ITEM   = 3'b011,
    RETURN_CHANGE     = 3'b100,
    RETURN_MONEY      = 3'b101
  } state_t;

  //-------------------------------------------------------------------------
  // Internal Registers
  //-------------------------------------------------------------------------
  state_t state;
  // Accumulated coins (assumed 5-bit wide to cover typical transaction amounts)
  logic [4:0] coins_accumulated;
  // Registered selected item and its price
  logic [2:0] item_selected_reg;
  logic [4:0] item_price_reg;
  // Change amount to be returned
  logic [4:0] change_amount_reg;
  // One-cycle pulse registers for error, dispense, change, and money return
  logic error_reg;
  logic dispense_item_reg;
  logic return_change_reg;
  logic return_money_reg;
  // Registers to detect rising edges of item_button and cancel signals
  logic item_button_reg;
  logic cancel_reg;

  //-------------------------------------------------------------------------
  // Main FSM Process
  //-------------------------------------------------------------------------
  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      state                  <= IDLE;
      coins_accumulated      <= 5'd0;
      item_selected_reg      <= 3'd0;
      item_price_reg         <= 5'd0;
      change_amount_reg      <= 5'd0;
      error_reg              <= 1'b0;
      dispense_item_reg      <= 1'b0;
      return_change_reg      <= 1'b0;
      return_money_reg       <= 1'b0;
      item_button_reg        <= 1'b0;
      cancel_reg             <= 1'b0;
    end
    else begin
      // Update button registers to detect rising edges
      item_button_reg <= item_button;
      cancel_reg      <= cancel;

      // Default: clear one-cycle pulses
      error_reg       <= 1'b0;
      dispense_item_reg <= 1'b0;
      return_change_reg <= 1'b0;
      return_money_reg  <= 1'b0;

      case (state)
        //-------------------------------------------------------------------------
        // IDLE State
        //-------------------------------------------------------------------------
        IDLE: begin
          // If coins are inserted before item selection, trigger error.
          if (coin_input != 4'd0) begin
            error_reg <= 1;
            state     <= RETURN_MONEY;
          end
          // Transition to ITEM_SELECTION on rising edge of item_button.
          else if (item_button && !item_button_reg) begin
            state <= ITEM_SELECTION;
          end
          else begin
            state <= IDLE;
          end
        end

        //-------------------------------------------------------------------------
        // ITEM_SELECTION State
        //-------------------------------------------------------------------------
        ITEM_SELECTION: begin
          // If cancel is pressed, trigger error.
          if (cancel && !cancel_reg) begin
            error_reg <= 1;
            state     <= RETURN_MONEY;
          end
          // Also, if coins are inserted before confirming the item, trigger error.
          else if (coin_input != 4'd0) begin
            error_reg <= 1;
            state     <= RETURN_MONEY;
          end
          else begin
            // Validate item selection: only valid if 3'b001, 3'b010, 3'b011, or 3'b100.
            if ((item_selected == 3'b001) || (item_selected == 3'b010) ||
                (item_selected == 3'b011) || (item_selected == 3'b100)) begin
              item_selected_reg <= item_selected;
              // Map item_selected to a price.
              case (item_selected)
                3'b001: item_price_reg <= 5'd5;
                3'b010: item_price_reg <= 5'd10;
                3'b011: item_price_reg <= 5'd15;
                3'b100: item_price_reg <= 5'd20;
                default: item_price_reg <= 5'd0;
              endcase
              // Transition to PAYMENT_VALIDATION.
              state <= PAYMENT_VALIDATION;
            end
            else begin
              error_reg <= 1;
              state     <= RETURN_MONEY;
            end
          end
        end

        //-------------------------------------------------------------------------
        // PAYMENT_VALIDATION State
        //-------------------------------------------------------------------------
        PAYMENT_VALIDATION: begin
          // If cancel is pressed, trigger error.
          if (cancel && !cancel_reg) begin
            error_reg <= 1;
            state     <= RETURN_MONEY;
          end
          else begin
            // Validate coin_input: only accept coins of value 1, 2, 5, or 10.
            if ((coin_input == 4'd1) || (coin_input == 4'd2) ||
                (coin_input == 4'd5) || (coin_input == 4'd10)) begin
              coins_accumulated <= coins_accumulated + coin_input;
              // If accumulated coins meet/exceed the item price, move to DISPENSING_ITEM.
              if (coins_accumulated >= item_price_reg) begin
                state <= DISPENSING_ITEM;
              end
            end
            else begin
              error_reg <= 1;
              state     <= RETURN_MONEY;
            end
          end
        end

        //-------------------------------------------------------------------------
        // DISPENSING_ITEM State
        //-------------------------------------------------------------------------
        DISPENSING_ITEM: begin
          // Assert dispense_item pulse for one cycle.
          dispense_item_reg <= 1;
          // If cancel is pressed during dispensing, trigger error.
          if (cancel && !cancel_reg) begin
            error_reg <= 1;
            state     <= RETURN_MONEY;
          end
          else begin
            // If excess coins were inserted, calculate change.
            if (coins_accumulated > item_price_reg) begin
              change_amount_reg <= coins_accumulated - item_price_reg;
              state             <= RETURN_CHANGE;
            end
            else begin
              state <= IDLE;
            end
          end
        end

        //-------------------------------------------------------------------------
        // RETURN_CHANGE State
        //-------------------------------------------------------------------------
        RETURN_CHANGE: begin
          // Assert return_change pulse for one cycle.
          return_change_reg <= 1;
          state             <= IDLE;
        end

        //-------------------------------------------------------------------------
        // RETURN_MONEY State
        //-------------------------------------------------------------------------
        RETURN_MONEY: begin
          // Assert return_money pulse for one cycle.
          return_money_reg <= 1;
          state            <= IDLE;
        end

        default: state <= IDLE;
      endcase
    end
  end

  //-------------------------------------------------------------------------
  // Output Assignments
  //-------------------------------------------------------------------------
  // One-cycle pulse outputs.
  assign error         = error_reg;
  assign dispense_item = dispense_item_reg;
  assign return_change = return_change_reg;
  assign return_money  = return_money_reg;

  // Display the item price once selected.
  assign item_price = item_price_reg;

  // Output the change amount only during RETURN_CHANGE state.
  assign change_amount = (state == RETURN_CHANGE) ? change_amount_reg : 5'd0;

  // Output the dispensed item ID only during DISPENSING_ITEM state.
  assign dispense_item_id = (state == DISPENSING_ITEM) ? item_selected_reg : 3'd0;

endmodule

